    '                }',
    '            } else {',
    '                println!("Usage: /template [list | use <name> key=val ... | add <name> <template>]");',
    '            }'
]).

rust_command_body(multiline, [
    '            state.multiline = !state.multiline;',
    '            println!("Multiline mode: {}", if state.multiline { "on" } else { "off" });'
]).

rust_command_body(search, [
