%% =============================================================================
%% Cross-Target Parity Report
%% =============================================================================

generate_parity_report :-
    open('generated/PARITY_REPORT.md', write, S),
    write(S, '# Cross-Target Parity Report\n\n'),
    write(S, '_Auto-generated by `generate_parity_report/0`. Do not edit manually._\n\n'),
    %% --- shared_logic coverage ---
    write(S, '## shared_logic Methods\n\n'),
    write(S, '| Method | Module | Python | Rust | Elixir | Prolog | Clojure |\n'),
    write(S, '|--------|--------|--------|------|--------|--------|--------|\n'),
    forall(shared_logic(Cat, Method, _Props), (
        (compile_logic(python, Method, _) -> Py = 'Y' ; Py = '-'),
        (compile_logic(rust, Method, _) -> Rs = 'Y' ; Rs = '-'),
        (compile_logic(elixir, Method, _) -> Ex = 'Y' ; Ex = '-'),
        (compile_logic(prolog, Method, _) -> Pl = 'Y' ; Pl = '-'),
        (compile_logic(clojure, Method, _) -> Cl = 'Y' ; Cl = '-'),
        format(S, '| `~w` | ~w | ~w | ~w | ~w | ~w | ~w |~n', [Method, Cat, Py, Rs, Ex, Pl, Cl])
    )),
    %% --- summary counts ---
    findall(M, shared_logic(_, M, _), AllMethods),
    length(AllMethods, Total),
    include([M]>>compile_logic(python, M, _), AllMethods, PyOk), length(PyOk, PyN),
    include([M]>>compile_logic(rust, M, _), AllMethods, RsOk), length(RsOk, RsN),
    include([M]>>compile_logic(elixir, M, _), AllMethods, ExOk), length(ExOk, ExN),
    include([M]>>compile_logic(prolog, M, _), AllMethods, PlOk), length(PlOk, PlN),
    include([M]>>compile_logic(clojure, M, _), AllMethods, ClOk), length(ClOk, ClN),
    format(S, '\n**Total: ~w methods** — Python: ~w, Rust: ~w, Elixir: ~w, Prolog: ~w, Clojure: ~w\n\n', [Total, PyN, RsN, ExN, PlN, ClN]),
    %% --- generated module inventory ---
    write(S, '## Generated Module Inventory\n\n'),
    write(S, '| Target | Modules | Tests |\n'),
    write(S, '|--------|---------|-------|\n'),
    (expand_file_name('generated/python/*.py', PyFiles) -> length(PyFiles, PyFC) ; PyFC = 0),
    (expand_file_name('generated/rust/src/*.rs', RsFiles) -> length(RsFiles, RsFC) ; RsFC = 0),
    (expand_file_name('generated/elixir/lib/agent_loop/*.ex', ExFiles) -> length(ExFiles, ExFC) ; ExFC = 0),
    (expand_file_name('generated/elixir/test/*.exs', ExTests) -> length(ExTests, ExTC) ; ExTC = 0),
    (expand_file_name('generated/rust/tests/*.rs', RsTests) -> length(RsTests, RsTC) ; RsTC = 0),
    (expand_file_name('generated/prolog/*.pl', PlFiles) -> length(PlFiles, PlFC) ; PlFC = 0),
    (expand_file_name('generated/clojure/src/agent_loop/*.clj', CljFiles) -> length(CljFiles, CljFC) ; CljFC = 0),
    format(S, '| Python | ~w modules | — |~n', [PyFC]),
    format(S, '| Rust | ~w modules | ~w test files |~n', [RsFC, RsTC]),
    format(S, '| Elixir | ~w modules | ~w test files |~n', [ExFC, ExTC]),
    format(S, '| Prolog | ~w modules | — |~n', [PlFC]),
    format(S, '| Clojure | ~w modules | — |~n', [CljFC]),
    %% --- GenServer wrappers ---
    write(S, '\n## Elixir OTP Components\n\n'),
    write(S, '| GenServer | Wraps | Supervised |\n'),
    write(S, '|-----------|-------|------------|\n'),
    forall(elixir_server(Srv, Wrapped), (
        format(S, '| `AgentLoop.~w` | `AgentLoop.~w` | Y |~n', [Srv, Wrapped])
    )),
    %% --- coverage gaps ---
    write(S, '\n## Coverage Gaps\n\n'),
    write(S, '| Category | Gap | Notes |\n'),
    write(S, '|----------|-----|-------|\n'),
    write(S, '| Context trimming | Not in shared_logic | Too complex (multi-condition loops, platform-specific optimizations) |\n'),
    write(S, '| Session save/load | Not in shared_logic | JSON serialization differs per language |\n'),
    write(S, '| Tool dispatch | Not in shared_logic | Branching + I/O differs per language |\n'),
    write(S, '| Elixir CI | No mix compile/test | Requires Elixir toolchain in CI |\n'),
    close(S),
    format('  Generated PARITY_REPORT.md (generated/PARITY_REPORT.md)~n', []).

generate_declarative_tests :-
    output_path(prolog, 'test_declarative.pl', Path),
    open(Path, write, S),
    write_decl_test_header(S),
    write_decl_existence_tests(S),
    write_decl_property_tests(S),
    write_decl_crossref_tests(S),
    write_decl_count_tests(S),
    write_decl_shared_logic_tests(S),
    write_decl_test_runner(S),
    close(S),
    format('  Generated test_declarative.pl (~w)~n', [Path]).

write_decl_test_header(S) :-
    write(S, '%% Auto-generated declarative tests — do not edit manually.\n'),
    write(S, '%% Regenerate with: swipl -g "generate_all(tests), halt" agent_loop_module.pl\n\n'),
    write(S, ':- use_module(library(lists)).\n\n'),
    write(S, ':- dynamic decl_test_passed/1, decl_test_failed/1.\n\n'),
    write(S, 'decl_assert_true(Name, Goal) :-\n'),
    write(S, '    (call(Goal) ->\n'),
    write(S, '        assert(decl_test_passed(Name)),\n'),
    write(S, '        format("  [PASS] ~w~n", [Name])\n'),
    write(S, '    ;\n'),
    write(S, '        assert(decl_test_failed(Name)),\n'),
    write(S, '        format("  [FAIL] ~w~n", [Name])\n'),
    write(S, '    ).\n\n'),
    write(S, 'decl_assert_eq(Name, Got, Expected) :-\n'),
    write(S, '    (Got == Expected ->\n'),
    write(S, '        assert(decl_test_passed(Name)),\n'),
    write(S, '        format("  [PASS] ~w~n", [Name])\n'),
    write(S, '    ;\n'),
    write(S, '        assert(decl_test_failed(Name)),\n'),
    write(S, '        format("  [FAIL] ~w (expected ~w, got ~w)~n", [Name, Expected, Got])\n'),
    write(S, '    ).\n\n').

%% --- Existence tests: one per fact instance ---
write_decl_existence_tests(S) :-
    write(S, '%% =============================================================================\n'),
    write(S, '%% Existence Tests\n'),
    write(S, '%% =============================================================================\n\n'),
    write(S, 'test_decl_existence :-\n'),
    write(S, '    format("~nDeclarative existence tests:~n"),\n'),
    %% tool_spec
    forall(tool_spec(Name, _), (
        format(atom(Label), 'tool_spec(~w) exists', [Name]),
        format(S, '    decl_assert_true(\'~w\', agent_loop_module:tool_spec(~w, _)),~n', [Label, Name])
    )),
    %% agent_backend
    forall(agent_backend(Name, _), (
        format(atom(Label), 'agent_backend(~w) exists', [Name]),
        format(S, '    decl_assert_true(\'~w\', agent_loop_module:agent_backend(~w, _)),~n', [Label, Name])
    )),
    %% security_profile
    forall(security_profile(Name, _), (
        format(atom(Label), 'security_profile(~w) exists', [Name]),
        format(S, '    decl_assert_true(\'~w\', agent_loop_module:security_profile(~w, _)),~n', [Label, Name])
    )),
    %% agent_config_field — use findall to get all field names
    findall(FName, agent_config_field(FName, _, _, _), Fields),
    forall(member(F, Fields), (
        format(atom(Label), 'agent_config_field(~w) exists', [F]),
        format(S, '    decl_assert_true(\'~w\', agent_loop_module:agent_config_field(~w, _, _, _)),~n', [Label, F])
    )),
    %% slash_command — use name only (quote atoms with special chars)
    findall(CName, slash_command(CName, _, _, _), Cmds),
    forall(member(C, Cmds), (
        format(atom(Label), 'slash_command(~w) exists', [C]),
        format(S, '    decl_assert_true(\'~w\', agent_loop_module:slash_command(~q, _, _, _)),~n', [Label, C])
    )),
    %% End the predicate with true
    write(S, '    true.\n\n').

%% --- Property tests: structural invariants ---
%% Each property check is a separate predicate to avoid variable sharing issues.
write_decl_property_tests(S) :-
    write(S, '%% =============================================================================\n'),
    write(S, '%% Property Tests\n'),
    write(S, '%% =============================================================================\n\n'),
    %% Generate individual test predicates for tool_spec properties
    forall(tool_spec(Name, _), (
        format(atom(PredName), 'test_prop_tool_~w', [Name]),
        format(S, '~w :-~n', [PredName]),
        format(atom(L1), 'tool_spec(~w) has description', [Name]),
        format(S, '    decl_assert_true(\'~w\', (agent_loop_module:tool_spec(~w, P), member(description(_), P))),~n', [L1, Name]),
        format(atom(L2), 'tool_spec(~w) has parameters', [Name]),
        format(S, '    decl_assert_true(\'~w\', (agent_loop_module:tool_spec(~w, P), member(parameters(_), P))).~n~n', [L2, Name])
    )),
    %% Generate individual test predicates for backend properties
    forall(agent_backend(Name, _), (
        format(atom(PredName), 'test_prop_backend_~w', [Name]),
        format(S, '~w :-~n', [PredName]),
        format(atom(L1), 'backend(~w) has type', [Name]),
        format(S, '    decl_assert_true(\'~w\', (agent_loop_module:agent_backend(~w, P), member(type(_), P))),~n', [L1, Name]),
        format(atom(L2), 'backend(~w) has class_name', [Name]),
        format(S, '    decl_assert_true(\'~w\', (agent_loop_module:agent_backend(~w, P), member(class_name(_), P))).~n~n', [L2, Name])
    )),
    %% Generate individual test predicates for security profile properties
    forall(security_profile(Name, _), (
        format(atom(PredName), 'test_prop_security_~w', [Name]),
        format(S, '~w :-~n', [PredName]),
        format(atom(L1), 'security(~w) has path_validation', [Name]),
        format(S, '    decl_assert_true(\'~w\', (agent_loop_module:security_profile(~w, P), member(path_validation(_), P))),~n', [L1, Name]),
        format(atom(L2), 'security(~w) has audit_logging', [Name]),
        format(S, '    decl_assert_true(\'~w\', (agent_loop_module:security_profile(~w, P), member(audit_logging(_), P))).~n~n', [L2, Name])
    )),
    %% Main property test predicate calls all sub-predicates
    write(S, 'test_decl_properties :-\n'),
    write(S, '    format("~nDeclarative property tests:~n"),\n'),
    forall(tool_spec(Name, _), (
        format(atom(PredName), 'test_prop_tool_~w', [Name]),
        format(S, '    ~w,~n', [PredName])
    )),
    forall(agent_backend(Name, _), (
        format(atom(PredName), 'test_prop_backend_~w', [Name]),
        format(S, '    ~w,~n', [PredName])
    )),
    forall(security_profile(Name, _), (
        format(atom(PredName), 'test_prop_security_~w', [Name]),
        format(S, '    ~w,~n', [PredName])
    )),
    %% Every slash_command has valid match type
    forall(slash_command(Name, MatchType, _, _), (
        format(atom(Label), 'command(~w) has valid match type', [Name]),
        format(S, '    decl_assert_true(\'~w\', member(~w, [exact, prefix, prefix_sp, exact_or_prefix_sp])),~n', [Label, MatchType])
    )),
    %% Every config field has non-empty type (individual predicates to avoid var sharing)
    findall(FName, agent_config_field(FName, _, _, _), Fields),
    forall(member(F, Fields), (
        format(atom(PredName), 'test_prop_config_~w', [F]),
        format(S, '    ~w,~n', [PredName])
    )),
    write(S, '    true.\n\n'),
    %% Emit config property predicates
    forall(member(F2, Fields), (
        format(atom(PredName2), 'test_prop_config_~w', [F2]),
        format(S, '~w :- decl_assert_true(\'config(~w) has type\', (agent_loop_module:agent_config_field(~w, T, _, _), T \\= \'\')).~n', [PredName2, F2, F2])
    )),
    nl(S).

%% --- Cross-reference tests ---

%% resolve_alias_target(+CmdStr, -SlashCmdName)
%% Given a command alias target string, find the actual slash_command it refers to.
resolve_alias_target(CmdStr, CmdName) :-
    atom_string(CAtom, CmdStr),
    %% Extract first word
    (sub_atom(CAtom, Pos, _, _, ' ') ->
        sub_atom(CAtom, 0, Pos, _, FirstWord)
    ;
        FirstWord = CAtom
    ),
    %% Check if it's a direct command
    (slash_command(FirstWord, _, _, _) ->
        CmdName = FirstWord
    ;
        %% Check if it's in a command's aliases list
        (slash_command(RealCmd, _, Props, _),
         member(aliases(AliasList), Props),
         member(FirstWord, AliasList)) ->
            CmdName = RealCmd
        ;
            CmdName = FirstWord  %% fallback — will fail the test
    ).

write_decl_crossref_tests(S) :-
    write(S, '%% =============================================================================\n'),
    write(S, '%% Cross-Reference Tests\n'),
    write(S, '%% =============================================================================\n\n'),
    write(S, 'test_decl_crossrefs :-\n'),
    write(S, '    format("~nDeclarative cross-reference tests:~n"),\n'),
    %% Every command_alias resolves to a valid slash_command
    findall(Alias-Cmd, command_alias(Alias, Cmd), Aliases),
    forall(member(A-C, Aliases), (
        resolve_alias_target(C, CmdName),
        format(atom(Label), 'alias(~w) -> command(~w)', [A, CmdName]),
        format(S, '    decl_assert_true(\'~w\', agent_loop_module:slash_command(~q, _, _, _)),~n', [Label, CmdName])
    )),
    %% Every backend with helper_fragments has matching py_fragments
    forall((agent_backend(BName, Props), member(helper_fragments(Frags), Props), Frags \= []), (
        forall(member(Frag, Frags), (
            format(atom(Label), 'backend(~w) helper fragment ~w exists', [BName, Frag]),
            format(S, '    decl_assert_true(\'~w\', agent_loop_module:py_fragment(~w, _)),~n', [Label, Frag])
        ))
    )),
    write(S, '    true.\n\n').

%% --- Count consistency tests ---
write_decl_count_tests(S) :-
    write(S, '%% =============================================================================\n'),
    write(S, '%% Count Consistency Tests\n'),
    write(S, '%% =============================================================================\n\n'),
    write(S, 'test_decl_counts :-\n'),
    write(S, '    format("~nDeclarative count tests:~n"),\n'),
    %% Count each fact type and emit hardcoded assertions
    findall(_, tool_spec(_, _), Tools), length(Tools, NTools),
    format(S, '    findall(N, agent_loop_module:tool_spec(N, _), Ts), length(Ts, TC),~n', []),
    format(S, '    decl_assert_eq(\'tool_spec count\', TC, ~w),~n', [NTools]),
    findall(_, agent_backend(_, _), Backends), length(Backends, NBackends),
    format(S, '    findall(N, agent_loop_module:agent_backend(N, _), Bs), length(Bs, BC),~n', []),
    format(S, '    decl_assert_eq(\'backend count\', BC, ~w),~n', [NBackends]),
    findall(_, security_profile(_, _), Profiles), length(Profiles, NProfiles),
    format(S, '    findall(N, agent_loop_module:security_profile(N, _), Ps), length(Ps, PC),~n', []),
    format(S, '    decl_assert_eq(\'security_profile count\', PC, ~w),~n', [NProfiles]),
    findall(_, agent_config_field(_, _, _, _), CfgFields), length(CfgFields, NCfg),
    format(S, '    findall(N, agent_loop_module:agent_config_field(N, _, _, _), Cs), length(Cs, CC),~n', []),
    format(S, '    decl_assert_eq(\'config_field count\', CC, ~w),~n', [NCfg]),
    findall(_, slash_command(_, _, _, _), SlashCmds), length(SlashCmds, NCmds),
    format(S, '    findall(N, agent_loop_module:slash_command(N, _, _, _), Ss), length(Ss, SC),~n', []),
    format(S, '    decl_assert_eq(\'slash_command count\', SC, ~w),~n', [NCmds]),
    findall(_, py_fragment(_, _), PyFrags), length(PyFrags, NPy),
    format(S, '    findall(N, agent_loop_module:py_fragment(N, _), PFs), length(PFs, PFC),~n', []),
    format(S, '    decl_assert_eq(\'py_fragment count\', PFC, ~w),~n', [NPy]),
    findall(_, rust_fragment(_, _), RsFrags), length(RsFrags, NRs),
    format(S, '    findall(N, agent_loop_module:rust_fragment(N, _), RFs), length(RFs, RFC),~n', []),
    format(S, '    decl_assert_eq(\'rust_fragment count\', RFC, ~w),~n', [NRs]),
    write(S, '    true.\n\n').

%% --- Shared logic tests (for Feature 2) ---
write_decl_shared_logic_tests(S) :-
    write(S, '%% =============================================================================\n'),
    write(S, '%% Shared Logic Tests\n'),
    write(S, '%% =============================================================================\n\n'),
    write(S, 'test_decl_shared_logic :-\n'),
    write(S, '    format("~nDeclarative shared logic tests:~n"),\n'),
    %% Test each shared_logic fact exists and compiles for both targets
    findall(Method, shared_logic(_, Method, _), Methods),
    (Methods = [] ->
        write(S, '    true.  %% No shared_logic facts yet\n\n')
    ;
        forall(member(M, Methods), (
            format(atom(L1), 'shared_logic(~w) exists', [M]),
            format(S, '    decl_assert_true(\'~w\', agent_loop_module:shared_logic(_, ~w, _)),~n', [L1, M]),
            format(atom(L2), 'shared_logic(~w) compiles for python', [M]),
            format(S, '    decl_assert_true(\'~w\', agent_loop_module:compile_logic(python, ~w, _)),~n', [L2, M]),
            format(atom(L3), 'shared_logic(~w) compiles for rust', [M]),
            format(S, '    decl_assert_true(\'~w\', agent_loop_module:compile_logic(rust, ~w, _)),~n', [L3, M]),
            format(atom(L4), 'shared_logic(~w) compiles for elixir', [M]),
            format(S, '    decl_assert_true(\'~w\', agent_loop_module:compile_logic(elixir, ~w, _)),~n', [L4, M]),
            format(atom(L5), 'shared_logic(~w) compiles for prolog', [M]),
            format(S, '    decl_assert_true(\'~w\', agent_loop_module:compile_logic(prolog, ~w, _)),~n', [L5, M]),
            format(atom(L6), 'shared_logic(~w) compiles for clojure', [M]),
            format(S, '    decl_assert_true(\'~w\', agent_loop_module:compile_logic(clojure, ~w, _)),~n', [L6, M])
        )),
        write(S, '    true.\n\n')
    ).

%% --- Test runner ---
write_decl_test_runner(S) :-
    write(S, '%% =============================================================================\n'),
    write(S, '%% Test Runner\n'),
    write(S, '%% =============================================================================\n\n'),
    write(S, 'run_declarative_tests :-\n'),
    write(S, '    retractall(decl_test_passed(_)),\n'),
    write(S, '    retractall(decl_test_failed(_)),\n'),
    write(S, '    format("~n=== Declarative Tests (auto-generated) ===~n"),\n'),
    write(S, '    test_decl_existence,\n'),
    write(S, '    test_decl_properties,\n'),
    write(S, '    test_decl_crossrefs,\n'),
    write(S, '    test_decl_counts,\n'),
    write(S, '    test_decl_shared_logic,\n'),
    write(S, '    aggregate_all(count, decl_test_passed(_), Passed),\n'),
    write(S, '    aggregate_all(count, decl_test_failed(_), Failed),\n'),
    write(S, '    format("~n=== Declarative: ~w passed, ~w failed ===~n", [Passed, Failed]),\n'),
    write(S, '    true.  %% Main runner handles halt\n').

%% =============================================================================
%% Shared Logic — Target-Neutral Method Templates
%% =============================================================================
%%
%% shared_logic(+Component, +MethodName, +Properties)
%% Stores algorithms once, compiled to target-specific code via logic_slot/3.
%% This eliminates duplication between py_fragment and rust_fragment for
%% methods with identical logic and only syntactic differences.

shared_logic(costs, is_over_budget, [
    signature(is_over_budget, [budget], bool),
    arg_types([float]),
    doc("Check if total cost exceeds budget. Budget of 0 means unlimited."),
    container('CostTracker'),
    body_template("if ~guard_leq_zero(budget)~:\n    ~return_val(false)~\n~return_val(self_total_cost >= budget)~")
]).

shared_logic(costs, budget_remaining, [
    signature(budget_remaining, [budget], float),
    arg_types([float]),
    doc("Return remaining budget in USD. Budget of 0 means unlimited (returns -1)."),
    container('CostTracker'),
    body_template("if ~guard_leq_zero(budget)~:\n    ~return_val(-1.0)~\n~return_val(max_zero(budget - self_total_cost))~")
]).


shared_logic(tool_cache, cache_clear, [
    signature(clear, [], void),
    doc("Clear all cached tool results."),
    container('ToolResultCache'),
    mutable,
    field_map(python, ['self.cache'-'self._cache']),
    field_map(rust, ['self.cache()'-'self.cache']),
    field_map(elixir, ['state.cache.clear()'-'%{state | cache: %{}}']),
    field_map(clojure, ['(:cache state).clear()'-'(assoc state :cache {})']),
    field_map(prolog, ['State.cache.clear()'-'put_dict(cache, State, _{}, State1)']),
    body_template("~self_field(cache)~.clear()")
]).

shared_logic(tool_cache, cache_len, [
    signature(len, [], usize),
    doc("Return number of cached entries."),
    container('ToolResultCache'),
    field_map(python, ['self.cache'-'self._cache']),
    field_map(rust, ['self.cache()'-'self.cache']),
    body_template("~return_val(len_of(self_field(cache)))~")
]).

%% =============================================================================
%% Logic Slots — Target-specific syntax mappings
%% =============================================================================

%% Python slots
logic_slot(python, guard_leq_zero(X), S) :- expand_expr(python, X, XS), format(atom(S), "~w <= 0", [XS]).
logic_slot(python, guard_leq(A, B), S) :-
    expand_expr(python, A, AS), expand_expr(python, B, BS),
    format(atom(S), "~w <= ~w", [AS, BS]).
logic_slot(python, return_val(false), "return False").
logic_slot(python, return_val(true), "return True").
logic_slot(python, return_val(Expr), S) :-
    Expr \= true, Expr \= false,
    expand_expr(python, Expr, ExprStr),
    format(atom(S), "return ~w", [ExprStr]).
logic_slot(python, self_field(F), S) :- format(atom(S), "self.~w", [F]).

%% Rust slots
logic_slot(rust, guard_leq_zero(X), S) :- expand_expr(rust, X, XS), format(atom(S), "~w <= 0.0", [XS]).
logic_slot(rust, guard_leq(A, B), S) :-
    expand_expr(rust, A, AS), expand_expr(rust, B, BS),
    format(atom(S), "~w <= ~w", [AS, BS]).
logic_slot(rust, return_val(false), "return false;").
logic_slot(rust, return_val(true), "return true;").
logic_slot(rust, return_val(literal("")), "return String::new();").
%% Clone self fields when returning owned String to avoid move from &self
logic_slot(rust, return_val(self_direct(Field)), S) :-
    expand_expr(rust, self_direct(Field), FS),
    format(atom(S), "return ~w.clone();", [FS]).
logic_slot(rust, return_val(Expr), S) :-
    Expr \= true, Expr \= false,
    expand_expr(rust, Expr, ExprStr),
    %% Strip balanced outer parens to avoid "unnecessary parentheses around return value"
    atom_string(ExprStr, ExprS),
    (rust_strip_outer_parens(ExprS, Inner) ->
        format(atom(S), "return ~w;", [Inner])
    ;
        format(atom(S), "return ~w;", [ExprStr])
    ).

%% Strip outer parens if the expression is fully wrapped: "(expr)"
%% Only strip if no unbalanced parens remain inside
rust_strip_outer_parens(S, Inner) :-
    string_concat("(", Rest, S),
    string_concat(Inner, ")", Rest),
    rust_parens_balanced(Inner).

rust_parens_balanced(S) :-
    string_codes(S, Codes),
    rust_count_parens(Codes, 0).

rust_count_parens([], 0).
rust_count_parens([0'(|T], N) :- N1 is N + 1, rust_count_parens(T, N1).
rust_count_parens([0')|T], N) :- N > 0, N1 is N - 1, rust_count_parens(T, N1).
rust_count_parens([C|T], N) :- C \= 0'(, C \= 0'), rust_count_parens(T, N).
logic_slot(rust, self_field(F), S) :- format(atom(S), "self.~w()", [F]).

%% Prolog slots — state is a SWI-Prolog dict; results via unification
logic_slot(prolog, guard_leq_zero(X), S) :- expand_expr(prolog, X, XS), format(atom(S), "~w =< 0", [XS]).
logic_slot(prolog, guard_leq(A, B), S) :-
    expand_expr(prolog, A, AS), expand_expr(prolog, B, BS),
    format(atom(S), "~w =< ~w", [AS, BS]).
logic_slot(prolog, return_val(false), "Result = false").
logic_slot(prolog, return_val(true), "Result = true").
%% Special case: return_val(format_str(...)) → format(atom(Result), ...) directly
logic_slot(prolog, return_val(format_str(Fmt, Args)), S) :-
    format_args_list(Args, prolog, ArgStr),
    atomic_list_concat(Parts, '{}', Fmt),
    atomic_list_concat(Parts, '~w', PlFmt),
    format(atom(S), "format(atom(Result), \"~w\", [~w])", [PlFmt, ArgStr]).

logic_slot(prolog, return_val(Expr), S) :-
    Expr \= true, Expr \= false,
    expand_expr(prolog, Expr, ExprStr),
    %% If expanded expression already contains Result (goal-style), emit directly
    (sub_atom(ExprStr, _, _, _, 'Result') ->
        S = ExprStr
    ;
        %% If expression is a boolean/comparison, wrap in goal-style conditional
        (prolog_is_bool_expr(Expr) ->
            format(atom(S), "(~w -> Result = true ; Result = false)", [ExprStr])
        ;
            %% If expression is arithmetic, use 'is' instead of '='
            (prolog_is_arithmetic_expr(Expr) ->
                format(atom(S), "Result is ~w", [ExprStr])
            ;
                format(atom(S), "Result = ~w", [ExprStr])
            )
        )
    ).

%% Detect expressions that require arithmetic evaluation via is/2
prolog_is_arithmetic_expr(sub(_, _)).
prolog_is_arithmetic_expr(add(_, _)).
prolog_is_arithmetic_expr(mul(_, _)).
prolog_is_arithmetic_expr(div_float(_, _)).
prolog_is_arithmetic_expr(as_float(_)).
prolog_is_arithmetic_expr(len_of(_)).
prolog_is_arithmetic_expr(max_zero(_)).

%% Detect expressions that produce boolean results in Prolog
prolog_is_bool_expr(gt(_, _)).
prolog_is_bool_expr(gte(_, _)).
prolog_is_bool_expr(eq_zero(_)).
prolog_is_bool_expr(eq_str(_, _)).
prolog_is_bool_expr(not_expr(_)).
prolog_is_bool_expr(or_expr(_, _)).
prolog_is_bool_expr(and_expr(_, _)).
prolog_is_bool_expr(str_starts_with(_, _)).
prolog_is_bool_expr(map_has_key(_, _)).
prolog_is_bool_expr(path_exists(_)).
prolog_is_bool_expr(lt(_, _)).
prolog_is_bool_expr(lte(_, _)).
prolog_is_bool_expr(neq(_, _)).
prolog_is_bool_expr(self_total_cost >= _).
logic_slot(prolog, self_field(F), S) :- format(atom(S), "State.~w", [F]).

%% Expression expansion
expand_expr(python, self_total_cost >= budget, "self.total_cost >= budget").
expand_expr(rust, self_total_cost >= budget, "self.total_cost() >= budget").
expand_expr(python, max_zero(Expr), S) :-
    expand_expr(python, Expr, Inner),
    format(atom(S), "max(0.0, ~w)", [Inner]).
expand_expr(rust, max_zero(Expr), S) :-
    expand_expr(rust, Expr, Inner),
    format(atom(S), "(~w).max(0.0)", [Inner]).
expand_expr(python, budget - self_total_cost, "budget - self.total_cost").
expand_expr(rust, budget - self_total_cost, "budget - self.total_cost()").
expand_expr(python, len_of(Expr), S) :-
    expand_expr(python, Expr, Inner),
    format(atom(S), "len(~w)", [Inner]).
expand_expr(rust, len_of(Expr), S) :-
    expand_expr(rust, Expr, Inner),
    format(atom(S), "~w.len()", [Inner]).

%% --- Map access ---
expand_expr(python, map_get(Collection, Key), S) :-
    expand_expr(python, Collection, CS),
    expand_expr(python, Key, KS),
    format(atom(S), "~w.get(~w)", [CS, KS]).
expand_expr(rust, map_get(Collection, Key), S) :-
    expand_expr(rust, Collection, CS),
    expand_expr(rust, Key, KS),
    format(atom(S), "~w.get(~w).cloned()", [CS, KS]).

%% --- Map get with default ---
expand_expr(python, map_get_default(Coll, Key, Default), S) :-
    expand_expr(python, Coll, CS), expand_expr(python, Key, KS),
    expand_expr(python, Default, DS),
    format(atom(S), "~w.get(~w, ~w)", [CS, KS, DS]).
expand_expr(rust, map_get_default(Coll, Key, Default), S) :-
    expand_expr(rust, Coll, CS), expand_expr(rust, Key, KS),
    expand_expr(rust, Default, DS),
    format(atom(S), "~w.get(~w).cloned().unwrap_or_else(|| ~w.to_string())", [CS, KS, DS]).

%% --- Map has_key ---
expand_expr(python, map_has_key(Collection, Key), S) :-
    expand_expr(python, Collection, CS),
    expand_expr(python, Key, KS),
    format(atom(S), "~w in ~w", [KS, CS]).
expand_expr(rust, map_has_key(Collection, Key), S) :-
    expand_expr(rust, Collection, CS),
    expand_expr(rust, Key, KS),
    format(atom(S), "~w.contains_key(~w)", [CS, KS]).

%% --- Modulo ---
expand_expr(python, modulo(A, B), S) :-
    expand_expr(python, A, AS), expand_expr(python, B, BS),
    format(atom(S), "(~w % ~w)", [AS, BS]).
expand_expr(rust, modulo(A, B), S) :-
    expand_expr(rust, A, AS), expand_expr(rust, B, BS),
    format(atom(S), "(~w % ~w)", [AS, BS]).

%% --- HTML escape ---
expand_expr(python, html_escape(X), S) :-
    expand_expr(python, X, XS),
    format(atom(S), "~w.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('\"', '&quot;')", [XS]).
expand_expr(rust, html_escape(X), S) :-
    expand_expr(rust, X, XS),
    format(atom(S), '~w.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace("\\\"", "&quot;")', [XS]).

%% --- String truncation with ellipsis ---
expand_expr(python, str_slice_ellipsis(X, N), S) :-
    expand_expr(python, X, XS), expand_expr(python, N, NS),
    format(atom(S), "~w[:~w] + \"...\"", [XS, NS]).
expand_expr(rust, str_slice_ellipsis(X, N), S) :-
    expand_expr(rust, X, XS), expand_expr(rust, N, NS),
    format(atom(S), 'format!("{}...", &~w[..~w])', [XS, NS]).

%% --- List last element ---
expand_expr(python, list_last(Expr), S) :-
    expand_expr(python, Expr, Inner),
    format(atom(S), "~w[-1]", [Inner]).
expand_expr(rust, list_last(Expr), S) :-
    expand_expr(rust, Expr, Inner),
    format(atom(S), "~w.last().cloned()", [Inner]).

%% --- String split (whitespace) ---
expand_expr(python, str_split(X), S) :-
    expand_expr(python, X, XS),
    format(atom(S), "~w.split()", [XS]).
expand_expr(rust, str_split(X), S) :-
    expand_expr(rust, X, XS),
    format(atom(S), "~w.split_whitespace().collect::<Vec<_>>()", [XS]).

%% --- str_split with separator ---
expand_expr(python, str_split(X, Sep), S) :-
    expand_expr(python, X, XS),
    format(atom(S), '~w.split("~w")', [XS, Sep]).
expand_expr(rust, str_split(X, Sep), S) :-
    expand_expr(rust, X, XS),
    format(atom(S), '~w.split("~w").collect::<Vec<_>>()', [XS, Sep]).
expand_expr(elixir, str_split(X, Sep), S) :-
    expand_expr(elixir, X, XS),
    format(atom(S), 'String.split(~w, "~w")', [XS, Sep]).
expand_expr(prolog, str_split(X, Sep), S) :-
    expand_expr(prolog, X, XS),
    format(atom(S), 'split_string(~w, "~w", "", Parts)', [XS, Sep]).
expand_expr(clojure, str_split(X, Sep), S) :-
    expand_expr(clojure, X, XS),
    format(atom(S), '(clojure.string/split ~w #"~w")', [XS, Sep]).

%% --- Filter by suffix ---
expand_expr(python, filter_endswith(List, Suffix), S) :-
    expand_expr(python, List, LS),
    format(atom(S), '[f for f in ~w if f.endswith("~w")]', [LS, Suffix]).
expand_expr(rust, filter_endswith(List, Suffix), S) :-
    expand_expr(rust, List, LS),
    format(atom(S), '~w.iter().filter(|f| f.ends_with("~w")).collect::<Vec<_>>()', [LS, Suffix]).

%% --- Map keys ---
expand_expr(python, map_keys(Expr), S) :-
    expand_expr(python, Expr, ES),
    format(atom(S), "list(~w.keys())", [ES]).
expand_expr(rust, map_keys(Expr), S) :-
    expand_expr(rust, Expr, ES),
    format(atom(S), "~w.keys().cloned().collect::<Vec<_>>()", [ES]).

%% --- Addition ---
expand_expr(python, add(A, B), S) :-
    expand_expr(python, A, AS),
    expand_expr(python, B, BS),
    format(atom(S), "(~w + ~w)", [AS, BS]).
expand_expr(rust, add(A, B), S) :-
    expand_expr(rust, A, AS),
    expand_expr(rust, B, BS),
    format(atom(S), "(~w + ~w)", [AS, BS]).

%% --- Literal values ---
expand_expr(rust, literal(""), "\"\"") :- !.
expand_expr(python, literal(""), "\"\"") :- !.
expand_expr(elixir, literal(""), "\"\"") :- !.
expand_expr(clojure, literal(""), "\"\"") :- !.
expand_expr(prolog, literal(""), "\"\"") :- !.
expand_expr(_, literal(V), S) :- atom_string(V, S).

%% Note: self_direct/self_field handled by generic bridge (expand_expr -> logic_slot) at line ~2208

%% --- None/nil ---
expand_expr(python, none_val, "None").
expand_expr(rust, none_val, "None").
expand_expr(elixir, none_val, "nil").
expand_expr(prolog, none_val, "none").

%% --- Path operations ---
expand_expr(python, path_join(Dir, File), S) :-
    expand_expr(python, Dir, DS),
    expand_expr(python, File, FS),
    format(atom(S), "os.path.join(~w, ~w)", [DS, FS]).
expand_expr(rust, path_join(Dir, File), S) :-
    expand_expr(rust, Dir, DS),
    expand_expr(rust, File, FS),
    format(atom(S), "~w.join(~w)", [DS, FS]).
expand_expr(elixir, path_join(Dir, File), S) :-
    expand_expr(elixir, Dir, DS),
    expand_expr(elixir, File, FS),
    format(atom(S), "Path.join(~w, ~w)", [DS, FS]).
expand_expr(prolog, path_join(Dir, File), S) :-
    expand_expr(prolog, Dir, DS),
    expand_expr(prolog, File, FS),
    format(atom(S), "directory_file_path(~w, ~w, Path)", [DS, FS]).

expand_expr(python, path_exists(Path), S) :-
    expand_expr(python, Path, PS),
    format(atom(S), "os.path.exists(~w)", [PS]).
expand_expr(rust, path_exists(Path), S) :-
    expand_expr(rust, Path, PS),
    format(atom(S), "~w.exists()", [PS]).
expand_expr(elixir, path_exists(Path), S) :-
    expand_expr(elixir, Path, PS),
    format(atom(S), "File.exists?(~w)", [PS]).
expand_expr(prolog, path_exists(Path), S) :-
    expand_expr(prolog, Path, PS),
    format(atom(S), "exists_file(~w)", [PS]).

%% --- String equality ---
expand_expr(python, eq_str(A, B), S) :-
    expand_expr(python, A, AS),
    expand_expr(python, B, BS),
    format(atom(S), "~w == \"~w\"", [AS, BS]).
expand_expr(rust, eq_str(A, B), S) :-
    expand_expr(rust, A, AS),
    expand_expr(rust, B, BS),
    format(atom(S), "~w == \"~w\"", [AS, BS]).
expand_expr(elixir, eq_str(A, B), S) :-
    expand_expr(elixir, A, AS),
    expand_expr(elixir, B, BS),
    format(atom(S), "~w == \"~w\"", [AS, BS]).
expand_expr(prolog, eq_str(A, B), S) :-
    expand_expr(prolog, A, AS),
    expand_expr(prolog, B, BS),
    format(atom(S), "~w == \"~w\"", [AS, BS]).

expand_expr(clojure, Atom, S) :- atom(Atom), \+ number(Atom), Atom \= true, Atom \= false, Atom \= nil, Atom \= none_val, clojure_kebab(Atom, S).
%% Prolog atoms: capitalize identifier-like atoms as Prolog variables
expand_expr(prolog, Atom, S) :-
    atom(Atom), \+ number(Atom),
    Atom \= true, Atom \= false, Atom \= none,
    atom_chars(Atom, [H|T]),
    char_type(H, alpha),
    upcase_atom(H, UH),
    atom_chars(S, [UH|T]).
expand_expr(Target, Atom, S) :- Target \= clojure, Target \= prolog, atom(Atom), atom_string(Atom, S).

%% Strings — emit as quoted string literals
expand_expr(_, Str, S) :- string(Str), format(atom(S), '"~w"', [Str]).

%% Bridge: compound expressions that are actually slots delegate to logic_slot/3
expand_expr(Target, Expr, S) :-
    compound(Expr),
    logic_slot(Target, Expr, S), !.

%% =============================================================================
%% compile_logic/3 — Compile shared logic to target code
%% =============================================================================

compile_logic(Target, MethodName, Code) :-
    shared_logic(_, MethodName, Props),
    member(body_template(Template), Props),
    expand_template(Target, Template, Code).

%% =============================================================================
%% emit_shared_method/3 — Emit a complete method from shared_logic to a stream
%% =============================================================================

%% emit_shared_method(+Stream, +Target, +MethodName)
%% Writes a properly formatted method (with signature, doc, body) from shared_logic.
%%
%% Supported properties:
%%   container(none)  → standalone function (no self/&self)
%%   classmethod      → Python @classmethod with cls instead of self
%%   mutable          → Rust &mut self even for non-void return
%%   rust_use(Items)  → inject `use` statements before body (Rust only)
%%   field_map(Target, Map) → target-specific field name rewrites
%%   py_extra_body(Code)    → extra Python body lines appended after template
%%
%% --- Python emitter ---
emit_shared_method(S, python, MethodName) :-
    shared_logic(_, MethodName, Props),
    member(signature(Name0, Args, _RetType), Props),
    member(doc(Doc), Props),
    compile_logic(python, MethodName, Body),
    %% Apply private prefix if present
    (member(private, Props) ->
        atom_concat('_', Name0, Name)
    ;
        Name = Name0
    ),
    %% Determine receiver: none, associated, cls, or self
    member(container(Container), Props),
    (Container = none ->
        %% Standalone function (no indentation, no self)
        (Args = [] ->
            format(S, 'def ~w():~n', [Name])
        ;
            atomic_list_concat(Args, ', ', ArgsStr),
            format(S, 'def ~w(~w):~n', [Name, ArgsStr])
        ),
        format(S, '    """~w"""~n', [Doc]),
        Indent = '    '
    ; member(classmethod, Props) ->
        %% Class method with @classmethod decorator
        format(S, '    @classmethod~n', []),
        (Args = [] ->
            format(S, '    def ~w(cls):~n', [Name])
        ;
            atomic_list_concat(Args, ', ', ArgsStr),
            format(S, '    def ~w(cls, ~w):~n', [Name, ArgsStr])
        ),
        format(S, '        """~w"""~n', [Doc]),
        Indent = '        '
    ;
        %% Instance method (default) — associated methods skip 'self'
        (member(associated, Props) ->
            %% Static method (no self receiver, inside class)
            format(S, '    @staticmethod~n', []),
            (Args = [] ->
                format(S, '    def ~w():~n', [Name])
            ;
                atomic_list_concat(Args, ', ', ArgsStr),
                format(S, '    def ~w(~w):~n', [Name, ArgsStr])
            )
        ;
            (Args = [] ->
                format(S, '    def ~w(self):~n', [Name])
            ;
                atomic_list_concat(Args, ', ', ArgsStr),
                format(S, '    def ~w(self, ~w):~n', [Name, ArgsStr])
            )
        ),
        format(S, '        """~w"""~n', [Doc]),
        Indent = '        '
    ),
    %% Apply field_map rewrites if present
    atom_string(Body, BodyStr0),
    (member(field_map(python, Map), Props) ->
        apply_field_map(BodyStr0, Map, BodyStr)
    ;
        BodyStr = BodyStr0
    ),
    %% Emit body lines
    split_string(BodyStr, "\n", "", Lines),
    forall(member(Line, Lines), (
        format(S, '~w~w~n', [Indent, Line])
    )),
    %% Emit extra Python body if present
    (member(py_extra_body(Extra), Props) ->
        split_string(Extra, "\n", "", ExtraLines),
        forall(member(EL, ExtraLines), (
            format(S, '~w~w~n', [Indent, EL])
        ))
    ; true),
    nl(S).

%% --- Rust emitter ---
emit_shared_method(S, rust, MethodName) :-
    shared_logic(_, MethodName, Props),
    member(signature(Name, Args, RetType), Props),
    member(doc(Doc), Props),
    compile_logic(rust, MethodName, Body),
    member(container(Container), Props),
    %% Determine visibility
    (member(private, Props) -> Vis = '' ; Vis = 'pub '),
    format_rust_typed_args(Props, Args, ArgsStr),
    (Container = none ->
        %% Standalone function (no self, top-level)
        format(S, '#[allow(dead_code, unused_variables, unused_parens)]~n/// ~w~n', [Doc]),
        (RetType = void ->
            (Args = [] ->
                format(S, '~wfn ~w() {~n', [Vis, Name])
            ;
                format(S, '~wfn ~w(~w) {~n', [Vis, Name, ArgsStr])
            )
        ;
            resolve_type(rust, RetType, RType),
            (Args = [] ->
                format(S, '~wfn ~w() -> ~w {~n', [Vis, Name, RType])
            ;
                format(S, '~wfn ~w(~w) -> ~w {~n', [Vis, Name, ArgsStr, RType])
            )
        ),
        Indent = '    '
    ; member(associated, Props) ->
        %% Associated function (no self, inside impl block)
        format(S, '    #[allow(dead_code, unused_variables, unused_parens)]~n    /// ~w~n', [Doc]),
        (RetType = void ->
            (Args = [] ->
                format(S, '    ~wfn ~w() {~n', [Vis, Name])
            ;
                format(S, '    ~wfn ~w(~w) {~n', [Vis, Name, ArgsStr])
            )
        ;
            resolve_type(rust, RetType, RType),
            (Args = [] ->
                format(S, '    ~wfn ~w() -> ~w {~n', [Vis, Name, RType])
            ;
                format(S, '    ~wfn ~w(~w) -> ~w {~n', [Vis, Name, ArgsStr, RType])
            )
        ),
        Indent = '        '
    ;
        %% Method on struct (with self)
        format(S, '    #[allow(dead_code, unused_variables, unused_parens)]~n    /// ~w~n', [Doc]),
        (( RetType = void ; member(mutable, Props) ) ->
            MutSelf = '&mut self'
        ;
            MutSelf = '&self'
        ),
        (RetType = void ->
            (Args = [] ->
                format(S, '    ~wfn ~w(~w) {~n', [Vis, Name, MutSelf])
            ;
                format(S, '    ~wfn ~w(~w, ~w) {~n', [Vis, Name, MutSelf, ArgsStr])
            )
        ;
            resolve_type(rust, RetType, RType),
            (Args = [] ->
                format(S, '    ~wfn ~w(~w) -> ~w {~n', [Vis, Name, MutSelf, RType])
            ;
                format(S, '    ~wfn ~w(~w, ~w) -> ~w {~n', [Vis, Name, MutSelf, ArgsStr, RType])
            )
        ),
        Indent = '        '
    ),
    %% Emit use statements if present
    (member(rust_use(Uses), Props) ->
        forall(member(U, Uses), (
            format(S, '~wuse ~w;~n', [Indent, U])
        ))
    ; true),
    %% Apply field_map rewrites if present
    atom_string(Body, BodyStr0),
    (member(field_map(rust, Map), Props) ->
        apply_field_map(BodyStr0, Map, BodyStr)
    ;
        BodyStr = BodyStr0
    ),
    %% Emit body with Rust syntax fixup
    rust_fixup_body(BodyStr, FixedStr),
    split_string(FixedStr, "\n", "", Lines),
    forall(member(Line, Lines), (
        format(S, '~w~w~n', [Indent, Line])
    )),
    (Container = none ->
        format(S, '}~n~n', [])
    ;
        format(S, '    }~n~n', [])
    ).

%% --- Elixir emitter ---
%%
%% Elixir methods are module functions. State is passed as first arg and
%% returned for mutable methods (immutable update pattern).
%% =============================================================================
%% emit_rust_impl_block(+Stream, +RustStructName, +MethodNames)
%% Wraps a list of shared_logic method names in an impl block for the given struct.
%% Auto-filters to only emit methods whose container matches.
%% =============================================================================
emit_rust_impl_block(S, StructName, Methods) :-
    format(S, '\nimpl ~w {\n', [StructName]),
    forall(member(M, Methods), (
        (shared_logic(_, M, _) ->
            emit_shared_method(S, rust, M)
        ;
            true
        )
    )),
    write(S, '}\n').

%% emit_rust_module_methods(+Stream, +Module)
%% Emit all standalone (container=none) shared_logic methods for a module.
emit_rust_module_methods(S, Module) :-
    forall(
        (shared_logic(Module, MethodName, Props),
         member(container(none), Props)),
        emit_shared_method(S, rust, MethodName)
    ).

%% Container maps to module name (e.g., CostTracker → AgentLoop.CostTracker).
%% private → defp; public → def.
%% Mutable methods: body wrapped to return updated state.
%% @spec annotations generated from signature types.

emit_shared_method(S, elixir, MethodName) :-
    shared_logic(_, MethodName, Props),
    member(signature(Name, Args, RetType), Props),
    member(doc(Doc), Props),
    compile_logic(elixir, MethodName, Body),
    member(container(Container), Props),
    %% Determine visibility
    (member(private, Props) -> DefKw = 'defp' ; DefKw = 'def'),
    %% Format typed args for @spec
    format_elixir_spec_args(Props, Args, SpecArgs),
    resolve_type(elixir, RetType, ElixirRetType),
    %% Determine if mutable (state-returning)
    (member(mutable, Props) -> Mutable = true ; Mutable = false),
    (Container = none ->
        %% Standalone module function (no state)
        format(S, '  @doc "~w"~n', [Doc]),
        (Args = [] ->
            format(S, '  @spec ~w() :: ~w~n', [Name, ElixirRetType]),
            format(S, '  ~w ~w do~n', [DefKw, Name])
        ;
            format(S, '  @spec ~w(~w) :: ~w~n', [Name, SpecArgs, ElixirRetType]),
            atomic_list_concat(Args, ', ', ArgsStr),
            format(S, '  ~w ~w(~w) do~n', [DefKw, Name, ArgsStr])
        )
    ; member(associated, Props) ->
        %% Module function (no state parameter)
        format(S, '  @doc "~w"~n', [Doc]),
        (Args = [] ->
            format(S, '  @spec ~w() :: ~w~n', [Name, ElixirRetType]),
            format(S, '  ~w ~w do~n', [DefKw, Name])
        ;
            format(S, '  @spec ~w(~w) :: ~w~n', [Name, SpecArgs, ElixirRetType]),
            atomic_list_concat(Args, ', ', ArgsStr),
            format(S, '  ~w ~w(~w) do~n', [DefKw, Name, ArgsStr])
        )
    ;
        %% Instance method — state is first argument
        (Mutable = true ->
            format(S, '  @doc "~w"~n', [Doc]),
            (Args = [] ->
                format(S, '  @spec ~w(map()) :: map()~n', [Name]),
                format(S, '  ~w ~w(state) do~n', [DefKw, Name])
            ;
                format(S, '  @spec ~w(map(), ~w) :: map()~n', [Name, SpecArgs]),
                atomic_list_concat(Args, ', ', ArgsStr),
                format(S, '  ~w ~w(state, ~w) do~n', [DefKw, Name, ArgsStr])
            )
        ;
            format(S, '  @doc "~w"~n', [Doc]),
            (Args = [] ->
                format(S, '  @spec ~w(map()) :: ~w~n', [Name, ElixirRetType]),
                format(S, '  ~w ~w(state) do~n', [DefKw, Name])
            ;
                format(S, '  @spec ~w(map(), ~w) :: ~w~n', [Name, SpecArgs, ElixirRetType]),
                atomic_list_concat(Args, ', ', ArgsStr),
                format(S, '  ~w ~w(state, ~w) do~n', [DefKw, Name, ArgsStr])
            )
        )
    ),
    %% Apply field_map rewrites if present
    atom_string(Body, BodyStr0),
    (member(field_map(elixir, Map), Props) ->
        apply_field_map(BodyStr0, Map, BodyStr1)
    ;
        BodyStr1 = BodyStr0
    ),
    %% Apply Elixir fixup (if X: → if X do/end)
    elixir_fixup_body(BodyStr1, BodyStr2),
    %% Chain state updates for mutable methods: %{state | ...} → state = %{state | ...}
    (Mutable = true ->
        elixir_chain_state(BodyStr2, BodyStr)
    ;
        BodyStr = BodyStr2
    ),
    %% Emit body lines
    split_string(BodyStr, "\n", "", Lines),
    forall(member(Line, Lines), (
        format(S, '    ~w~n', [Line])
    )),
    format(S, '  end~n~n', []).

%% --- Prolog emitter ---
%%
%% Prolog methods are predicates. State is a SWI-Prolog dict passed as first arg.
%% Return values are unified with a Result variable (last arg).
%% container(X) where X \= none → predicate with State dict
%% container(none) → standalone predicate
%% Mutable → State in, State1 out
%%
emit_shared_method(S, prolog, MethodName) :-
    shared_logic(_, MethodName, Props),
    member(signature(Name, Args, RetType), Props),
    member(doc(Doc), Props),
    compile_logic(prolog, MethodName, Body),
    member(container(Container), Props),
    (member(mutable, Props) -> Mutable = true ; Mutable = false),
    %% Mark unused args with _ prefix to avoid Prolog singleton warnings
    prolog_mark_unused_args(Args, Body, MArgs),
    %% Comment/doc
    format(S, '%% ~w~n', [Doc]),
    %% Build argument list
    (Container = none ->
        %% Standalone predicate
        (RetType = void ->
            (MArgs = [] ->
                format(S, '~w :-~n', [Name])
            ;
                atomic_list_concat(MArgs, ', ', ArgsStr),
                prolog_capitalize_args(ArgsStr, CArgs),
                format(S, '~w(~w) :-~n', [Name, CArgs])
            )
        ;
            (MArgs = [] ->
                format(S, '~w(Result) :-~n', [Name])
            ;
                atomic_list_concat(MArgs, ', ', ArgsStr),
                prolog_capitalize_args(ArgsStr, CArgs),
                format(S, '~w(~w, Result) :-~n', [Name, CArgs])
            )
        )
    ;
        %% Method on state dict
        (Mutable = true ->
            (MArgs = [] ->
                format(S, '~w(State, State1) :-~n', [Name])
            ;
                atomic_list_concat(MArgs, ', ', ArgsStr),
                prolog_capitalize_args(ArgsStr, CArgs),
                format(S, '~w(State, ~w, State1) :-~n', [Name, CArgs])
            )
        ; RetType = void ->
            (MArgs = [] ->
                format(S, '~w(State) :-~n', [Name])
            ;
                atomic_list_concat(MArgs, ', ', ArgsStr),
                prolog_capitalize_args(ArgsStr, CArgs),
                format(S, '~w(State, ~w) :-~n', [Name, CArgs])
            )
        ;
            (MArgs = [] ->
                format(S, '~w(State, Result) :-~n', [Name])
            ;
                atomic_list_concat(MArgs, ', ', ArgsStr),
                prolog_capitalize_args(ArgsStr, CArgs),
                format(S, '~w(State, ~w, Result) :-~n', [Name, CArgs])
            )
        )
    ),
    %% Apply field_map rewrites if present
    atom_string(Body, BodyStr0),
    (member(field_map(prolog, Map), Props) ->
        apply_field_map(BodyStr0, Map, BodyStr1)
    ;
        BodyStr1 = BodyStr0
    ),
    %% Apply Prolog fixup (if X:\n    Y\nZ → (X -> Y ; Z))
    prolog_fixup_body(BodyStr1, BodyStr2),
    %% Capitalize parameter names in body (budget → Budget)
    prolog_capitalize_body_params(Args, BodyStr2, BodyStr3),
    %% Add commas between goals and period at end
    prolog_add_clause_punctuation(BodyStr3, BodyStr),
    %% Emit body lines
    split_string(BodyStr, "\n", "", Lines),
    forall(member(Line, Lines), (
        format(S, '    ~w~n', [Line])
    )),
    format(S, '~n', []).

%% Capitalize Prolog argument names (budget → Budget)
prolog_capitalize_args(ArgsStr, Result) :-
    split_string(ArgsStr, ", ", "", Parts0),
    exclude([P]>>(P = ""), Parts0, Parts),
    maplist([P, Cap]>>(
        string_chars(P, Chars),
        prolog_capitalize_one_arg(Chars, CapChars),
        atom_chars(Cap, CapChars)
    ), Parts, CapParts),
    atomic_list_concat(CapParts, ', ', Result).

%% Capitalize first letter; handle _prefix by capitalizing second char
prolog_capitalize_one_arg(['_', H|T], ['_', UH|T]) :- !,
    upcase_atom(H, UH).
prolog_capitalize_one_arg([H|T], [UH|T]) :-
    upcase_atom(H, UH).

%% Mark unused args with _ prefix for Prolog singleton avoidance
%% prolog_mark_unused_args(+Args, +Body, -MarkedArgs)
%% Checks if each capitalized arg appears in the body; if not, prepends _
prolog_mark_unused_args([], _, []).
prolog_mark_unused_args([Arg|Rest], Body, [Marked|RestMarked]) :-
    atom_string(Arg, ArgStr),
    atom_string(Body, BodyStr),
    %% Check both lowercase (pre-capitalize) and capitalized forms
    string_chars(ArgStr, [H|T]),
    upcase_atom(H, UH),
    atom_chars(CapArg, [UH|T]),
    atom_string(CapArg, CapStr),
    ((sub_string(BodyStr, _, _, _, ArgStr) ; sub_string(BodyStr, _, _, _, CapStr)) ->
        Marked = Arg
    ;
        atom_concat('_', Arg, Marked)
    ),
    prolog_mark_unused_args(Rest, Body, RestMarked).

%% Capitalize parameter names in the body text (budget → Budget, text → Text)
%% Uses word-boundary replacement to avoid over-matching substrings
prolog_capitalize_body_params([], Body, Body).
prolog_capitalize_body_params([Arg|Rest], BodyIn, BodyOut) :-
    atom_string(Arg, ArgStr),
    string_chars(ArgStr, [H|T]),
    upcase_atom(H, UH),
    atom_chars(CapArg, [UH|T]),
    %% Replace whole-word occurrences of the lowercase param with capitalized
    prolog_replace_param(ArgStr, CapArg, BodyIn, BodyMid),
    prolog_capitalize_body_params(Rest, BodyMid, BodyOut).

%% Replace a parameter name (whole word) in body text
%% We split on the param and check boundaries to avoid partial matches
prolog_replace_param(Param, CapParam, In, Out) :-
    atom_string(Param, ParamStr),
    atom_string(CapParam, CapStr),
    atom_string(In, InStr),
    string_length(ParamStr, PLen),
    prolog_replace_param_str(InStr, ParamStr, CapStr, PLen, OutStr),
    atom_string(Out, OutStr).

prolog_replace_param_str("", _, _, _, "").
prolog_replace_param_str(In, Param, Cap, PLen, Out) :-
    string_length(In, InLen),
    InLen >= PLen,
    sub_string(In, 0, PLen, _, Front),
    Front = Param,
    %% Check character before (at position -1 = start of string)
    %% and after to ensure word boundary
    sub_string(In, PLen, _, 0, After),
    (After = "" -> AfterOk = true
    ; sub_string(After, 0, 1, _, AfterChar),
      (prolog_is_ident_char(AfterChar) -> AfterOk = false ; AfterOk = true)
    ),
    AfterOk = true,
    !,
    prolog_replace_param_str(After, Param, Cap, PLen, RestOut),
    string_concat(Cap, RestOut, Out).
prolog_replace_param_str(In, Param, Cap, PLen, Out) :-
    sub_string(In, 0, 1, _, Ch),
    sub_string(In, 1, _, 0, Rest),
    %% If current char is ident char, skip ahead until word ends
    (prolog_is_ident_char(Ch) ->
        prolog_skip_ident(Rest, Skipped, Remaining),
        string_concat(Ch, Skipped, Word),
        prolog_replace_param_str(Remaining, Param, Cap, PLen, RestOut),
        string_concat(Word, RestOut, Out)
    ;
        prolog_replace_param_str(Rest, Param, Cap, PLen, RestOut),
        string_concat(Ch, RestOut, Out)
    ).

prolog_skip_ident("", "", "").
prolog_skip_ident(In, Skipped, Remaining) :-
    sub_string(In, 0, 1, _, Ch),
    (prolog_is_ident_char(Ch) ->
        sub_string(In, 1, _, 0, Rest),
        prolog_skip_ident(Rest, RestSkipped, Remaining),
        string_concat(Ch, RestSkipped, Skipped)
    ;
        Skipped = "",
        Remaining = In
    ).

prolog_is_ident_char(Ch) :-
    atom_string(ChAtom, Ch),
    char_code(ChAtom, Code),
    (Code >= 0'a, Code =< 0'z -> true
    ; Code >= 0'A, Code =< 0'Z -> true
    ; Code >= 0'0, Code =< 0'9 -> true
    ; ChAtom = '_' -> true
    ; fail
    ).

%% Add commas between Prolog body goals and a period at the end
%% Rules: don't add comma before lines starting with ';' or ')' or after '->'
prolog_add_clause_punctuation(In, Out) :-
    split_string(In, "\n", "", Lines),
    exclude([L]>>(L = ""), Lines, NonEmpty),
    (NonEmpty = [] ->
        Out = "true."
    ;
        prolog_punctuate_lines(NonEmpty, Punctuated),
        atomics_to_text(Punctuated, "\n", Out)
    ).

prolog_punctuate_lines([], []).
prolog_punctuate_lines([Last], [WithDot]) :-
    %% Add period to last line
    atom_concat(Last, '.', WithDot).
prolog_punctuate_lines([Line, Next|Rest], [WithComma|RestPunct]) :-
    %% Decide if comma needed between Line and Next
    (prolog_needs_comma(Line, Next) ->
        atom_concat(Line, ',', WithComma)
    ;
        WithComma = Line
    ),
    prolog_punctuate_lines([Next|Rest], RestPunct).

%% Check if a comma is needed between two consecutive lines
prolog_needs_comma(Line, Next) :-
    atom_string(Line, LineStr),
    atom_string(Next, NextStr),
    %% No comma if current line ends with '->' (conditional then)
    \+ sub_atom(Line, _, 2, 0, '->'),
    %% No comma if current line starts with '(' (conditional open)
    \+ sub_atom(Line, 0, 1, _, '('),
    %% No comma if current line is ';' or starts with ';' (else branch)
    \+ sub_string(LineStr, 0, 1, _, ";"),
    %% No comma if next line starts with ';' (else branch)
    \+ sub_string(NextStr, 0, 1, _, ";"),
    %% No comma if next line starts with ')' (closing conditional)
    \+ sub_string(NextStr, 0, 1, _, ")"),
    %% No comma if current line ends with '('
    \+ sub_atom(Line, _, 1, 0, '('),
    %% No comma if current line already ends with ','
    \+ sub_atom(Line, _, 1, 0, ',').

%% Prolog fixup: convert imperative if/return patterns to Prolog (Cond -> Then ; Else)
%% Prolog fixup: convert imperative if/return patterns to Prolog conditionals
%% Pattern: "if COND:\n    THEN\nELSE" → "(COND ->\n    THEN\n;\n    ELSE\n)"
%% Handles: single-line then, unindented else, no else (uses "; true)")
%% Also handles nested if/return patterns via recursive fixup
prolog_fixup_body(In, Out) :-
    split_string(In, "\n", "", Lines),
    prolog_fixup_lines(Lines, FixedLines),
    atomics_to_text(FixedLines, "\n", Out).

prolog_fixup_lines([], []).
prolog_fixup_lines([Line|Rest], Result) :-
    (  is_if_line(Line, Cond)
    ->
       %% Collect indented then-body lines
       collect_indented(Rest, ThenLines, AfterThen),
       (ThenLines = [] ->
           %% Malformed — pass through
           prolog_fixup_lines(Rest, RestFixed),
           Result = [Line|RestFixed]
       ;
           %% Strip leading indent from then-body
           maplist(strip_indent, ThenLines, StrippedThen),
           %% Recursively fixup nested if/return in then-body
           prolog_fixup_lines(StrippedThen, FixedThen),
           %% Check if there are else lines (unindented continuation)
           format(atom(CondLine), "(~w ->", [Cond]),
           indent_lines(FixedThen, IndentedThen),
           (AfterThen = [] ->
               append([CondLine|IndentedThen], ["; true)"], Result)
           ;
               %% Remaining lines are the else/continuation
               prolog_fixup_lines(AfterThen, FixedElse),
               append([CondLine|IndentedThen], [";"|FixedElse2], Result),
               append(FixedElse, [")"], FixedElse2)
           )
       )
    ;
       prolog_fixup_lines(Rest, RestFixed),
       Result = [Line|RestFixed]
    ).

%% Check if a line is "if COND:" and extract COND
is_if_line(Line, Cond) :-
    sub_string(Line, 0, _, _, "if "),
    sub_string(Line, _, 1, 0, ":"),
    sub_string(Line, 3, _, 1, Cond).

%% Collect lines with 4-space indent; stop at first unindented line
collect_indented([], [], []).
collect_indented([Line|Rest], [Line|Indented], After) :-
    sub_string(Line, 0, 4, _, "    "), !,
    collect_indented(Rest, Indented, After).
collect_indented(Lines, [], Lines).

%% Strip 4-space leading indent
strip_indent(Line, Stripped) :-
    (sub_string(Line, 0, 4, _, "    ") ->
        sub_string(Line, 4, _, 0, Stripped)
    ;
        Stripped = Line
    ).

%% Add 4-space indent to each line
indent_lines([], []).
indent_lines([L|Ls], [IL|ILs]) :-
    format(atom(IL), "    ~w", [L]),
    indent_lines(Ls, ILs).

atomics_to_text([], _, "").
atomics_to_text([X], _, X).
atomics_to_text([X|Xs], Sep, Result) :-
    Xs \= [],
    atomics_to_text(Xs, Sep, Rest),
    format(atom(Result), "~w~w~w", [X, Sep, Rest]).

%% Write shared block for Prolog target
write_shared_block_prolog(S, Module) :-
    write_shared_block(S, prolog, Module).

write_shared_block_clojure(S, Module) :-
    write_shared_block(S, clojure, Module).

%% Format Elixir @spec argument types
format_elixir_spec_args(Props, Args, ArgsStr) :-
    (member(arg_types(Types), Props) ->
        format_elixir_typed_list(Types, ArgsStr)
    ;
        length(Args, N),
        make_any_list(N, ArgsStr)
    ).

format_elixir_typed_list([], "").
format_elixir_typed_list([T], S) :- resolve_type(elixir, T, S).
format_elixir_typed_list([T|Ts], S) :-
    Ts \= [],
    resolve_type(elixir, T, TS),
    format_elixir_typed_list(Ts, Rest),
    format(atom(S), "~w, ~w", [TS, Rest]).

make_any_list(0, "").
make_any_list(1, "any()").
make_any_list(N, S) :-
    N > 1, N1 is N - 1,
    make_any_list(N1, Rest),
    format(atom(S), "any(), ~w", [Rest]).

%% apply_field_map(+Str, +Map, -Result)
%% Applies a list of From-To string replacements to Str.
apply_field_map(Str, [], Str).
apply_field_map(Str, [From-To|Rest], Result) :-
    atom_string(From, FromS),
    atom_string(To, ToS),
    split_string(Str, "", "", _),  %% ensure string
    (sub_string(Str, Before, _, After, FromS) ->
        sub_string(Str, 0, Before, _, Prefix),
        sub_string(Str, _, After, 0, Suffix),
        string_concat(Prefix, ToS, Tmp),
        string_concat(Tmp, Suffix, Str1),
        apply_field_map(Str1, [From-To|Rest], Result)  %% recurse for multiple occurrences
    ;
        apply_field_map(Str, Rest, Result)
    ).

%% Format Rust function arguments with types from signature props
format_rust_typed_args(Props, Args, ArgsStr) :-
    (member(arg_types(Types), Props) ->
        format_rust_args_typed(Args, Types, ArgsStr)
    ;
        format_rust_args_default(Args, ArgsStr)
    ).

format_rust_args_typed([], [], "").
format_rust_args_typed([A], [T], S) :-
    resolve_type(rust, T, RT),
    format(atom(S), "~w: ~w", [A, RT]).
format_rust_args_typed([A|As], [T|Ts], S) :-
    As \= [],
    resolve_type(rust, T, RT),
    format_rust_args_typed(As, Ts, Rest),
    format(atom(S), "~w: ~w, ~w", [A, RT, Rest]).

format_rust_args_default([], "").
format_rust_args_default([A], S) :- format(atom(S), "~w: &str", [A]).
format_rust_args_default([A|As], S) :-
    As \= [],
    format_rust_args_default(As, Rest),
    format(atom(S), "~w: &str, ~w", [A, Rest]).

%% Convert Python-style body to Rust-style:
%%   - "if X:" → "if X {"  with "}" closing after indented block
%%   - Add ";" to statement lines
rust_fixup_body(Str, Result) :-
    split_string(Str, "\n", "", Lines),
    rust_fixup_lines(Lines, 0, FixedLines),
    atomic_list_concat(FixedLines, '\n', Result).

rust_fixup_lines([], 0, []) :- !.
rust_fixup_lines([], BlockIndent, ["}"]) :- BlockIndent > 0, !.
rust_fixup_lines([Line|Rest], InBlock, Out) :-
    atom_string(Line, LS),
    %% Check if we need to close a block (indentation dropped)
    (InBlock > 0, \+ line_indented(LS, InBlock) ->
        %% Close the block, then process this line at outer level
        rust_fixup_lines([Line|Rest], 0, RestOut),
        Out = ["}" | RestOut]
    ;
        %% Process this line
        rust_fixup_single(LS, InBlock, FixedLine, NewBlock),
        (NewBlock > 0 ->
            rust_fixup_lines(Rest, NewBlock, RestOut)
        ;
            rust_fixup_lines(Rest, InBlock, RestOut)
        ),
        Out = [FixedLine | RestOut]
    ).

%% Check if a line is indented by at least N spaces
line_indented(Str, N) :-
    string_length(Str, Len), Len >= N,
    sub_string(Str, 0, N, _, Prefix),
    atom_string(SpAtom, Prefix),
    atom_codes(SpAtom, Codes),
    maplist(=(0' ), Codes).

%% Process a single line: handle "if X:" and add semicolons
rust_fixup_single(LS, _InBlock, Fixed, NewBlock) :-
    %% Check for "if X:" pattern (with optional leading spaces)
    (sub_string(LS, _, 1, 0, ":"),
     %% Find "if " somewhere after leading spaces
     string_concat(Spaces, Core, LS),
     atom_string(SpA, Spaces), atom_codes(SpA, SpCodes),
     (SpCodes = [] ; maplist(=(0' ), SpCodes)),
     sub_string(Core, 0, 3, _, "if ") ->
        %% Convert "if X:" → "if X {"
        sub_string(LS, 0, _, 1, Prefix),
        string_concat(Prefix, " {", FS),
        atom_string(Fixed, FS),
        NewBlock = 4
    ;
        %% Regular line — add semicolon if it's a statement
        rust_maybe_semicolon(LS, Fixed),
        NewBlock = 0
    ).

%% Add semicolons to Rust statement lines
rust_maybe_semicolon(LS, Fixed) :-
    string_length(LS, Len),
    (Len =:= 0 ->
        Fixed = ''
    ; sub_string(LS, _, 1, 0, "{") ->
        atom_string(Fixed, LS)
    ; sub_string(LS, _, 1, 0, "}") ->
        atom_string(Fixed, LS)
    ; sub_string(LS, _, 1, 0, ";") ->
        atom_string(Fixed, LS)
    ;
        %% Strip trailing spaces for clean output
        string_concat(LS, ";", WithSemi),
        atom_string(Fixed, WithSemi)
    ).

%% elixir_chain_state/2 — Chain %{state | ...} updates for mutable Elixir methods.
%% Non-last %{state | ...} lines get "state = " prepended so they rebind state.
elixir_chain_state(Str, Result) :-
    split_string(Str, "\n", "", Lines),
    reverse(Lines, RevLines),
    elixir_chain_lines(RevLines, true, RevResult),
    reverse(RevResult, ResultLines),
    atomic_list_concat(ResultLines, '\n', Result).

elixir_chain_lines([], _, []).
elixir_chain_lines([Line|Rest], IsLast, [Fixed|FixedRest]) :-
    atom_string(LineAtom, Line),
    (IsLast = false, sub_string(Line, 0, _, _, "%{state |") ->
        atom_concat('state = ', LineAtom, Fixed)
    ;
        Fixed = LineAtom
    ),
    %% After first line (which is last in original), all subsequent are non-last
    (sub_string(Line, 0, _, _, "%{state |") ->
        elixir_chain_lines(Rest, false, FixedRest)
    ;
        elixir_chain_lines(Rest, IsLast, FixedRest)
    ).

%% elixir_fixup_body/2 — Convert Python-style if/else blocks to Elixir do/end
%% Handles: "if X:" → "if X do" + "end", with "else" insertion when there's
%% code after the block (early-return pattern).
elixir_fixup_body(Str, Result) :-
    split_string(Str, "\n", "", Lines),
    elixir_fixup_lines(Lines, 0, FixedLines),
    atomic_list_concat(FixedLines, '\n', Result).

elixir_fixup_lines([], 0, []) :- !.
elixir_fixup_lines([], BlockIndent, ["end"]) :- BlockIndent > 0, !.
elixir_fixup_lines([Line|Rest], InBlock, Out) :-
    atom_string(Line, LS),
    (InBlock > 0, \+ line_indented(LS, InBlock) ->
        %% Block ended — remaining lines become else branch
        %% Indent the else-body lines by the block indent
        elixir_fixup_lines(Rest, 0, RestFixed),
        atom_string(IndentedLine, LS),
        format(atom(IndentedFirst), "    ~w", [IndentedLine]),
        maplist([L, IL]>>(format(atom(IL), "    ~w", [L])), RestFixed, IndentedRest),
        append(["else", IndentedFirst | IndentedRest], ["end"], Out)
    ;
        elixir_fixup_single(LS, FixedLine, NewBlock),
        (NewBlock > 0 ->
            elixir_fixup_lines(Rest, NewBlock, RestOut)
        ;
            elixir_fixup_lines(Rest, InBlock, RestOut)
        ),
        Out = [FixedLine | RestOut]
    ).

elixir_fixup_single(LS, Fixed, NewBlock) :-
    %% Check for "if X:" pattern
    (sub_string(LS, _, 1, 0, ":"),
     string_concat(Spaces, Core, LS),
     atom_string(SpA, Spaces), atom_codes(SpA, SpCodes),
     (SpCodes = [] ; maplist(=(0' ), SpCodes)),
     sub_string(Core, 0, 3, _, "if ") ->
        %% Convert "if X:" → "if X do"
        sub_string(LS, 0, _, 1, Prefix),
        string_concat(Prefix, " do", FS),
        atom_string(Fixed, FS),
        NewBlock = 4
    ;
        atom_string(Fixed, LS),
        NewBlock = 0
    ).

%% write_shared_block(+Stream, +Target, +Module)
%% Emit all shared_logic methods for a module as a block with header comment.
write_shared_block(S, Target, Module) :-
    findall(M, shared_logic(Module, M, _), Methods),
    (Methods \= [] ->
        ((Target = python ; Target = elixir) ->
            format(S, '~n# --- shared_logic: ~w (generated from compile_logic) ---~n~n', [Module])
        ; Target = prolog ->
            format(S, '~n%% --- shared_logic: ~w (generated from compile_logic) ---~n~n', [Module])
        ; Target = clojure ->
            format(S, '~n;; --- shared_logic: ~w (generated from compile_logic) ---~n~n', [Module])
        ;
            format(S, '~n// --- shared_logic: ~w (generated from compile_logic) ---~n~n', [Module])
        ),
        forall(member(Method, Methods), (
            emit_shared_method(S, Target, Method)
        ))
    ;
        true  %% No methods for this module — skip silently
    ).

%% write_shared_block_py(+Stream, +Module) — convenience for Python target
write_shared_block_py(S, Module) :- write_shared_block(S, python, Module).

%% write_shared_block_rust(+Stream, +Module) — convenience for Rust target
write_shared_block_rust(S, Module) :- write_shared_block(S, rust, Module).

%% write_shared_block_elixir(+Stream, +Module) — convenience for Elixir target
write_shared_block_elixir(S, Module) :- write_shared_block(S, elixir, Module).

%% expand_template(+Target, +Template, -Result)
%% Replace ~slot(args)~ markers with target-specific expansions.
expand_template(Target, Template, Result) :-
    atom_string(Template, TStr),
    expand_template_str(Target, TStr, ResultStr),
    atom_string(Result, ResultStr).

expand_template_str(_, Str, Str) :-
    \+ sub_string(Str, _, _, _, "~"), !.
expand_template_str(Target, Str, Result) :-
    %% Find the first ~ in the string
    sub_string(Str, Before, 1, _, "~"),
    sub_string(Str, 0, Before, _, Prefix),
    AfterStart is Before + 1,
    sub_string(Str, AfterStart, _, 0, Rest),
    %% Check if it's a ~~ escape (next char is also ~)
    (sub_string(Rest, 0, 1, _, "~") ->
        %% ~~ escape: emit literal ~ and continue after both tildes
        sub_string(Rest, 1, _, 0, AfterEscape),
        expand_template_str(Target, AfterEscape, ExpandedRest),
        string_concat(Prefix, "~", WithTilde),
        string_concat(WithTilde, ExpandedRest, Result)
    ;
    %% Regular ~slot~ expansion
    (sub_string(Rest, End, 1, _, "~") ->
        sub_string(Rest, 0, End, _, SlotStr),
        AfterSlot is End + 1,
        sub_string(Rest, AfterSlot, _, 0, Remaining),
        term_string(SlotTerm, SlotStr),
        (logic_slot(Target, SlotTerm, Replacement) ->
            true
        ; expand_expr(Target, SlotTerm, Replacement) ->
            true
        ;
            %% Slot not found — keep literal
            format(atom(Replacement), "~w", [SlotStr])
        ),
        atom_string(Replacement, RepStr),
        string_concat(Prefix, RepStr, Partial),
        expand_template_str(Target, Remaining, ExpandedRest),
        string_concat(Partial, ExpandedRest, Result)
    ;
        %% No closing tilde — keep as is
        Result = Str
    )).

%% =============================================================================
%% resolve_type/3 — Abstract type vocabulary (inspired by TypR type_declarations)
%% Maps abstract types in shared_logic signatures to concrete target types.
%% =============================================================================

resolve_type(python, int, "int").
resolve_type(python, float, "float").
resolve_type(python, string, "str").
resolve_type(python, bool, "bool").
resolve_type(python, void, "None").
resolve_type(python, usize, "int").
resolve_type(python, dict, "dict").
resolve_type(python, set_of_string, "set[str]").
resolve_type(python, owned_string, "str").
resolve_type(python, list_of_dict, "list[dict]").
resolve_type(python, list_of_string, "list[str]").
resolve_type(python, list, "list").
resolve_type(python, ref(T), S) :-
    resolve_type(python, T, S).
resolve_type(python, optional(T), S) :-
    resolve_type(python, T, Inner),
    format(atom(S), "~w | None", [Inner]).

resolve_type(rust, int, "i64").
resolve_type(rust, float, "f64").
resolve_type(rust, string, "&str").
resolve_type(rust, bool, "bool").
resolve_type(rust, void, "()").
resolve_type(rust, usize, "usize").
resolve_type(rust, dict, "std::collections::HashMap<String, serde_json::Value>").
resolve_type(rust, set_of_string, "std::collections::HashSet<String>").
resolve_type(rust, owned_string, "String").
resolve_type(rust, list_of_dict, "Vec<serde_json::Value>").
resolve_type(rust, list_of_string, "Vec<String>").
resolve_type(rust, list, "Vec<serde_json::Value>").
resolve_type(rust, ref(T), S) :-
    resolve_type(rust, T, Inner),
    format(atom(S), "&~w", [Inner]).
resolve_type(rust, optional(T), S) :-
    resolve_type(rust, T, Inner),
    format(atom(S), "Option<~w>", [Inner]).

%% =============================================================================
%% Additional shared_logic/3 — Expand coverage to streaming, cache, retry, parser
%% =============================================================================

%% --- StreamingTokenCounter methods ---

shared_logic(streaming, on_token, [
    signature(on_token, [token], void),
    arg_types([string]),
    mutable,
    rust_use(['std::io::Write']),
    doc("Process a streamed token chunk: print it, update char and token counts."),
    container('StreamingTokenCounter'),
    body_template("~print_flush(token)~\n~self_inc(char_count, str_len(token))~\n~self_assign(token_count, max_one(int_div(self_direct(char_count), 4)))~")
]).

shared_logic(streaming, format_summary, [
    signature(format_summary, [], owned_string),
    doc("Format a one-line summary of streaming stats."),
    container('StreamingTokenCounter'),
