%% =============================================================================
%% Additional logic_slot/3 — Slots for expanded shared_logic coverage
%% =============================================================================

%% --- eq_zero: check if value is zero ---
expand_expr(python, eq_zero(X), S) :-
    expand_expr(python, X, XS), format(atom(S), "~w == 0", [XS]).
expand_expr(rust, eq_zero(X), S) :-
    expand_expr(rust, X, XS), format(atom(S), "~w == 0", [XS]).
expand_expr(elixir, eq_zero(X), S) :-
    expand_expr(elixir, X, XS), format(atom(S), "~w == 0", [XS]).
expand_expr(prolog, eq_zero(X), S) :-
    expand_expr(prolog, X, XS), format(atom(S), "~w =:= 0", [XS]).
expand_expr(clojure, eq_zero(X), S) :-
    expand_expr(clojure, X, XS), format(atom(S), "(zero? ~w)", [XS]).

%% --- list_tail_n: get last N elements ---
expand_expr(python, list_tail_n(List, N), S) :-
    expand_expr(python, List, LS), expand_expr(python, N, NS),
    format(atom(S), "~w[-~w:]", [LS, NS]).
expand_expr(rust, list_tail_n(List, N), S) :-
    expand_expr(rust, List, LS), expand_expr(rust, N, NS),
    format(atom(S), "~w[~w.len().saturating_sub(~w)..]", [LS, LS, NS]).
expand_expr(elixir, list_tail_n(List, N), S) :-
    expand_expr(elixir, List, LS), expand_expr(elixir, N, NS),
    format(atom(S), "Enum.take(~w, -~w)", [LS, NS]).
expand_expr(prolog, list_tail_n(List, N), S) :-
    expand_expr(prolog, List, LS), expand_expr(prolog, N, NS),
    format(atom(S), "last_n(~w, ~w, Result)", [LS, NS]).
expand_expr(clojure, list_tail_n(List, N), S) :-
    expand_expr(clojure, List, LS), expand_expr(clojure, N, NS),
    format(atom(S), "(take-last ~w ~w)", [NS, LS]).

%% --- list_first: get first element ---
expand_expr(python, list_first(List), S) :-
    expand_expr(python, List, LS), format(atom(S), "~w[0]", [LS]).
expand_expr(rust, list_first(List), S) :-
    expand_expr(rust, List, LS), format(atom(S), "~w.first().cloned()", [LS]).
expand_expr(elixir, list_first(List), S) :-
    expand_expr(elixir, List, LS), format(atom(S), "List.first(~w)", [LS]).
expand_expr(prolog, list_first(List), S) :-
    expand_expr(prolog, List, LS), format(atom(S), "nth0(0, ~w, Result)", [LS]).
expand_expr(clojure, list_first(List), S) :-
    expand_expr(clojure, List, LS), format(atom(S), "(first ~w)", [LS]).

%% --- field_of: access a named field/key on an object ---
expand_expr(python, field_of(Obj, Field), S) :-
    expand_expr(python, Obj, OS),
    format(atom(S), '~w.get("~w", "")', [OS, Field]).
expand_expr(rust, field_of(Obj, Field), S) :-
    expand_expr(rust, Obj, OS),
    format(atom(S), "~w.map(|x| x.~w.clone()).unwrap_or_default()", [OS, Field]).
expand_expr(elixir, field_of(Obj, Field), S) :-
    expand_expr(elixir, Obj, OS),
    format(atom(S), "Map.get(~w, :~w, \"\")", [OS, Field]).
expand_expr(prolog, field_of(Obj, Field), S) :-
    expand_expr(prolog, Obj, OS),
    format(atom(S), "get_dict(~w, ~w, Result)", [Field, OS]).
expand_expr(clojure, field_of(Obj, Field), S) :-
    expand_expr(clojure, Obj, OS),
    clojure_kebab(Field, KF),
    format(atom(S), '(:~w ~w)', [KF, OS]).

%% --- list_rest: get all but first element ---
expand_expr(python, list_rest(List), S) :-
    expand_expr(python, List, LS), format(atom(S), "~w[1:]", [LS]).
expand_expr(rust, list_rest(List), S) :-
    expand_expr(rust, List, LS), format(atom(S), "~w[1..].to_vec()", [LS]).
expand_expr(elixir, list_rest(List), S) :-
    expand_expr(elixir, List, LS), format(atom(S), "tl(~w)", [LS]).
expand_expr(prolog, list_rest(List), S) :-
    expand_expr(prolog, List, LS), format(atom(S), "~w = [_|Result]", [LS]).
expand_expr(clojure, list_rest(List), S) :-
    expand_expr(clojure, List, LS), format(atom(S), "(rest ~w)", [LS]).

%% --- list_nth: get element at index ---
expand_expr(python, list_nth(List, N), S) :-
    expand_expr(python, List, LS), expand_expr(python, N, NS),
    format(atom(S), "~w[~w]", [LS, NS]).
expand_expr(rust, list_nth(List, N), S) :-
    expand_expr(rust, List, LS), expand_expr(rust, N, NS),
    format(atom(S), "~w[~w]", [LS, NS]).
expand_expr(elixir, list_nth(List, N), S) :-
    expand_expr(elixir, List, LS), expand_expr(elixir, N, NS),
    format(atom(S), "Enum.at(~w, ~w)", [LS, NS]).
expand_expr(prolog, list_nth(List, N), S) :-
    expand_expr(prolog, List, LS), expand_expr(prolog, N, NS),
    format(atom(S), "nth0(~w, ~w, Result)", [NS, LS]).
expand_expr(clojure, list_nth(List, N), S) :-
    expand_expr(clojure, List, LS), expand_expr(clojure, N, NS),
    format(atom(S), "(nth ~w ~w nil)", [LS, NS]).

%% --- is_empty_str: check if string is empty ---
logic_slot(python, is_empty_str(X), S) :-
    expand_expr(python, X, XS), format(atom(S), "not ~w", [XS]).
logic_slot(rust, is_empty_str(X), S) :-
    expand_expr(rust, X, XS), format(atom(S), "~w.is_empty()", [XS]).
logic_slot(elixir, is_empty_str(X), S) :-
    expand_expr(elixir, X, XS), format(atom(S), "~w == \"\"", [XS]).
logic_slot(prolog, is_empty_str(X), S) :-
    expand_expr(prolog, X, XS), format(atom(S), '~w == ""', [XS]).
logic_slot(clojure, is_empty_str(X), S) :-
    expand_expr(clojure, X, XS), format(atom(S), "(empty? ~w)", [XS]).

%% --- str_contains: check if string contains substring ---
logic_slot(python, str_contains(Str, Sub), S) :-
    expand_expr(python, Str, SS),
    format(atom(S), '"~w" in ~w', [Sub, SS]).
logic_slot(rust, str_contains(Str, Sub), S) :-
    expand_expr(rust, Str, SS),
    format(atom(S), '~w.contains("~w")', [SS, Sub]).
logic_slot(elixir, str_contains(Str, Sub), S) :-
    expand_expr(elixir, Str, SS),
    format(atom(S), 'String.contains?(~w, "~w")', [SS, Sub]).
logic_slot(prolog, str_contains(Str, Sub), S) :-
    expand_expr(prolog, Str, SS),
    format(atom(S), 'sub_string(~w, _, _, _, "~w")', [SS, Sub]).
logic_slot(clojure, str_contains(Str, Sub), S) :-
    expand_expr(clojure, Str, SS),
    format(atom(S), '(clojure.string/includes? ~w "~w")', [SS, Sub]).

%% --- str_slice_from: substring from index N to end ---
expand_expr(python, str_slice_from(Str, N), S) :-
    expand_expr(python, Str, SS), format(atom(S), "~w[~w:]", [SS, N]).
expand_expr(rust, str_slice_from(Str, N), S) :-
    expand_expr(rust, Str, SS), format(atom(S), "&~w[~w..]", [SS, N]).
expand_expr(elixir, str_slice_from(Str, N), S) :-
    expand_expr(elixir, Str, SS), format(atom(S), "String.slice(~w, ~w..-1)", [SS, N]).
expand_expr(prolog, str_slice_from(Str, N), S) :-
    expand_expr(prolog, Str, SS), format(atom(S), "sub_string(~w, ~w, _, 0, Result)", [SS, N]).
expand_expr(clojure, str_slice_from(Str, N), S) :-
    expand_expr(clojure, Str, SS), format(atom(S), "(subs ~w ~w)", [SS, N]).

%% --- str_slice_to: substring from start to index N (negative = from end) ---
expand_expr(python, str_slice_to(Str, N), S) :-
    expand_expr(python, Str, SS), format(atom(S), "~w[:~w]", [SS, N]).
expand_expr(rust, str_slice_to(Str, N), S) :-
    expand_expr(rust, Str, SS),
    (N < 0 ->
        AbsN is abs(N),
        format(atom(S), "&~w[..~w.len()-~w]", [SS, SS, AbsN])
    ;
        format(atom(S), "&~w[..~w]", [SS, N])
    ).
expand_expr(elixir, str_slice_to(Str, N), S) :-
    expand_expr(elixir, Str, SS),
    format(atom(S), "String.slice(~w, 0..~w)", [SS, N]).
expand_expr(prolog, str_slice_to(Str, N), S) :-
    expand_expr(prolog, Str, SS),
    (N < 0 ->
        AbsN is abs(N),
        format(atom(S), "atom_length(~w, Len), End is Len - ~w, sub_atom(~w, 0, End, _, Result)", [SS, AbsN, SS])
    ;
        format(atom(S), "sub_atom(~w, 0, ~w, _, Result)", [SS, N])
    ).
expand_expr(clojure, str_slice_to(Str, N), S) :-
    expand_expr(clojure, Str, SS),
    (N < 0 ->
        AbsN is abs(N),
        format(atom(S), "(subs ~w 0 (- (count ~w) ~w))", [SS, SS, AbsN])
    ;
        format(atom(S), "(subs ~w 0 ~w)", [SS, N])
    ).

%% --- Print/IO slots ---
logic_slot(python, print_flush(X), S) :-
    format(atom(S), "print(~w, end=\"\", flush=True)", [X]).
logic_slot(rust, print_flush(X), S) :-
    format(atom(S), "print!(\"{}\", ~w); std::io::stdout().flush().ok()", [X]).

%% --- String/collection slots ---
logic_slot(python, str_len(X), S) :- format(atom(S), "len(~w)", [X]).
logic_slot(rust, str_len(X), S) :- format(atom(S), "~w.len()", [X]).

logic_slot(python, contains(Collection, Item), S) :-
    expand_expr(python, Collection, CS),
    expand_expr(python, Item, IS),
    format(atom(S), "~w in ~w", [IS, CS]).
logic_slot(rust, contains(Collection, Item), S) :-
    expand_expr(rust, Collection, CS),
    expand_expr(rust, Item, IS),
    format(atom(S), "~w.contains(&~w)", [CS, IS]).

logic_slot(python, not_empty(X), S) :-
    expand_expr(python, X, XS), format(atom(S), "~w", [XS]).
logic_slot(rust, not_empty(X), S) :-
    expand_expr(rust, X, XS), format(atom(S), "!~w.is_empty()", [XS]).

%% Direct struct field access (no () in Rust, same as Python self.field)
logic_slot(python, self_direct(F), S) :- format(atom(S), "self.~w", [F]).
logic_slot(rust, self_direct(F), S) :- format(atom(S), "self.~w", [F]).

%% --- Assignment/mutation slots ---
logic_slot(python, self_inc(Field, Expr), S) :-
    logic_slot(python, self_field(Field), SF),
    expand_expr(python, Expr, ES),
    format(atom(S), "~w += ~w", [SF, ES]).
logic_slot(rust, self_inc(Field, Expr), S) :-
    expand_expr(rust, Expr, ES),
    format(atom(S), "self.~w += ~w", [Field, ES]).

logic_slot(python, self_assign(Field, Expr), S) :-
    logic_slot(python, self_field(Field), SF),
    expand_expr(python, Expr, ES),
    format(atom(S), "~w = ~w", [SF, ES]).
logic_slot(rust, self_assign(Field, Expr), S) :-
    expand_expr(rust, Expr, ES),
    format(atom(S), "self.~w = ~w", [Field, ES]).

logic_slot(python, assign(Var, Expr), S) :-
    expand_expr(python, Expr, ES),
    format(atom(S), "~w = ~w", [Var, ES]).
logic_slot(rust, assign(Var, Expr), S) :-
    expand_expr(rust, Expr, ES),
    format(atom(S), "let ~w = ~w", [Var, ES]).

%% --- Map/collection mutation slots ---
logic_slot(python, self_map_put(Field, Key, Value), S) :-
    logic_slot(python, self_field(Field), SF),
    expand_expr(python, Key, KS),
    expand_expr(python, Value, VS),
    format(atom(S), "~w[~w] = ~w", [SF, KS, VS]).
logic_slot(rust, self_map_put(Field, Key, Value), S) :-
    expand_expr(rust, Key, KS),
    expand_expr(rust, Value, VS),
    format(atom(S), "self.~w.insert(~w, ~w)", [Field, KS, VS]).

logic_slot(python, self_list_append(Field, Item), S) :-
    logic_slot(python, self_field(Field), SF),
    expand_expr(python, Item, IS),
    format(atom(S), "~w.append(~w)", [SF, IS]).
logic_slot(rust, self_list_append(Field, Item), S) :-
    expand_expr(rust, Item, IS),
    format(atom(S), "self.~w.push(~w)", [Field, IS]).

%% --- Map keys / remove slots ---
logic_slot(python, map_keys(Expr), S) :-
    expand_expr(python, Expr, ES),
    format(atom(S), "list(~w.keys())", [ES]).
logic_slot(rust, map_keys(Expr), S) :-
    expand_expr(rust, Expr, ES),
    format(atom(S), "~w.keys().cloned().collect::<Vec<_>>()", [ES]).

logic_slot(python, self_map_remove(Field, Key), S) :-
    logic_slot(python, self_field(Field), SF),
    expand_expr(python, Key, KS),
    format(atom(S), "~w.pop(~w, None)", [SF, KS]).
logic_slot(rust, self_map_remove(Field, Key), S) :-
    expand_expr(rust, Key, KS),
    format(atom(S), "self.~w.remove(&~w)", [Field, KS]).

%% --- String split (whitespace) ---
logic_slot(python, str_split(X), S) :- format(atom(S), "~w.split()", [X]).
logic_slot(rust, str_split(X), S) :-
    format(atom(S), "~w.split_whitespace().collect::<Vec<_>>()", [X]).

%% --- Filter list by suffix ---
logic_slot(python, filter_endswith(List, Suffix), S) :-
    format(atom(S), '[f for f in ~w if f.endswith("~w")]', [List, Suffix]).
logic_slot(rust, filter_endswith(List, Suffix), S) :-
    format(atom(S), '~w.iter().filter(|f| f.ends_with("~w")).collect::<Vec<_>>()', [List, Suffix]).

%% --- Arithmetic slots ---
logic_slot(python, matches_set(X, List), S) :-
    atomic_list_concat(List, ', ', Items),
    format(atom(S), "~w in {~w}", [X, Items]).
logic_slot(rust, matches_set(X, List), S) :-
    atomic_list_concat(List, ' | ', Items),
    format(atom(S), "matches!(~w, ~w)", [X, Items]).

%% --- String set membership (quoted) ---
logic_slot(python, matches_str_set(X, List), S) :-
    maplist([Item, Quoted]>>format(atom(Quoted), "\"~w\"", [Item]), List, QList),
    atomic_list_concat(QList, ', ', Items),
    format(atom(S), "~w in {~w}", [X, Items]).
logic_slot(rust, matches_str_set(X, List), S) :-
    maplist([Item, Quoted]>>format(atom(Quoted), "\"~w\"", [Item]), List, QList),
    atomic_list_concat(QList, ' | ', Items),
    format(atom(S), "matches!(~w.as_str(), ~w)", [X, Items]).
logic_slot(elixir, matches_str_set(X, List), S) :-
    maplist([Item, Quoted]>>format(atom(Quoted), "\"~w\"", [Item]), List, QList),
    atomic_list_concat(QList, ', ', Items),
    format(atom(S), "~w in [~w]", [X, Items]).
logic_slot(prolog, matches_str_set(X, List), S) :-
    maplist([Item, Quoted]>>format(atom(Quoted), "\"~w\"", [Item]), List, QList),
    atomic_list_concat(QList, ', ', Items),
    format(atom(S), "memberchk(~w, [~w])", [X, Items]).

%% --- Format string slots ---
logic_slot(python, format_str(Fmt, Args), S) :-
    python_fstring(Fmt, Args, S).
logic_slot(rust, format_str(Fmt, Args), S) :-
    format_args_list(Args, rust, ArgStr),
    format(atom(S), "format!(\"~w\", ~w)", [Fmt, ArgStr]).

%% --- Method call slots ---
logic_slot(python, call_method(Method, Args), S) :-
    format_args_list(Args, python, ArgStr),
    format(atom(S), "cls._~w(~w)", [Method, ArgStr]).
logic_slot(rust, call_method(Method, Args), S) :-
    format_args_list(Args, rust, ArgStr),
    format(atom(S), "Self::~w(~w)", [Method, ArgStr]).

logic_slot(python, canonical_json(X), S) :-
    format(atom(S), "_json.dumps(~w, sort_keys=True, default=str)", [X]).
logic_slot(rust, canonical_json(X), S) :-
    format(atom(S), "serde_json::to_string(~w).unwrap_or_default()", [X]).

%% --- Method call on self (getter-style) ---
logic_slot(python, self_method(M), S) :- format(atom(S), "self.~w()", [M]).
logic_slot(rust, self_method(M), S) :- format(atom(S), "self.~w()", [M]).

%% --- Empty check ---
logic_slot(python, is_empty_check(X), S) :-
    expand_expr(python, X, XS),
    format(atom(S), "len(~w) == 0", [XS]).
logic_slot(rust, is_empty_check(X), S) :-
    expand_expr(rust, X, XS),
    format(atom(S), "~w.is_empty()", [XS]).

%% --- Streaming summary format (handles ~ prefix for "approx") ---
logic_slot(python, streaming_summary(Tokens, Chars), S) :-
    expand_expr(python, Tokens, TS),
    expand_expr(python, Chars, CS),
    format(atom(S), "f\"~~{~w} tokens, {~w} chars\"", [TS, CS]).
logic_slot(rust, streaming_summary(Tokens, Chars), S) :-
    expand_expr(rust, Tokens, TS),
    expand_expr(rust, Chars, CS),
    format(atom(S), "format!(\"~~{} tokens, {} chars\", ~w, ~w)", [TS, CS]).

%% =============================================================================
%% Elixir Logic Slots
%% =============================================================================
%%
%% Elixir design: modules with structs (not GenServer). State is passed as
%% first argument and returned (immutable updates via %{state | field: val}).
%% container('CostTracker') → AgentLoop.CostTracker module with %__MODULE__{} struct
%% container(none) → module-level function
%% private → defp instead of def
%% mutable → function returns updated state struct
%% associated → module function, no state parameter

%% --- Core slots ---
logic_slot(elixir, guard_leq_zero(X), S) :- expand_expr(elixir, X, XS), format(atom(S), "~w <= 0", [XS]).
logic_slot(elixir, guard_leq(A, B), S) :-
    expand_expr(elixir, A, AS), expand_expr(elixir, B, BS),
    format(atom(S), "~w <= ~w", [AS, BS]).
logic_slot(elixir, return_val(false), "false").
logic_slot(elixir, return_val(true), "true").
logic_slot(elixir, return_val(Expr), S) :-
    Expr \= true, Expr \= false,
    expand_expr(elixir, Expr, ExprStr),
    format(atom(S), "~w", [ExprStr]).

%% self_field: in Elixir, struct fields accessed via state.field
logic_slot(elixir, self_field(F), S) :- format(atom(S), "state.~w", [F]).
logic_slot(elixir, self_direct(F), S) :- format(atom(S), "state.~w", [F]).
logic_slot(elixir, self_method(M), S) :- format(atom(S), "~w(state)", [M]).

%% --- Print/IO slots ---
logic_slot(elixir, print_flush(X), S) :-
    format(atom(S), "IO.write(~w)", [X]).

%% --- String/collection slots ---
logic_slot(elixir, str_len(X), S) :- format(atom(S), "String.length(~w)", [X]).

logic_slot(elixir, contains(Collection, Item), S) :-
    expand_expr(elixir, Collection, CS),
    expand_expr(elixir, Item, IS),
    format(atom(S), "MapSet.member?(~w, ~w)", [CS, IS]).

logic_slot(elixir, not_empty(X), S) :-
    expand_expr(elixir, X, XS), format(atom(S), "~w != []", [XS]).

%% --- Assignment/mutation slots (Elixir: immutable updates) ---
logic_slot(elixir, self_inc(Field, Expr), S) :-
    expand_expr(elixir, Expr, ES),
    format(atom(S), "%{state | ~w: state.~w + ~w}", [Field, Field, ES]).
logic_slot(elixir, self_assign(Field, Expr), S) :-
    expand_expr(elixir, Expr, ES),
    format(atom(S), "%{state | ~w: ~w}", [Field, ES]).
logic_slot(elixir, assign(Var, Expr), S) :-
    expand_expr(elixir, Expr, ES),
    format(atom(S), "~w = ~w", [Var, ES]).

%% --- Map/collection mutation slots (Elixir: immutable struct updates) ---
logic_slot(elixir, self_map_put(Field, Key, Value), S) :-
    expand_expr(elixir, Key, KS),
    expand_expr(elixir, Value, VS),
    format(atom(S), "%{state | ~w: Map.put(state.~w, ~w, ~w)}", [Field, Field, KS, VS]).

logic_slot(elixir, self_list_append(Field, Item), S) :-
    expand_expr(elixir, Item, IS),
    format(atom(S), "%{state | ~w: state.~w ++ [~w]}", [Field, Field, IS]).

%% --- Map keys / remove slots ---
logic_slot(elixir, map_keys(Expr), S) :-
    expand_expr(elixir, Expr, ES),
    format(atom(S), "Map.keys(~w)", [ES]).
logic_slot(elixir, self_map_remove(Field, Key), S) :-
    expand_expr(elixir, Key, KS),
    format(atom(S), "%{state | ~w: Map.delete(state.~w, ~w)}", [Field, Field, KS]).
%% --- String split / filter ---
logic_slot(elixir, str_split(X), S) :-
    format(atom(S), "String.split(~w)", [X]).
logic_slot(elixir, filter_endswith(List, Suffix), S) :-
    format(atom(S), 'Enum.filter(~w, &String.ends_with?(&1, "~w"))', [List, Suffix]).

%% --- Set membership ---
logic_slot(elixir, matches_set(X, List), S) :-
    atomic_list_concat(List, ', ', Items),
    format(atom(S), "~w in [~w]", [X, Items]).

%% --- Format string slots ---
logic_slot(elixir, format_str(Fmt, Args), S) :-
    elixir_interpolation(Fmt, Args, S).
logic_slot(elixir, canonical_json(X), S) :-
    format(atom(S), "Jason.encode!(~w)", [X]).

%% --- Method call slots ---
logic_slot(elixir, call_method(Method, Args), S) :-
    format_args_list(Args, elixir, ArgStr),
    format(atom(S), "~w(~w)", [Method, ArgStr]).

%% --- Empty check ---
logic_slot(elixir, is_empty_check(X), S) :-
    expand_expr(elixir, X, XS),
    format(atom(S), "Enum.empty?(~w)", [XS]).

%% --- Streaming summary ---
logic_slot(elixir, streaming_summary(Tokens, Chars), S) :-
    expand_expr(elixir, Tokens, TS),
    expand_expr(elixir, Chars, CS),
    format(atom(S), "\"#{~w} tokens, #{~w} chars\"", [TS, CS]).

%% =============================================================================
%% Prolog Logic Slots
%% =============================================================================
%%
%% Prolog design: state is a SWI-Prolog dict (state{field: value, ...}).
%% Results are returned via unification with a Result variable.
%% Mutation creates a new dict via put_dict/4.
%% container('CostTracker') → predicate with State dict as first arg
%% container(none) → standalone predicate

%% --- Print/IO slots ---
logic_slot(prolog, print_flush(X), S) :-
    format(atom(S), "write(~w), flush_output", [X]).

%% --- String/collection slots ---
logic_slot(prolog, str_len(X), S) :- format(atom(S), "atom_length(~w, Len)", [X]).

logic_slot(prolog, contains(Collection, Item), S) :-
    expand_expr(prolog, Collection, CS),
    expand_expr(prolog, Item, IS),
    format(atom(S), "memberchk(~w, ~w)", [IS, CS]).

logic_slot(prolog, not_empty(X), S) :-
    expand_expr(prolog, X, XS), format(atom(S), "~w \\= []", [XS]).

%% Direct struct field access via dict dot notation
logic_slot(prolog, self_direct(F), S) :- format(atom(S), "State.~w", [F]).

%% --- Assignment/mutation slots (Prolog: put_dict) ---
logic_slot(prolog, self_inc(Field, Expr), S) :-
    expand_expr(prolog, Expr, ES),
    format(atom(S), "NewVal is State.~w + ~w, put_dict(~w, State, NewVal, State1)", [Field, ES, Field]).
logic_slot(prolog, self_assign(Field, Expr), S) :-
    expand_expr(prolog, Expr, ES),
    format(atom(S), "put_dict(~w, State, ~w, State1)", [Field, ES]).
logic_slot(prolog, assign(Var, Expr), S) :-
    expand_expr(prolog, Expr, ES),
    %% Capitalize variable name for Prolog
    atom_string(Var, VarStr),
    string_chars(VarStr, [H|T]),
    upcase_atom(H, UH),
    atom_chars(CapVar, [UH|T]),
    format(atom(S), "~w = ~w", [CapVar, ES]).

%% --- Map/collection mutation slots ---
logic_slot(prolog, self_map_put(Field, Key, Value), S) :-
    expand_expr(prolog, Key, KS),
    expand_expr(prolog, Value, VS),
    format(atom(S), "put_dict(~w, State.~w, ~w, NewMap), put_dict(~w, State, NewMap, State1)", [KS, Field, VS, Field]).

logic_slot(prolog, self_list_append(Field, Item), S) :-
    expand_expr(prolog, Item, IS),
    format(atom(S), "append(State.~w, [~w], NewList), put_dict(~w, State, NewList, State1)", [Field, IS, Field]).

%% --- Map keys / remove slots ---
logic_slot(prolog, map_keys(Expr), S) :-
    expand_expr(prolog, Expr, ES),
    format(atom(S), "dict_keys(~w, Keys)", [ES]).
logic_slot(prolog, self_map_remove(Field, Key), S) :-
    expand_expr(prolog, Key, KS),
    format(atom(S), "del_dict(~w, State.~w, _, NewMap), put_dict(~w, State, NewMap, State1)", [KS, Field, Field]).
%% --- String split / filter ---
logic_slot(prolog, str_split(X), S) :-
    format(atom(S), "split_string(~w, \" \", \"\", Words)", [X]).
logic_slot(prolog, filter_endswith(List, Suffix), S) :-
    format(atom(S), 'include([F]>>(sub_atom(F, _, _, 0, "~w")), ~w, Filtered)', [Suffix, List]).

%% --- Set membership ---
logic_slot(prolog, matches_set(X, List), S) :-
    atomic_list_concat(List, ', ', Items),
    format(atom(S), "memberchk(~w, [~w])", [X, Items]).

%% --- Format string slots ---
logic_slot(prolog, format_str(Fmt, Args), S) :-
    format_args_list(Args, prolog, ArgStr),
    %% Convert {} placeholders to ~w for Prolog format/3
    atomic_list_concat(Parts, '{}', Fmt),
    atomic_list_concat(Parts, '~w', PlFmt),
    format(atom(S), "format(atom(Formatted), \"~w\", [~w])", [PlFmt, ArgStr]).
logic_slot(prolog, canonical_json(X), S) :-
    format(atom(S), "atom_json_term(~w, JsonStr, [])", [X]).

%% --- Method call slots ---
logic_slot(prolog, call_method(Method, Args), S) :-
    format_args_list(Args, prolog, ArgStr),
    format(atom(S), "~w(~w, Result)", [Method, ArgStr]).

logic_slot(prolog, self_method(M), S) :- format(atom(S), "~w(State, Result)", [M]).

%% --- Empty check ---
logic_slot(prolog, is_empty_check(X), S) :-
    expand_expr(prolog, X, XS),
    format(atom(S), "~w == []", [XS]).

%% --- Streaming summary ---
logic_slot(prolog, streaming_summary(Tokens, Chars), S) :-
    expand_expr(prolog, Tokens, TS),
    expand_expr(prolog, Chars, CS),
    atomic_list_concat(['format(atom(Summary), "~w tokens, ~w chars", [', TS, ', ', CS, '])'], S).

%% =============================================================================
%% Prolog expand_expr/3
%% =============================================================================

expand_expr(prolog, self_total_cost >= budget, "State.total_cost >= Budget").
expand_expr(prolog, max_zero(Expr), S) :-
    expand_expr(prolog, Expr, Inner),
    format(atom(S), "max(0.0, ~w)", [Inner]).
expand_expr(prolog, budget - self_total_cost, "Budget - State.total_cost").
expand_expr(prolog, len_of(Expr), S) :-
    expand_expr(prolog, Expr, Inner),
    format(atom(S), "length(~w, Result)", [Inner]).
expand_expr(prolog, int_div(A, B), S) :-
    expand_expr(prolog, A, AStr),
    expand_expr(prolog, B, BStr),
    format(atom(S), "(~w // ~w)", [AStr, BStr]).
expand_expr(prolog, max_one(Expr), S) :-
    expand_expr(prolog, Expr, Inner),
    format(atom(S), "max(1, ~w)", [Inner]).
expand_expr(prolog, min_val(A, B), S) :-
    expand_expr(prolog, A, AStr),
    expand_expr(prolog, B, BStr),
    format(atom(S), "min(~w, ~w)", [AStr, BStr]).
expand_expr(prolog, mul(A, B), S) :-
    expand_expr(prolog, A, AStr),
    expand_expr(prolog, B, BStr),
    format(atom(S), "(~w * ~w)", [AStr, BStr]).
expand_expr(prolog, pow(Base, Exp), S) :-
    expand_expr(prolog, Base, BStr),
    expand_expr(prolog, Exp, EStr),
    format(atom(S), "(~w ** ~w)", [BStr, EStr]).
expand_expr(prolog, sub(A, B), S) :-
    expand_expr(prolog, A, AStr),
    expand_expr(prolog, B, BStr),
    format(atom(S), "(~w - ~w)", [AStr, BStr]).
expand_expr(prolog, as_float(X), S) :-
    expand_expr(prolog, X, Inner),
    format(atom(S), "float(~w)", [Inner]).
expand_expr(prolog, div_float(A, B), S) :-
    expand_expr(prolog, A, AStr),
    expand_expr(prolog, B, BStr),
    format(atom(S), "(~w / ~w)", [AStr, BStr]).

%% --- Map access ---
expand_expr(prolog, map_get(Collection, Key), S) :-
    expand_expr(prolog, Collection, CS),
    expand_expr(prolog, Key, KS),
    format(atom(S), "get_dict(~w, ~w, Val)", [KS, CS]).

%% --- Map get with default ---
expand_expr(prolog, map_get_default(Coll, Key, Default), S) :-
    expand_expr(prolog, Coll, CS), expand_expr(prolog, Key, KS),
    expand_expr(prolog, Default, DS),
    format(atom(S), "(get_dict(~w, ~w, Val) -> Val ; ~w)", [KS, CS, DS]).

%% --- Map has_key ---
expand_expr(prolog, map_has_key(Collection, Key), S) :-
    expand_expr(prolog, Collection, CS),
    expand_expr(prolog, Key, KS),
    format(atom(S), "get_dict(~w, ~w, _)", [KS, CS]).

%% --- Modulo ---
expand_expr(prolog, modulo(A, B), S) :-
    expand_expr(prolog, A, AS), expand_expr(prolog, B, BS),
    format(atom(S), "(~w mod ~w)", [AS, BS]).

%% --- HTML escape ---
expand_expr(prolog, html_escape(X), S) :-
    expand_expr(prolog, X, XS),
    format(atom(S), 'html_escape(~w, Escaped)', [XS]).

%% --- String truncation with ellipsis ---
expand_expr(prolog, str_slice_ellipsis(X, N), S) :-
    expand_expr(prolog, X, XS), expand_expr(prolog, N, NS),
    format(atom(S), 'sub_atom(~w, 0, ~w, _, Prefix), atom_concat(Prefix, "...", Truncated)', [XS, NS]).

%% --- List last element ---
expand_expr(prolog, list_last(Expr), S) :-
    expand_expr(prolog, Expr, Inner),
    format(atom(S), "last(~w, Last)", [Inner]).

%% --- String split / filter / map_keys ---
expand_expr(prolog, str_split(X), S) :-
    expand_expr(prolog, X, XS),
    format(atom(S), 'split_string(~w, " ", "", Words)', [XS]).
expand_expr(prolog, filter_endswith(List, Suffix), S) :-
    expand_expr(prolog, List, LS),
    format(atom(S), 'include([F]>>(sub_atom(F, _, _, 0, "~w")), ~w, Filtered)', [Suffix, LS]).
expand_expr(prolog, map_keys(Expr), S) :-
    expand_expr(prolog, Expr, ES),
    format(atom(S), "dict_keys(~w, Keys)", [ES]).

%% --- Addition ---
expand_expr(prolog, add(A, B), S) :-
    expand_expr(prolog, A, AS),
    expand_expr(prolog, B, BS),
    format(atom(S), "(~w + ~w)", [AS, BS]).

%% =============================================================================
%% Coverage-gap slots: not, gt, str_starts_with, str_ends_with, all_keys_present,
%%   literal_list, json_encode, json_decode, file_read, file_write
%% =============================================================================

%% --- Boolean negation ---
logic_slot(python, not_expr(Expr), S) :-
    logic_slot(python, Expr, Inner), format(atom(S), "not ~w", [Inner]).
logic_slot(rust, not_expr(Expr), S) :-
    logic_slot(rust, Expr, Inner), format(atom(S), "!(~w)", [Inner]).
logic_slot(elixir, not_expr(Expr), S) :-
    logic_slot(elixir, Expr, Inner), format(atom(S), "not ~w", [Inner]).
logic_slot(prolog, not_expr(Expr), S) :-
    logic_slot(prolog, Expr, Inner), format(atom(S), "\\+ ~w", [Inner]).

expand_expr(python, not_expr(Expr), S) :-
    expand_expr(python, Expr, Inner), format(atom(S), "not ~w", [Inner]).
expand_expr(rust, not_expr(Expr), S) :-
    expand_expr(rust, Expr, Inner), format(atom(S), "!(~w)", [Inner]).
expand_expr(elixir, not_expr(Expr), S) :-
    expand_expr(elixir, Expr, Inner), format(atom(S), "not ~w", [Inner]).
expand_expr(prolog, not_expr(Expr), S) :-
    expand_expr(prolog, Expr, Inner), format(atom(S), "\\+ ~w", [Inner]).

%% --- Boolean combinators ---
expand_expr(python, or_expr(A, B), S) :-
    expand_expr(python, A, AS), expand_expr(python, B, BS),
    format(atom(S), "(~w or ~w)", [AS, BS]).
expand_expr(rust, or_expr(A, B), S) :-
    expand_expr(rust, A, AS), expand_expr(rust, B, BS),
    format(atom(S), "(~w || ~w)", [AS, BS]).
expand_expr(elixir, or_expr(A, B), S) :-
    expand_expr(elixir, A, AS), expand_expr(elixir, B, BS),
    format(atom(S), "(~w or ~w)", [AS, BS]).
expand_expr(prolog, or_expr(A, B), S) :-
    expand_expr(prolog, A, AS), expand_expr(prolog, B, BS),
    format(atom(S), "(~w ; ~w)", [AS, BS]).

expand_expr(python, and_expr(A, B), S) :-
    expand_expr(python, A, AS), expand_expr(python, B, BS),
    format(atom(S), "(~w and ~w)", [AS, BS]).
expand_expr(rust, and_expr(A, B), S) :-
    expand_expr(rust, A, AS), expand_expr(rust, B, BS),
    format(atom(S), "(~w && ~w)", [AS, BS]).
expand_expr(elixir, and_expr(A, B), S) :-
    expand_expr(elixir, A, AS), expand_expr(elixir, B, BS),
    format(atom(S), "(~w and ~w)", [AS, BS]).
expand_expr(prolog, and_expr(A, B), S) :-
    expand_expr(prolog, A, AS), expand_expr(prolog, B, BS),
    format(atom(S), "(~w , ~w)", [AS, BS]).

%% --- String strip (trim whitespace) ---
expand_expr(python, str_strip(Expr), S) :-
    expand_expr(python, Expr, Inner), format(atom(S), "~w.strip()", [Inner]).
expand_expr(rust, str_strip(Expr), S) :-
    expand_expr(rust, Expr, Inner), format(atom(S), "~w.trim()", [Inner]).
expand_expr(elixir, str_strip(Expr), S) :-
    expand_expr(elixir, Expr, Inner), format(atom(S), "String.trim(~w)", [Inner]).
expand_expr(prolog, str_strip(Expr), S) :-
    expand_expr(prolog, Expr, Inner), format(atom(S), "normalize_space(atom(Result), ~w)", [Inner]).

%% --- Greater-than comparison ---
expand_expr(python, gt(A, B), S) :-
