resolve_type(prolog, int, "integer").
resolve_type(prolog, float, "float").
resolve_type(prolog, string, "atom").
resolve_type(prolog, bool, "boolean").
resolve_type(prolog, void, "true").
resolve_type(prolog, usize, "nonneg").
resolve_type(prolog, dict, "dict").
resolve_type(prolog, set_of_string, "list").
resolve_type(prolog, owned_string, "atom").
resolve_type(prolog, list_of_dict, "list").
resolve_type(prolog, list_of_string, "list").
resolve_type(prolog, list, "list").
resolve_type(prolog, optional(T), S) :-
    resolve_type(prolog, T, Inner),
    format(atom(S), "~w_or_none", [Inner]).
resolve_type(prolog, ref(T), S) :-
    resolve_type(prolog, T, S).

%% =============================================================================
%% Clojure target — resolve_type, expand_expr, logic_slot, emit_shared_method
%% =============================================================================

%% --- Clojure helper: snake_case to kebab-case ---
clojure_kebab(Atom, Kebab) :-
    atom_string(Atom, Str),
    split_string(Str, "_", "", Parts),
    atomics_to_text(Parts, "-", Kebab).

%% --- Clojure format args as space-separated kebab-case ---
clojure_format_args([], "").
clojure_format_args(Args, Result) :-
    Args \= [],
    maplist([A, KA]>>(clojure_kebab(A, KA)), Args, KArgs),
    atomics_to_text(KArgs, " ", Result).

%% --- resolve_type/3 for Clojure ---
resolve_type(clojure, int, "long").
resolve_type(clojure, float, "double").
resolve_type(clojure, string, "String").
resolve_type(clojure, bool, "Boolean").
resolve_type(clojure, void, "nil").
resolve_type(clojure, usize, "long").
resolve_type(clojure, dict, "IPersistentMap").
resolve_type(clojure, set_of_string, "#{String}").
resolve_type(clojure, owned_string, "String").
resolve_type(clojure, list_of_dict, "[IPersistentMap]").
resolve_type(clojure, list_of_string, "[String]").
resolve_type(clojure, list, "coll").
resolve_type(clojure, optional(T), S) :-
    resolve_type(clojure, T, Inner),
    format(atom(S), "(or ~w nil)", [Inner]).
resolve_type(clojure, ref(T), S) :-
    resolve_type(clojure, T, S).

%% --- logic_slot/3 for Clojure ---

logic_slot(clojure, guard_leq_zero(X), S) :- expand_expr(clojure, X, XS), format(atom(S), "(<= ~w 0)", [XS]).
logic_slot(clojure, guard_leq(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
    format(atom(S), "(<= ~w ~w)", [AS, BS]).
logic_slot(clojure, return_val(false), "false").
logic_slot(clojure, return_val(true), "true").
logic_slot(clojure, return_val(Expr), S) :-
    Expr \= true, Expr \= false,
    expand_expr(clojure, Expr, ExprStr),
    S = ExprStr.
logic_slot(clojure, self_field(F), S) :-
    clojure_kebab(F, KF), format(atom(S), "(:~w state)", [KF]).
logic_slot(clojure, self_direct(F), S) :-
    clojure_kebab(F, KF), format(atom(S), "(:~w state)", [KF]).
logic_slot(clojure, self_method(M), S) :-
    clojure_kebab(M, KM), format(atom(S), "(~w state)", [KM]).
logic_slot(clojure, print_flush(X), S) :-
    format(atom(S), "(print ~w) (flush)", [X]).
logic_slot(clojure, str_len(X), S) :-
    clojure_kebab(X, KX), format(atom(S), "(count ~w)", [KX]).
logic_slot(clojure, contains(Collection, Item), S) :-
    expand_expr(clojure, Collection, CS),
    expand_expr(clojure, Item, IS),
    format(atom(S), "(contains? ~w ~w)", [CS, IS]).
logic_slot(clojure, not_empty(X), S) :-
    expand_expr(clojure, X, XS), format(atom(S), "(seq ~w)", [XS]).
logic_slot(clojure, self_inc(Field, Expr), S) :-
    clojure_kebab(Field, KF),
    expand_expr(clojure, Expr, ES),
    format(atom(S), "(update state :~w + ~w)", [KF, ES]).
logic_slot(clojure, self_assign(Field, Expr), S) :-
    clojure_kebab(Field, KF),
    expand_expr(clojure, Expr, ES),
    format(atom(S), "(assoc state :~w ~w)", [KF, ES]).
logic_slot(clojure, assign(Var, Expr), S) :-
    clojure_kebab(Var, KV),
    expand_expr(clojure, Expr, ES),
    format(atom(S), "(let [~w ~w]", [KV, ES]).
logic_slot(clojure, self_map_put(Field, Key, Value), S) :-
    clojure_kebab(Field, KF),
    expand_expr(clojure, Key, KS),
    expand_expr(clojure, Value, VS),
    format(atom(S), "(update state :~w assoc ~w ~w)", [KF, KS, VS]).
logic_slot(clojure, self_list_append(Field, Item), S) :-
    clojure_kebab(Field, KF),
    expand_expr(clojure, Item, IS),
    format(atom(S), "(update state :~w conj ~w)", [KF, IS]).

%% --- Map keys / remove slots ---
logic_slot(clojure, map_keys(Expr), S) :-
    expand_expr(clojure, Expr, ES),
    format(atom(S), "(keys ~w)", [ES]).
logic_slot(clojure, self_map_remove(Field, Key), S) :-
    clojure_kebab(Field, KF),
    expand_expr(clojure, Key, KS),
    format(atom(S), "(update state :~w dissoc ~w)", [KF, KS]).
%% --- String split / filter ---
logic_slot(clojure, str_split(X), S) :-
    clojure_kebab(X, KX),
    format(atom(S), "(clojure.string/split ~w #\"\\s+\")", [KX]).
logic_slot(clojure, filter_endswith(List, Suffix), S) :-
    clojure_kebab(List, KL),
    format(atom(S), '(filter #(.endsWith % "~w") ~w)', [Suffix, KL]).

logic_slot(clojure, matches_set(X, List), S) :-
    atomic_list_concat(List, ' ', ListStr),
    expand_expr(clojure, X, XS),
    format(atom(S), "(#{~w} ~w)", [ListStr, XS]).
logic_slot(clojure, matches_str_set(X, List), S) :-
    maplist([Item, QI]>>(format(atom(QI), '"~w"', [Item])), List, QList),
    atomic_list_concat(QList, ' ', ListStr),
    expand_expr(clojure, X, XS),
    format(atom(S), "(#{~w} ~w)", [ListStr, XS]).
logic_slot(clojure, format_str(Fmt, Args), S) :-
    format_args_list(Args, clojure, ArgStr),
    %% Convert {} placeholders to %s for Clojure (Java) format
    atomic_list_concat(Parts, '{}', Fmt),
    atomic_list_concat(Parts, '%s', CljFmt),
    format(atom(S), '(format "~w" ~w)', [CljFmt, ArgStr]).
logic_slot(clojure, canonical_json(X), S) :-
    format(atom(S), "(cheshire.core/generate-string ~w {:key-fn name})", [X]).
logic_slot(clojure, call_method(Method, Args), S) :-
    format_args_list(Args, clojure, ArgStr),
    clojure_kebab(Method, KM),
    format(atom(S), "(~w ~w)", [KM, ArgStr]).
logic_slot(clojure, is_empty_check(X), S) :-
    expand_expr(clojure, X, XS),
    format(atom(S), "(empty? ~w)", [XS]).
logic_slot(clojure, streaming_summary(Tokens, Chars), S) :-
    expand_expr(clojure, Tokens, TS),
    expand_expr(clojure, Chars, CS),
    atomic_list_concat(['(format "%s tokens, %s chars" ', TS, ' ', CS, ')'], S).
logic_slot(clojure, not_expr(Expr), S) :-
    logic_slot(clojure, Expr, Inner), format(atom(S), "(not ~w)", [Inner]).
logic_slot(clojure, str_starts_with(Str, Prefix), S) :-
    clojure_kebab(Str, KS), format(atom(S), '(.startsWith ~w "~w")', [KS, Prefix]).
logic_slot(clojure, str_ends_with(Str, Suffix), S) :-
    clojure_kebab(Str, KS), format(atom(S), '(.endsWith ~w "~w")', [KS, Suffix]).
logic_slot(clojure, all_keys_present(Dict, Keys), S) :-
    expand_expr(clojure, Dict, DS), expand_expr(clojure, Keys, KS),
    format(atom(S), "(every? #(contains? ~w %) ~w)", [DS, KS]).
logic_slot(clojure, json_encode(X), S) :-
    format(atom(S), "(cheshire.core/generate-string ~w {:pretty true})", [X]).
logic_slot(clojure, json_decode(X), S) :-
    format(atom(S), "(cheshire.core/parse-string ~w true)", [X]).
logic_slot(clojure, file_write(Path, Content), S) :-
    format(atom(S), "(spit ~w ~w)", [Path, Content]).
logic_slot(clojure, file_read(Path), S) :-
    format(atom(S), "(slurp ~w)", [Path]).

%% --- expand_expr/3 for Clojure (prefix notation) ---

expand_expr(clojure, self_total_cost >= budget, "(>= (:total-cost state) budget)").
expand_expr(clojure, budget - self_total_cost, "(- budget (:total-cost state))").
expand_expr(clojure, none_val, "nil").

expand_expr(clojure, max_zero(Expr), S) :-
    expand_expr(clojure, Expr, Inner),
    format(atom(S), "(max 0.0 ~w)", [Inner]).
expand_expr(clojure, max_one(Expr), S) :-
    expand_expr(clojure, Expr, Inner),
    format(atom(S), "(max 1 ~w)", [Inner]).
expand_expr(clojure, len_of(Expr), S) :-
    expand_expr(clojure, Expr, Inner),
    format(atom(S), "(count ~w)", [Inner]).
expand_expr(clojure, int_div(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
    format(atom(S), "(quot ~w ~w)", [AS, BS]).
expand_expr(clojure, min_val(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
    format(atom(S), "(min ~w ~w)", [AS, BS]).
expand_expr(clojure, add(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
    format(atom(S), "(+ ~w ~w)", [AS, BS]).
expand_expr(clojure, sub(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
    format(atom(S), "(- ~w ~w)", [AS, BS]).
expand_expr(clojure, mul(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
    format(atom(S), "(* ~w ~w)", [AS, BS]).
expand_expr(clojure, div_float(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
    format(atom(S), "(/ ~w ~w)", [AS, BS]).
expand_expr(clojure, pow(Base, Exp), S) :-
    expand_expr(clojure, Base, BS), expand_expr(clojure, Exp, ES),
    format(atom(S), "(Math/pow ~w ~w)", [BS, ES]).
expand_expr(clojure, as_float(X), S) :-
    expand_expr(clojure, X, Inner),
    format(atom(S), "(double ~w)", [Inner]).
expand_expr(clojure, gt(A, B), S) :-
    expand_expr(clojure, A, AS), expand_expr(clojure, B, BS),
