expand_expr(clojure, all_keys_present(Dict, Keys), S) :-
    expand_expr(clojure, Dict, DS), expand_expr(clojure, Keys, KS),
    format(atom(S), "(every? #(contains? ~w %) ~w)", [DS, KS]).
expand_expr(clojure, literal_list(Items), S) :-
    format_literal_list(clojure, Items, Inner),
    format(atom(S), "[~w]", [Inner]).
format_literal_item(clojure, X, S) :- format(atom(S), '"~w"', [X]).

%% --- Clojure fixup: convert if/return to (if ...) ---
clojure_fixup_body(In, Out) :-
    split_string(In, "\n", "", Lines),
    clojure_fixup_lines(Lines, FixedLines),
    atomics_to_text(FixedLines, "\n", Out).

clojure_fixup_lines([], []).
%% Merge consecutive (let [var val] lines into a single (let [v1 e1 v2 e2]
clojure_fixup_lines([Line|Rest], Result) :-
    is_let_binding_line(Line, Binding),
    !,
    collect_let_lines(Rest, MoreBindings, BodyLines),
    append([Binding], MoreBindings, AllBindings),
    atomic_list_concat(AllBindings, ' ', BindStr),
    format(atom(LetOpen), "(let [~w]", [BindStr]),
    clojure_fixup_lines(BodyLines, FixedBody),
    %% Add closing paren to last body line
    (FixedBody = [] ->
        Result = [LetOpen, ")"]
    ;
        append(BodyInit, [LastBody], FixedBody),
        format(atom(LastClosed), "~w)", [LastBody]),
        append([LetOpen|BodyInit], [LastClosed], Result)
    ).
%% Thread consecutive state-mutating lines: (assoc state ...), (update state ...) → (-> state ...)
clojure_fixup_lines([Line|Rest], Result) :-
    is_state_mutating_line(Line),
    Rest = [Next|_],
    is_state_mutating_line(Next),
    !,
    collect_state_mutating([Line|Rest], MutLines, Remaining),
    maplist(strip_state_prefix, MutLines, InnerOps),
    atomic_list_concat(['(-> state'|InnerOps], '\n    ', ThreadHead),
    atom_concat(ThreadHead, ')', Threaded),
    clojure_fixup_lines(Remaining, RestFixed),
    Result = [Threaded|RestFixed].
%% Single (assoc state :f1 v1) followed by non-mutating — keep as-is
clojure_fixup_lines([Line|Rest], Result) :-
    is_assoc_state_line(Line, Pairs),
    Rest = [Next|_],
    \+ is_state_mutating_line(Next),
    !,
    %% Check for consecutive assoc-only (merge pairs)
    collect_assoc_lines(Rest, MorePairs, Remaining),
    append(Pairs, MorePairs, AllPairs),
    atomic_list_concat(AllPairs, ' ', PairsStr),
    format(atom(Merged), "(assoc state ~w)", [PairsStr]),
    clojure_fixup_lines(Remaining, RestFixed),
    Result = [Merged|RestFixed].
%% State-mutating line followed by bare true/false — drop the literal (state is the return)
clojure_fixup_lines([Line|Rest], Result) :-
    is_state_mutating_line(Line),
    Rest = [Next|After],
    is_bare_literal(Next),
    !,
    clojure_fixup_lines([Line|After], Result).
%% State-mutating line followed by (:field state) — let-bind and access from new state
clojure_fixup_lines([Line|Rest], Result) :-
    is_state_mutating_line(Line),
    Rest = [Next|After],
    is_state_field_access(Next),
    !,
    atom_string(Next, NextStr),
    split_string(NextStr, "", "", _),  % ensure it's a valid string
    %% Replace " state)" with " new-state)" in the field access
    atomic_list_concat(Parts, ' state)', Next),
    atomic_list_concat(Parts, ' new-state)', FixedAccess),
    format(atom(LetExpr), "(let [new-state ~w]\n  ~w)", [Line, FixedAccess]),
    clojure_fixup_lines(After, RestFixed),
    Result = [LetExpr|RestFixed].
clojure_fixup_lines([Line|Rest], Result) :-
    (  is_if_line(Line, Cond)
    ->
       collect_indented(Rest, ThenLines, AfterThen),
       (ThenLines = [] ->
           clojure_fixup_lines(Rest, RestFixed),
           Result = [Line|RestFixed]
       ;
           maplist(strip_indent, ThenLines, StrippedThen),
           clojure_fixup_lines(StrippedThen, FixedThen),
           format(atom(IfOpen), "(if ~w", [Cond]),
           indent_lines(FixedThen, IndentedThen),
           (AfterThen = [] ->
               append([IfOpen|IndentedThen], [")"], Result)
           ;
               clojure_fixup_lines(AfterThen, FixedElse),
               indent_lines(FixedElse, IndentedElse),
               append([IfOpen|IndentedThen], IndentedElse, Mid),
               append(Mid, [")"], Result)
           )
       )
    ;
       clojure_fixup_lines(Rest, RestFixed),
       Result = [Line|RestFixed]
    ).

%% Helper: detect (let [var val] and extract binding string
is_let_binding_line(Line, Binding) :-
    atom_string(Line, S),
    string_concat("(let [", Rest, S),
    string_concat(Binding0, "]", Rest),
    atom_string(Binding, Binding0).

collect_let_lines([], [], []).
collect_let_lines([Line|Rest], Bindings, Body) :-
    (is_let_binding_line(Line, B) ->
        collect_let_lines(Rest, MoreB, Body),
        Bindings = [B|MoreB]
    ;
        Bindings = [], Body = [Line|Rest]
    ).

%% Helper: detect (:field state) access pattern
is_state_field_access(Line) :-
    atom_string(Line, S),
    sub_string(S, 0, _, _, "(:"),
    sub_string(S, _, _, 0, " state)").

%% Helper: detect bare literal lines (true, false, nil)
is_bare_literal(Line) :-
    atom_string(Line, S),
    string_to_atom(S, A),
    memberchk(A, [true, false, nil]).

%% Helper: detect any state-mutating line (assoc state ...) or (update state ...)
is_state_mutating_line(Line) :-
    (is_assoc_state_line(Line, _) ; is_update_state_line(Line)), !.

collect_state_mutating([], [], []).
collect_state_mutating([Line|Rest], [Line|More], Remaining) :-
    is_state_mutating_line(Line),
    !,
    collect_state_mutating(Rest, More, Remaining).
collect_state_mutating(Lines, [], Lines).

%% Strip "state" from (assoc state ...) or (update state ...) for threading
strip_state_prefix(Line, Inner) :-
    atom_string(Line, S),
    (string_concat("(assoc state ", Rest, S) ->
        string_concat(Args, ")", Rest),
        format(atom(Inner), "(assoc ~w)", [Args])
    ; string_concat("(update state ", Rest, S) ->
        string_concat(Args, ")", Rest),
        format(atom(Inner), "(update ~w)", [Args])
    ;
        Inner = Line
    ).

%% Helper: detect (assoc state :key val) and extract ":key val" pairs
is_assoc_state_line(Line, [Pairs]) :-
    atom_string(Line, S),
    string_concat("(assoc state ", Rest, S),
    string_concat(PairsStr, ")", Rest),
    atom_string(Pairs, PairsStr).

collect_assoc_lines([], [], []).
collect_assoc_lines([Line|Rest], Pairs, Remaining) :-
    (is_assoc_state_line(Line, P) ->
        collect_assoc_lines(Rest, MoreP, Remaining),
        append(P, MoreP, Pairs)
    ;
        Pairs = [], Remaining = [Line|Rest]
    ).

%% Helper: detect (update state ...) lines
is_update_state_line(Line) :-
    atom_string(Line, S),
    sub_string(S, 0, _, _, "(update state ").

collect_update_lines([], [], []).
collect_update_lines([Line|Rest], [Line|More], Remaining) :-
    is_update_state_line(Line),
    !,
    collect_update_lines(Rest, More, Remaining).
collect_update_lines(Lines, [], Lines).

strip_update_state_prefix(Line, Inner) :-
    atom_string(Line, S),
    string_concat("(update state ", Rest, S),
    string_concat(Args, ")", Rest),
    format(atom(Inner), "(update ~w)", [Args]).

%% --- emit_shared_method/3 for Clojure ---
emit_shared_method(S, clojure, MethodName) :-
    shared_logic(_, MethodName, Props),
    member(signature(Name, Args, _RetType), Props),
    member(doc(Doc), Props),
    compile_logic(clojure, MethodName, Body),
    member(container(Container), Props),
    (member(mutable, Props) -> _Mutable = true ; _Mutable = false),
    %% Kebab-case function name
    clojure_kebab(Name, KName),
    %% Docstring
    format(S, '(defn ~w~n', [KName]),
    format(S, '  "~w"~n', [Doc]),
    %% Arg vector
    (Container = none ->
        clojure_format_args(Args, ArgsVec),
        format(S, '  [~w]~n', [ArgsVec])
    ;
        clojure_format_args(Args, ArgsVec),
        (ArgsVec = "" ->
            write(S, '  [state]\n')
        ;
            format(S, '  [state ~w]~n', [ArgsVec])
        )
    ),
    %% Apply field_map rewrites
    atom_string(Body, BodyStr0),
    (member(field_map(clojure, Map), Props) ->
        apply_field_map(BodyStr0, Map, BodyStr1)
    ;
        BodyStr1 = BodyStr0
    ),
    %% Apply Clojure fixup
    clojure_fixup_body(BodyStr1, BodyStr),
    %% Emit body lines
    split_string(BodyStr, "\n", "", Lines),
    forall(member(Line, Lines), (
        format(S, '  ~w~n', [Line])
    )),
    format(S, ')~n~n', []).

