expand_expr(_, N, S) :- number(N), number_codes(N, Codes), atom_codes(S, Codes).

%% Bridge: new compound expressions that are slots
expand_expr(Target, Expr, S) :-
    compound(Expr),
    logic_slot(Target, Expr, S), !.

%% =============================================================================
%% Helper predicates for format_str slot
%% =============================================================================

%% Format a list of args for a function call
format_args_list([], _, "").
format_args_list([A], Target, S) :- expand_expr(Target, A, S).
format_args_list([A|Rest], Target, S) :-
    Rest \= [],
    expand_expr(Target, A, AStr),
    format_args_list(Rest, Target, RestStr),
    (Target = clojure ->
        format(atom(S), "~w ~w", [AStr, RestStr])
    ;
        format(atom(S), "~w, ~w", [AStr, RestStr])
    ).

%% Python f-string: replace {} with {expr} for each arg
python_fstring(Fmt, Args, S) :-
    replace_placeholders(Fmt, Args, python, Filled),
    format(atom(S), "f\"~w\"", [Filled]).

elixir_interpolation(Fmt, Args, S) :-
    replace_elixir_placeholders(Fmt, Args, Filled),
    format(atom(S), "\"~w\"", [Filled]).

replace_elixir_placeholders(Fmt, [], Fmt).
replace_elixir_placeholders(Fmt, [Arg|Rest], Result) :-
    expand_expr(elixir, Arg, ArgStr),
    atom_string(Fmt, FmtStr),
    (sub_string(FmtStr, Before, 2, _, "{}") ->
        sub_string(FmtStr, 0, Before, _, Prefix),
        After is Before + 2,
        sub_string(FmtStr, After, _, 0, Suffix),
        format(atom(Mid), "~w#{~w}~w", [Prefix, ArgStr, Suffix]),
        atom_string(Mid, MidStr),
        replace_elixir_placeholders(MidStr, Rest, Result)
    ;
        Result = Fmt
    ).

replace_placeholders(Fmt, [], _, Fmt).
replace_placeholders(Fmt, [Arg|Rest], Target, Result) :-
    expand_expr(Target, Arg, ArgStr),
    atom_string(Fmt, FmtStr),
    (sub_string(FmtStr, Before, 2, _, "{}") ->
        sub_string(FmtStr, 0, Before, _, Prefix),
        After is Before + 2,
        sub_string(FmtStr, After, _, 0, Suffix),
        format(atom(Mid), "~w{~w}~w", [Prefix, ArgStr, Suffix]),
        atom_string(Mid, MidStr),
        replace_placeholders(MidStr, Rest, Target, Result)
    ;
        Result = Fmt
    ).

%% =============================================================================
%% Prolog Target — Generate a functional SWI-Prolog agent loop
%% =============================================================================

generate_prolog_modules :-
    agent_loop_components:register_agent_loop_components,
    generate_prolog_costs,
    generate_prolog_config,
    generate_prolog_tools,
    generate_prolog_commands,
    generate_prolog_security,
    generate_prolog_backends,
    generate_prolog_agent_loop,
    generate_prolog_main.

%% --- Prolog output helpers ---

write_prolog_header(S, Module, Description) :-
    format(S, '%% ~w — ~w~n', [Module, Description]),
    format(S, '%% Auto-generated by agent_loop_module.pl~n', []),
    format(S, '%% DO NOT EDIT — regenerate with:~n', []),
    format(S, '%%   swipl -g "generate_all(prolog), halt" agent_loop_module.pl~n~n', []).

%% Write a properly quoted Prolog term
write_prolog_term(S, Term) :-
    (  is_list(Term)   -> write_prolog_list(S, Term)
    ;  string(Term)    -> format(S, '~q', [Term])
    ;  atom(Term)      -> format(S, '~q', [Term])
    ;  number(Term)    -> write(S, Term)
    ;  compound(Term)  -> write_canonical(S, Term)
    ;  write(S, Term)
    ).

write_prolog_list(S, []) :- write(S, '[]').
write_prolog_list(S, List) :-
    write(S, '['),
    write_prolog_list_items(S, List),
    write(S, ']').

write_prolog_list_items(_, []).
write_prolog_list_items(S, [X]) :- write_prolog_term(S, X).
write_prolog_list_items(S, [X|Xs]) :-
    Xs \= [],
    write_prolog_term(S, X),
    write(S, ', '),
    write_prolog_list_items(S, Xs).

