    output_path(rust, '', SrcDir),
    atom_concat(SrcDir, '../Makefile', Path),
    open(Path, write, S),
    write(S, '# UnifyWeaver Agent Loop — Rust build automation\n'),
    write(S, '# Auto-generated by agent_loop_module.pl\n\n'),
    write(S, 'BINARY_NAME := uwsal\n'),
    write(S, 'INSTALL_DIR := $(HOME)/.local/bin\n\n'),
    write(S, '.PHONY: build release test check clean install uninstall dist wasm wasm-pack help\n\n'),
    write(S, 'help: ## Show this help\n'),
    write(S, '\t@grep -E ''^[a-zA-Z_-]+:.*?## .*$$'' $(MAKEFILE_LIST) | sort | awk ''BEGIN {FS = ":.*?## "}; {printf "  \\033[36m%-15s\\033[0m %s\\n", $$1, $$2}''\n\n'),
    write(S, 'build: ## Build debug binary\n'),
    write(S, '\tcargo build\n\n'),
    write(S, 'release: ## Build optimized release binary (LTO + strip)\n'),
    write(S, '\tcargo build --release\n'),
    write(S, '\t@echo "Binary: target/release/$(BINARY_NAME)"\n'),
    write(S, '\t@ls -lh target/release/$(BINARY_NAME) 2>/dev/null || true\n\n'),
    write(S, 'test: ## Run all tests\n'),
    write(S, '\tcargo test\n\n'),
    write(S, 'check: ## Type-check without building\n'),
    write(S, '\tcargo check\n\n'),
    write(S, 'clean: ## Remove build artifacts\n'),
    write(S, '\tcargo clean\n\n'),
    write(S, 'install: release ## Install binary to ~/.local/bin\n'),
    write(S, '\t@mkdir -p $(INSTALL_DIR)\n'),
    write(S, '\tcp target/release/$(BINARY_NAME) $(INSTALL_DIR)/$(BINARY_NAME)\n'),
    write(S, '\t@echo "Installed $(BINARY_NAME) to $(INSTALL_DIR)/$(BINARY_NAME)"\n'),
    write(S, '\t@echo "Make sure $(INSTALL_DIR) is in your PATH"\n\n'),
    write(S, 'uninstall: ## Remove installed binary\n'),
    write(S, '\trm -f $(INSTALL_DIR)/$(BINARY_NAME)\n'),
    write(S, '\t@echo "Removed $(INSTALL_DIR)/$(BINARY_NAME)"\n\n'),
    write(S, 'dist: release ## Create distribution archive\n'),
    write(S, '\t@mkdir -p dist\n'),
    write(S, '\tcp target/release/$(BINARY_NAME) dist/\n'),
    write(S, '\t@cd dist && tar czf $(BINARY_NAME)-$(shell uname -m)-$(shell uname -s | tr A-Z a-z).tar.gz $(BINARY_NAME)\n'),
    write(S, '\t@echo "Archive: dist/$(BINARY_NAME)-$(shell uname -m)-$(shell uname -s | tr A-Z a-z).tar.gz"\n\n'),
    write(S, 'wasm: ## Build WASM library (requires wasm32-unknown-unknown target)\n'),
    write(S, '\tcargo build --target wasm32-unknown-unknown --features wasm --release\n'),
    write(S, '\t@echo "WASM: target/wasm32-unknown-unknown/release/agent_loop.wasm"\n\n'),
    write(S, 'wasm-pack: ## Build WASM with wasm-pack for web usage\n'),
    write(S, '\twasm-pack build --target web --features wasm\n'),
    write(S, '\t@echo "WASM pack output: pkg/"\n'),
    close(S),
    format('  Generated rust/Makefile~n', []).

%% =============================================================================
%% Elixir Code Generation
%% =============================================================================

generate_all(elixir) :-
    write('Generating Elixir target...'), nl,
    output_path(elixir, '', ElixirDir),
    make_directory_path(ElixirDir),
    generate_elixir_mix_exs,
    generate_elixir_costs,
    generate_elixir_streaming,
    generate_elixir_tool_cache,
    generate_elixir_context,
    generate_elixir_mcp_client,
    generate_elixir_output_parser,
    generate_elixir_sessions,
    generate_elixir_retry,
    %% Data layer
    generate_elixir_pricing,
    generate_elixir_tools,
    generate_elixir_backends,
    %% Security & config
    generate_elixir_security,
    generate_elixir_config,
    %% GenServer wrappers
    generate_elixir_cost_server,
    generate_elixir_context_server,
    generate_elixir_cache_server,
    generate_elixir_streaming_server,
    generate_elixir_mcp_server,
    generate_elixir_mcp_manager_server,
    %% HTTP API (Plug.Router)
    generate_elixir_router,
    generate_elixir_http_server,
    %% Application + supervision
    generate_elixir_application,
    %% ExUnit tests
    generate_elixir_tests,
    write('Elixir target done.'), nl.

%% write_elixir_header(+Stream, +Module, +Description)
write_elixir_header(S, Module, Description) :-
    format(S, '# ~w — ~w~n', [Module, Description]),
    format(S, '# Auto-generated by UnifyWeaver agent_loop_module.pl~n', []),
    format(S, '# Do not edit manually.~n~n', []).

%% --- mix.exs ---
generate_elixir_mix_exs :-
    target_dir(elixir, LibDir),
    atom_concat(LibDir, '../../mix.exs', Path),
    open(Path, write, S),
    write(S, 'defmodule AgentLoop.MixProject do\n'),
    write(S, '  use Mix.Project\n\n'),
    write(S, '  def project do\n'),
    write(S, '    [\n'),
    write(S, '      app: :agent_loop,\n'),
    write(S, '      version: "0.1.0",\n'),
    write(S, '      elixir: "~> 1.14",\n'),
    write(S, '      start_permanent: Mix.env() == :prod,\n'),
    write(S, '      deps: deps()\n'),
    write(S, '    ]\n'),
    write(S, '  end\n\n'),
    write(S, '  def application do\n'),
    write(S, '    [\n'),
    write(S, '      extra_applications: [:logger],\n'),
    write(S, '      mod: {AgentLoop.Application, []}\n'),
    write(S, '    ]\n'),
    write(S, '  end\n\n'),
    write(S, '  defp deps do\n'),
    write(S, '    [\n'),
    write(S, '      {:jason, "~> 1.4"},\n'),
    write(S, '      {:toml, "~> 0.7"},\n'),
    write(S, '      {:plug_cowboy, "~> 2.7"},\n'),
    write(S, '      {:plug, "~> 1.15"}\n'),
    write(S, '    ]\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/mix.exs~n', []).

