    write(S, '    total_output_tokens: 0,\n'),
    write(S, '    total_cost: 0.0,\n'),
    write(S, '    records: []\n'),
    write(S, '  ]\n\n'),
    write(S, '  @type t :: %__MODULE__{\n'),
    write(S, '    total_input_tokens: non_neg_integer(),\n'),
    write(S, '    total_output_tokens: non_neg_integer(),\n'),
    write(S, '    total_cost: float(),\n'),
    write(S, '    records: [map()]\n'),
    write(S, '  }\n\n'),
    %% Emit shared_logic methods
    write_shared_block_elixir(S, costs),
