%% --- ContextManager ---
generate_elixir_context :-
    output_path(elixir, 'context_manager.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.ContextManager', 'Conversation context management'),
    write(S, 'defmodule AgentLoop.ContextManager do\n'),
    write(S, '  @moduledoc "Manages conversation message history and context window."\n\n'),
    write(S, '  defstruct [\n'),
    write(S, '    messages: [],\n'),
    write(S, '    max_messages: 100,\n'),
    write(S, '    max_context_tokens: -1,\n'),
    write(S, '    max_chars: -1,\n'),
    write(S, '    max_words: -1,\n'),
    write(S, '    context_mode: "sliding"\n'),
    write(S, '  ]\n\n'),
    write(S, '  @type t :: %__MODULE__{\n'),
    write(S, '    messages: [map()],\n'),
    write(S, '    max_messages: non_neg_integer(),\n'),
    write(S, '    max_context_tokens: integer(),\n'),
    write(S, '    max_chars: integer(),\n'),
    write(S, '    max_words: integer(),\n'),
    write(S, '    context_mode: String.t()\n'),
    write(S, '  }\n\n'),
    %% char_count helper used by estimate_tokens
    write(S, '  @doc "Count total characters across all messages."\n'),
    write(S, '  @spec char_count(t()) :: non_neg_integer()\n'),
    write(S, '  def char_count(state) do\n'),
    write(S, '    Enum.reduce(state.messages, 0, fn msg, acc ->\n'),
    write(S, '      acc + String.length(Map.get(msg, "content", ""))\n'),
    write(S, '    end)\n'),
    write(S, '  end\n\n'),
    write_shared_block_elixir(S, context),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/context_manager.ex~n', []).

%% --- MCPClient ---
generate_elixir_mcp_client :-
    output_path(elixir, 'mcp_client.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.MCPClient', 'MCP client — stdio JSON-RPC 2.0 transport'),
    write(S, 'defmodule AgentLoop.MCPClient do\n'),
    write(S, '  @moduledoc "JSON-RPC 2.0 client for Model Context Protocol servers."\n\n'),
    write(S, '  defstruct [\n'),
    write(S, '    name: "",\n'),
    write(S, '    command: [],\n'),
    write(S, '    env: %{},\n'),
    write(S, '    port: nil,\n'),
    write(S, '    request_id: 0\n'),
    write(S, '  ]\n\n'),
    write(S, '  @type t :: %__MODULE__{\n'),
    write(S, '    name: String.t(),\n'),
    write(S, '    command: [String.t()],\n'),
    write(S, '    env: map(),\n'),
    write(S, '    port: port() | nil,\n'),
    write(S, '    request_id: non_neg_integer()\n'),
    write(S, '  }\n\n'),
    write_shared_block_elixir(S, mcp),
    %% --- Hand-guided MCP protocol methods ---
    write(S, '  @doc "Connect to MCP server via stdio subprocess"\n'),
    write(S, '  @spec connect(t()) :: {:ok, t()} | {:error, String.t()}\n'),
    write(S, '  def connect(%__MODULE__{} = client) do\n'),
    write(S, '    port = Port.open({:spawn_executable, hd(client.command)},\n'),
    write(S, '      [:binary, :exit_status, {:args, tl(client.command)},\n'),
    write(S, '       {:env, Enum.map(client.env, fn {k, v} -> {String.to_charlist(k), String.to_charlist(v)} end)}])\n'),
    write(S, '    client = %{client | port: port}\n'),
    write(S, '    case send_request(client, "initialize", %{}) do\n'),
    write(S, '      {:ok, _resp, client} -> {:ok, client}\n'),
    write(S, '      {:error, reason} -> {:error, reason}\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Send a JSON-RPC 2.0 request"\n'),
    write(S, '  @spec send_request(t(), String.t(), map()) :: {:ok, map(), t()} | {:error, String.t()}\n'),
    write(S, '  def send_request(%__MODULE__{} = client, method, params) do\n'),
    write(S, '    id = client.request_id + 1\n'),
    write(S, '    client = %{client | request_id: id}\n'),
    write(S, '    payload = Jason.encode!(%{"jsonrpc" => "2.0", "id" => id, "method" => method, "params" => params})\n'),
    write(S, '    Port.command(client.port, payload <> "\\n")\n'),
    write(S, '    receive do\n'),
    write(S, '      {port_ref, {:data, data}} when port_ref == client.port ->\n'),
    write(S, '        case Jason.decode(data) do\n'),
    write(S, '          {:ok, %{"result" => result}} -> {:ok, result, client}\n'),
    write(S, '          {:ok, %{"error" => error}} -> {:error, inspect(error)}\n'),
    write(S, '          _ -> {:error, "Invalid JSON-RPC response"}\n'),
    write(S, '        end\n'),
    write(S, '    after\n'),
    write(S, '      5_000 -> {:error, "MCP request timeout"}\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Discover available tools from MCP server"\n'),
    write(S, '  @spec discover_tools(t()) :: {:ok, [map()], t()} | {:error, String.t()}\n'),
    write(S, '  def discover_tools(%__MODULE__{} = client) do\n'),
    write(S, '    case send_request(client, "tools/list", %{}) do\n'),
    write(S, '      {:ok, %{"tools" => tools}, client} -> {:ok, tools, client}\n'),
    write(S, '      {:ok, _, client} -> {:ok, [], client}\n'),
    write(S, '      {:error, reason} -> {:error, reason}\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Call a tool on the MCP server"\n'),
    write(S, '  @spec call_tool(t(), String.t(), map()) :: {:ok, map(), t()} | {:error, String.t()}\n'),
    write(S, '  def call_tool(%__MODULE__{} = client, tool_name, arguments) do\n'),
    write(S, '    send_request(client, "tools/call", %{"name" => tool_name, "arguments" => arguments})\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Disconnect from MCP server"\n'),
    write(S, '  @spec disconnect(t()) :: :ok\n'),
    write(S, '  def disconnect(%__MODULE__{} = client) do\n'),
    write(S, '    if client.port, do: Port.close(client.port)\n'),
    write(S, '    :ok\n'),
    write(S, '  end\n'),
    write(S, 'end\n\n'),
    %% --- MCPManager module ---
    write(S, 'defmodule AgentLoop.MCPManager do\n'),
    write(S, '  @moduledoc "Manages multiple MCP server connections and routes tool calls."\n\n'),
    write(S, '  defstruct servers: %{}, tools: %{}\n\n'),
    write(S, '  @type t :: %__MODULE__{servers: map(), tools: map()}\n\n'),
    write(S, '  @doc "Add and connect to an MCP server"\n'),
    write(S, '  @spec add_server(t(), String.t(), [String.t()], map()) :: {:ok, t()} | {:error, String.t()}\n'),
    write(S, '  def add_server(%__MODULE__{} = mgr, name, command, env \\\\ %{}) do\n'),
    write(S, '    client = %AgentLoop.MCPClient{name: name, command: command, env: env}\n'),
    write(S, '    case AgentLoop.MCPClient.connect(client) do\n'),
    write(S, '      {:ok, client} ->\n'),
    write(S, '        case AgentLoop.MCPClient.discover_tools(client) do\n'),
    write(S, '          {:ok, tools, client} ->\n'),
    write(S, '            tool_map = Map.new(tools, fn t -> {t["name"], name} end)\n'),
    write(S, '            mgr = %{mgr | servers: Map.put(mgr.servers, name, client),\n'),
    write(S, '                          tools: Map.merge(mgr.tools, tool_map)}\n'),
    write(S, '            {:ok, mgr}\n'),
    write(S, '          {:error, reason} -> {:error, reason}\n'),
    write(S, '        end\n'),
    write(S, '      {:error, reason} -> {:error, reason}\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "List all available tools across servers"\n'),
    write(S, '  @spec list_tools(t()) :: [String.t()]\n'),
    write(S, '  def list_tools(%__MODULE__{} = mgr), do: Map.keys(mgr.tools)\n\n'),
    write(S, '  @doc "Dispatch a tool call to the appropriate server"\n'),
    write(S, '  @spec dispatch(t(), String.t(), map()) :: {:ok, map(), t()} | {:error, String.t()}\n'),
    write(S, '  def dispatch(%__MODULE__{} = mgr, tool_name, arguments) do\n'),
    write(S, '    case Map.get(mgr.tools, tool_name) do\n'),
    write(S, '      nil -> {:error, "Unknown tool: #{tool_name}"}\n'),
    write(S, '      server_name ->\n'),
    write(S, '        client = Map.get(mgr.servers, server_name)\n'),
    write(S, '        case AgentLoop.MCPClient.call_tool(client, tool_name, arguments) do\n'),
    write(S, '          {:ok, result, client} ->\n'),
    write(S, '            mgr = %{mgr | servers: Map.put(mgr.servers, server_name, client)}\n'),
    write(S, '            {:ok, result, mgr}\n'),
    write(S, '          {:error, reason} -> {:error, reason}\n'),
    write(S, '        end\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Disconnect all servers"\n'),
    write(S, '  @spec disconnect_all(t()) :: :ok\n'),
    write(S, '  def disconnect_all(%__MODULE__{} = mgr) do\n'),
    write(S, '    Enum.each(mgr.servers, fn {_name, client} ->\n'),
    write(S, '      AgentLoop.MCPClient.disconnect(client)\n'),
    write(S, '    end)\n'),
    write(S, '    :ok\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/mcp_client.ex~n', []).

%% --- OutputParser ---
generate_elixir_output_parser :-
    output_path(elixir, 'output_parser.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.OutputParser', 'Structured output parser — extract JSON from model responses'),
    write(S, 'defmodule AgentLoop.OutputParser do\n'),
    write(S, '  @moduledoc "Extracts structured JSON blocks from model text output."\n\n'),
    write(S, '  defstruct []\n\n'),
    write(S, '  @type t :: %__MODULE__{}\n\n'),
    write_shared_block_elixir(S, output_parser),
    %% --- Hand-guided helper methods ---
    write(S, '  @doc "Extract JSON from fenced code blocks (```json ... ```)"\n'),
    write(S, '  @spec extract_fenced(String.t()) :: [map()]\n'),
    write(S, '  def extract_fenced(text) do\n'),
    write(S, '    ~r/```(?:json)?\\s*\\n(.*?)```/s\n'),
    write(S, '    |> Regex.scan(text)\n'),
    write(S, '    |> Enum.flat_map(fn [_, body] ->\n'),
    write(S, '      case Jason.decode(body) do\n'),
    write(S, '        {:ok, parsed} when is_map(parsed) -> [parsed]\n'),
    write(S, '        _ -> []\n'),
    write(S, '      end\n'),
    write(S, '    end)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Extract bare JSON objects from text using bracket depth tracking"\n'),
    write(S, '  @spec extract_bare(String.t()) :: [map()]\n'),
    write(S, '  def extract_bare(text) do\n'),
    write(S, '    text\n'),
    write(S, '    |> String.graphemes()\n'),
    write(S, '    |> Enum.reduce({0, "", []}, fn\n'),
    write(S, '      "{", {0, _acc, results} -> {1, "{", results}\n'),
    write(S, '      "{", {depth, acc, results} -> {depth + 1, acc <> "{", results}\n'),
    write(S, '      "}", {1, acc, results} ->\n'),
    write(S, '        candidate = acc <> "}"\n'),
    write(S, '        case Jason.decode(candidate) do\n'),
    write(S, '          {:ok, parsed} when is_map(parsed) -> {0, "", results ++ [parsed]}\n'),
    write(S, '          _ -> {0, "", results}\n'),
    write(S, '        end\n'),
    write(S, '      "}", {depth, acc, results} when depth > 1 -> {depth - 1, acc <> "}", results}\n'),
    write(S, '      char, {depth, acc, results} when depth > 0 -> {depth, acc <> char, results}\n'),
    write(S, '      _, state -> state\n'),
    write(S, '    end)\n'),
    write(S, '    |> elem(2)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Parse model response text and extract structured JSON blocks"\n'),
    write(S, '  @spec parse_response(String.t(), [atom()]) :: {[map()], String.t(), [String.t()]}\n'),
    write(S, '  def parse_response(text, _expected_keys \\\\ []) do\n'),
    write(S, '    fenced = extract_fenced(text)\n'),
    write(S, '    blocks = if fenced != [], do: fenced, else: extract_bare(text)\n'),
    write(S, '    {blocks, text, []}\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/output_parser.ex~n', []).

%% --- Sessions ---
generate_elixir_sessions :-
    output_path(elixir, 'sessions.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.Sessions', 'Session persistence — save/load/list/delete conversation sessions'),
    write(S, 'defmodule AgentLoop.Sessions do\n'),
    write(S, '  @moduledoc "Session persistence for agent conversations."\n\n'),
    write(S, '  defstruct sessions_dir: "sessions"\n\n'),
    write(S, '  @type t :: %__MODULE__{sessions_dir: String.t()}\n\n'),
    write_shared_block_elixir(S, sessions),
    write(S, '  @doc "Save a conversation session to disk"\n'),
    write(S, '  @spec save_session(t(), String.t(), String.t(), [map()]) :: :ok | {:error, String.t()}\n'),
    write(S, '  def save_session(state, session_id, name, messages) do\n'),
    write(S, '    path = session_path(state, session_id)\n'),
    write(S, '    File.mkdir_p!(Path.dirname(path))\n'),
    write(S, '    data = %{\n'),
    write(S, '      "id" => session_id,\n'),
    write(S, '      "name" => name,\n'),
    write(S, '      "messages" => messages,\n'),
    write(S, '      "saved_at" => DateTime.utc_now() |> DateTime.to_iso8601()\n'),
    write(S, '    }\n'),
    write(S, '    File.write!(path, Jason.encode!(data, pretty: true))\n'),
    write(S, '    :ok\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Load a session from disk"\n'),
    write(S, '  @spec load_session(t(), String.t()) :: {:ok, map()} | {:error, String.t()}\n'),
    write(S, '  def load_session(state, session_id) do\n'),
    write(S, '    path = session_path(state, session_id)\n'),
    write(S, '    case File.read(path) do\n'),
    write(S, '      {:ok, content} -> Jason.decode(content)\n'),
    write(S, '      {:error, reason} -> {:error, "Failed to load session: #{inspect(reason)}"}\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "List all saved sessions"\n'),
    write(S, '  @spec list_sessions(t()) :: [map()]\n'),
    write(S, '  def list_sessions(state) do\n'),
    write(S, '    dir = state.sessions_dir\n'),
    write(S, '    case File.ls(dir) do\n'),
    write(S, '      {:ok, files} ->\n'),
    write(S, '        files\n'),
    write(S, '        |> Enum.filter(&String.ends_with?(&1, ".json"))\n'),
    write(S, '        |> Enum.map(fn file ->\n'),
    write(S, '          path = Path.join(dir, file)\n'),
    write(S, '          case File.read(path) do\n'),
    write(S, '            {:ok, content} ->\n'),
    write(S, '              case Jason.decode(content) do\n'),
    write(S, '                {:ok, data} -> Map.take(data, ["id", "name", "saved_at"])\n'),
    write(S, '                _ -> nil\n'),
    write(S, '              end\n'),
    write(S, '            _ -> nil\n'),
    write(S, '          end\n'),
    write(S, '        end)\n'),
    write(S, '        |> Enum.reject(&is_nil/1)\n'),
    write(S, '      {:error, _} -> []\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Delete a session file"\n'),
    write(S, '  @spec delete_session(t(), String.t()) :: :ok | {:error, String.t()}\n'),
    write(S, '  def delete_session(state, session_id) do\n'),
    write(S, '    path = session_path(state, session_id)\n'),
    write(S, '    case File.rm(path) do\n'),
    write(S, '      :ok -> :ok\n'),
    write(S, '      {:error, reason} -> {:error, "Failed to delete session: #{inspect(reason)}"}\n'),
    write(S, '    end\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/sessions.ex~n', []).

