%% --- Pricing module attribute table ---
generate_elixir_pricing :-
    output_path(elixir, 'pricing.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.Pricing', 'Model pricing table'),
    write(S, 'defmodule AgentLoop.Pricing do\n'),
    write(S, '  @moduledoc "Model pricing data — cost per million tokens (input/output)."\n\n'),
    write(S, '  @type entry :: {String.t(), float(), float()}\n\n'),
    write(S, '  @pricing [\n'),
    forall(model_pricing(Model, Input, Output), (
        format(S, '    {"~w", ~w, ~w},~n', [Model, Input, Output])
    )),
    write(S, '  ]\n\n'),
    write(S, '  @doc "Return the full pricing table."\n'),
    write(S, '  @spec all() :: [entry()]\n'),
    write(S, '  def all, do: @pricing\n\n'),
    write(S, '  @doc "Look up pricing for a model name. Returns {input, output} or :unknown."\n'),
    write(S, '  @spec lookup(String.t()) :: {float(), float()} | :unknown\n'),
    write(S, '  def lookup(model) do\n'),
    write(S, '    case Enum.find(@pricing, fn {name, _, _} -> name == model end) do\n'),
    write(S, '      {_, input, output} -> {input, output}\n'),
    write(S, '      nil -> :unknown\n'),
    write(S, '    end\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/pricing.ex~n', []).

%% --- Tool specs module ---
generate_elixir_tools :-
    output_path(elixir, 'tools.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.Tools', 'Tool specifications'),
    write(S, 'defmodule AgentLoop.Tools do\n'),
    write(S, '  @moduledoc "Tool specification registry — parameters, confirmation, timeouts."\n\n'),
    write(S, '  @type param :: %{name: atom(), type: atom(), required: boolean(), description: String.t()}\n'),
    write(S, '  @type spec :: %{name: atom(), description: String.t(), params: [param()], confirm: boolean(), timeout: non_neg_integer()}\n\n'),
    write(S, '  @tools [\n'),
    forall(tool_spec(Name, Props), (
        member(description(Desc), Props),
        (member(parameters(Params), Props) -> true ; Params = []),
        (member(confirmation_required(Confirm), Props) -> true ; Confirm = false),
        (member(timeout(Timeout), Props) -> true ; Timeout = 120),
        format(S, '    %{name: :~w, description: "~w", confirm: ~w, timeout: ~w, params: [', [Name, Desc, Confirm, Timeout]),
        forall(member(param(PName, PType, PReq, PDesc), Params), (
            (PReq == required -> IsReq = true ; IsReq = false),
            format(S, '%{name: :~w, type: :~w, required: ~w, description: "~w"}, ', [PName, PType, IsReq, PDesc])
        )),
        write(S, ']},\n')
    )),
    write(S, '  ]\n\n'),
    %% Destructive tools
    write(S, '  @destructive_tools MapSet.new([\n'),
    forall(destructive_tool(DT), (
        format(S, '    "~w",~n', [DT])
    )),
    write(S, '  ])\n\n'),
    write(S, '  @doc "Return all tool specifications."\n'),
    write(S, '  @spec all() :: [spec()]\n'),
    write(S, '  def all, do: @tools\n\n'),
    write(S, '  @doc "Look up a tool spec by name."\n'),
    write(S, '  @spec lookup(atom()) :: spec() | nil\n'),
    write(S, '  def lookup(name) do\n'),
    write(S, '    Enum.find(@tools, fn t -> t.name == name end)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Check if a tool is destructive."\n'),
    write(S, '  @spec destructive?(String.t()) :: boolean()\n'),
    write(S, '  def destructive?(name), do: MapSet.member?(@destructive_tools, name)\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/tools.ex~n', []).

%% --- Backend config module ---
generate_elixir_backends :-
    output_path(elixir, 'backends.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.Backends', 'Backend configuration registry'),
    write(S, 'defmodule AgentLoop.Backends do\n'),
    write(S, '  @moduledoc "Agent backend configuration — CLI and API backends."\n\n'),
    write(S, '  @type backend :: %{\n'),
    write(S, '    name: atom(),\n'),
    write(S, '    type: atom(),\n'),
    write(S, '    class_name: String.t(),\n'),
    write(S, '    command: String.t(),\n'),
    write(S, '    description: String.t(),\n'),
    write(S, '    supports_streaming: boolean()\n'),
    write(S, '  }\n\n'),
    write(S, '  @backends [\n'),
    forall(agent_backend(Name, Props), (
        (member(type(Type), Props) -> true ; Type = unknown),
        (member(class_name(ClassName), Props) -> true ; ClassName = ''),
        (member(command(Cmd), Props) -> true ; Cmd = ''),
        (member(description(Desc), Props) -> true ; Desc = ''),
        (member(supports_streaming(Stream), Props) -> true ; Stream = false),
        (member(default_model(DefModel0), Props) ->
            format(atom(DefModel), '"~w"', [DefModel0])
        ;
            DefModel = nil
        ),
        format(S, '    %{name: :~w, type: :~w, class_name: "~w", command: "~w", description: "~w", supports_streaming: ~w, default_model: ~w},~n',
            [Name, Type, ClassName, Cmd, Desc, Stream, DefModel])
    )),
    write(S, '  ]\n\n'),
    write(S, '  @doc "Return all backend configurations."\n'),
    write(S, '  @spec all() :: [backend()]\n'),
    write(S, '  def all, do: @backends\n\n'),
    write(S, '  @doc "Look up a backend by name."\n'),
    write(S, '  @spec lookup(atom()) :: backend() | nil\n'),
    write(S, '  def lookup(name) do\n'),
    write(S, '    Enum.find(@backends, fn b -> b.name == name end)\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/backends.ex~n', []).

%% =============================================================================
%% Elixir GenServer Wrappers
%% =============================================================================

%% --- CostTracker GenServer ---
generate_elixir_cost_server :-
    output_path(elixir, 'cost_server.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.CostServer', 'GenServer wrapper for CostTracker'),
    write(S, 'defmodule AgentLoop.CostServer do\n'),
    write(S, '  @moduledoc """\n'),
    write(S, '  GenServer wrapping AgentLoop.CostTracker for OTP integration.\n'),
    write(S, '  Manages cost tracking state across concurrent API calls.\n'),
    write(S, '  """\n\n'),
    write(S, '  use GenServer\n\n'),
    write(S, '  alias AgentLoop.CostTracker\n\n'),
    write(S, '  # --- Client API ---\n\n'),
    write(S, '  def start_link(opts \\\\ []) do\n'),
    write(S, '    GenServer.start_link(__MODULE__, %CostTracker{}, opts)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Check if total cost exceeds budget."\n'),
    write(S, '  def over_budget?(server, budget) do\n'),
    write(S, '    GenServer.call(server, {:is_over_budget, budget})\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Return remaining budget."\n'),
    write(S, '  def budget_remaining(server, budget) do\n'),
    write(S, '    GenServer.call(server, {:budget_remaining, budget})\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Reset all cost tracking state."\n'),
    write(S, '  def reset(server) do\n'),
    write(S, '    GenServer.call(server, :reset)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Get current state snapshot."\n'),
    write(S, '  def get_state(server) do\n'),
    write(S, '    GenServer.call(server, :get_state)\n'),
    write(S, '  end\n\n'),
    write(S, '  # --- Server Callbacks ---\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def init(state), do: {:ok, state}\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call({:is_over_budget, budget}, _from, state) do\n'),
    write(S, '    {:reply, CostTracker.is_over_budget(state, budget), state}\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call({:budget_remaining, budget}, _from, state) do\n'),
    write(S, '    {:reply, CostTracker.budget_remaining(state, budget), state}\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call(:reset, _from, _state) do\n'),
    write(S, '    new_state = CostTracker.reset(%CostTracker{})\n'),
    write(S, '    {:reply, :ok, new_state}\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call(:get_state, _from, state) do\n'),
    write(S, '    {:reply, state, state}\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/cost_server.ex~n', []).

