%% --- MCPClient GenServer ---
generate_elixir_mcp_server :-
    output_path(elixir, 'mcp_server.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.MCPServer', 'GenServer wrapper for MCPClient'),
    write(S, 'defmodule AgentLoop.MCPServer do\n'),
    write(S, '  @moduledoc """\n'),
    write(S, '  GenServer wrapping AgentLoop.MCPClient for OTP integration.\n'),
    write(S, '  Manages MCP connection state and request ID sequencing.\n'),
    write(S, '  """\n\n'),
    write(S, '  use GenServer\n\n'),
    write(S, '  alias AgentLoop.MCPClient\n\n'),
    write(S, '  # --- Client API ---\n\n'),
    write(S, '  def start_link(opts \\\\ []) do\n'),
    write(S, '    GenServer.start_link(__MODULE__, %MCPClient{}, opts)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Get next request ID and advance counter."\n'),
    write(S, '  def next_request_id(server) do\n'),
    write(S, '    GenServer.call(server, :next_request_id)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Get current state snapshot."\n'),
    write(S, '  def get_state(server) do\n'),
    write(S, '    GenServer.call(server, :get_state)\n'),
    write(S, '  end\n\n'),
    write(S, '  # --- Server Callbacks ---\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def init(state), do: {:ok, state}\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call(:next_request_id, _from, state) do\n'),
    write(S, '    id = MCPClient.next_request_id(state)\n'),
    write(S, '    new_state = %{state | request_id: state.request_id + 1}\n'),
    write(S, '    {:reply, id, new_state}\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call(:get_state, _from, state) do\n'),
    write(S, '    {:reply, state, state}\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/mcp_server.ex~n', []).

%% --- MCPManagerServer GenServer ---
generate_elixir_mcp_manager_server :-
    output_path(elixir, 'mcp_manager_server.ex', Path),
    open(Path, write, S),
    write_elixir_header(S, 'AgentLoop.MCPManagerServer', 'GenServer wrapper for MCPManager'),
    write(S, 'defmodule AgentLoop.MCPManagerServer do\n'),
    write(S, '  @moduledoc """\n'),
    write(S, '  GenServer wrapping AgentLoop.MCPManager for OTP integration.\n'),
    write(S, '  Manages multiple MCP server connections and routes tool calls.\n'),
    write(S, '  """\n\n'),
    write(S, '  use GenServer\n\n'),
    write(S, '  alias AgentLoop.MCPManager\n\n'),
    write(S, '  # --- Client API ---\n\n'),
    write(S, '  def start_link(opts \\\\ []) do\n'),
    write(S, '    GenServer.start_link(__MODULE__, %MCPManager{}, opts)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Add and connect to an MCP server."\n'),
    write(S, '  def add_server(server, name, command, env \\\\ %{}) do\n'),
    write(S, '    GenServer.call(server, {:add_server, name, command, env})\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "List all available tools across servers."\n'),
    write(S, '  def list_tools(server) do\n'),
    write(S, '    GenServer.call(server, :list_tools)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Dispatch a tool call to the appropriate server."\n'),
    write(S, '  def dispatch(server, tool_name, arguments) do\n'),
    write(S, '    GenServer.call(server, {:dispatch, tool_name, arguments})\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Disconnect all servers."\n'),
    write(S, '  def disconnect_all(server) do\n'),
    write(S, '    GenServer.call(server, :disconnect_all)\n'),
    write(S, '  end\n\n'),
    write(S, '  @doc "Get current state snapshot."\n'),
    write(S, '  def get_state(server) do\n'),
    write(S, '    GenServer.call(server, :get_state)\n'),
    write(S, '  end\n\n'),
    write(S, '  # --- Server Callbacks ---\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def init(state), do: {:ok, state}\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call({:add_server, name, command, env}, _from, state) do\n'),
    write(S, '    case MCPManager.add_server(state, name, command, env) do\n'),
    write(S, '      {:ok, new_state} -> {:reply, :ok, new_state}\n'),
    write(S, '      {:error, reason} -> {:reply, {:error, reason}, state}\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call(:list_tools, _from, state) do\n'),
    write(S, '    {:reply, MCPManager.list_tools(state), state}\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call({:dispatch, tool_name, arguments}, _from, state) do\n'),
    write(S, '    case MCPManager.dispatch(state, tool_name, arguments) do\n'),
    write(S, '      {:ok, result, new_state} -> {:reply, {:ok, result}, new_state}\n'),
    write(S, '      {:error, reason} -> {:reply, {:error, reason}, state}\n'),
    write(S, '    end\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call(:disconnect_all, _from, state) do\n'),
    write(S, '    MCPManager.disconnect_all(state)\n'),
    write(S, '    {:reply, :ok, %MCPManager{}}\n'),
    write(S, '  end\n\n'),
    write(S, '  @impl true\n'),
    write(S, '  def handle_call(:get_state, _from, state) do\n'),
    write(S, '    {:reply, state, state}\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/lib/agent_loop/mcp_manager_server.ex~n', []).

%% =============================================================================
%% Elixir ExUnit Test Generation
%% =============================================================================

generate_elixir_tests :-
    target_dir(elixir, LibDir),
    atom_concat(LibDir, '../../test/', TestDir),
    make_directory_path(TestDir),
    generate_elixir_test_helper(TestDir),
    generate_elixir_cost_test(TestDir),
    generate_elixir_context_test(TestDir),
    generate_elixir_streaming_test(TestDir),
    generate_elixir_tool_cache_test(TestDir),
    generate_elixir_retry_test(TestDir),
    generate_elixir_pricing_test(TestDir),
    generate_elixir_tools_test(TestDir),
    generate_elixir_security_test(TestDir),
    generate_elixir_config_test(TestDir),
    generate_elixir_cache_server_test(TestDir),
    generate_elixir_streaming_server_test(TestDir),
    generate_elixir_mcp_server_test(TestDir),
    generate_elixir_output_parser_test(TestDir),
    generate_elixir_sessions_test(TestDir),
    generate_elixir_mcp_manager_server_test(TestDir),
    generate_elixir_router_test(TestDir).

generate_elixir_test_helper(Dir) :-
    atom_concat(Dir, 'test_helper.exs', Path),
    open(Path, write, S),
    write(S, 'ExUnit.start()\n'),
    close(S),
    format('  Generated elixir/test/test_helper.exs~n', []).

%% --- CostTracker tests ---
generate_elixir_cost_test(Dir) :-
    atom_concat(Dir, 'cost_tracker_test.exs', Path),
    open(Path, write, S),
    write(S, 'defmodule AgentLoop.CostTrackerTest do\n'),
    write(S, '  use ExUnit.Case, async: true\n\n'),
    write(S, '  alias AgentLoop.CostTracker\n\n'),
    write(S, '  test "new struct has zero costs" do\n'),
    write(S, '    state = %CostTracker{}\n'),
    write(S, '    assert state.total_cost == 0.0\n'),
    write(S, '    assert state.total_input_tokens == 0\n'),
    write(S, '    assert state.total_output_tokens == 0\n'),
    write(S, '    assert state.records == []\n'),
    write(S, '  end\n\n'),
    write(S, '  test "is_over_budget returns false for zero budget (unlimited)" do\n'),
    write(S, '    state = %CostTracker{}\n'),
    write(S, '    refute CostTracker.is_over_budget(state, 0)\n'),
    write(S, '  end\n\n'),
    write(S, '  test "is_over_budget returns false when under budget" do\n'),
    write(S, '    state = %CostTracker{total_cost: 5.0}\n'),
    write(S, '    refute CostTracker.is_over_budget(state, 10.0)\n'),
    write(S, '  end\n\n'),
    write(S, '  test "is_over_budget returns true when over budget" do\n'),
    write(S, '    state = %CostTracker{total_cost: 15.0}\n'),
    write(S, '    assert CostTracker.is_over_budget(state, 10.0)\n'),
    write(S, '  end\n\n'),
    write(S, '  test "budget_remaining returns -1 for unlimited" do\n'),
    write(S, '    state = %CostTracker{}\n'),
    write(S, '    assert CostTracker.budget_remaining(state, 0) == -1.0\n'),
    write(S, '  end\n\n'),
    write(S, '  test "budget_remaining calculates correctly" do\n'),
    write(S, '    state = %CostTracker{total_cost: 3.0}\n'),
    write(S, '    assert CostTracker.budget_remaining(state, 10.0) == 7.0\n'),
    write(S, '  end\n\n'),
    write(S, '  test "reset clears all fields" do\n'),
    write(S, '    state = %CostTracker{total_cost: 5.0, total_input_tokens: 100, records: [%{}]}\n'),
    write(S, '    reset = CostTracker.reset(state)\n'),
    write(S, '    assert reset.total_cost == 0.0\n'),
    write(S, '    assert reset.total_input_tokens == 0\n'),
    write(S, '    assert reset.total_output_tokens == 0\n'),
    write(S, '    assert reset.records == []\n'),
    write(S, '  end\n\n'),
    write(S, '  test "cost_compute calculates per-million pricing" do\n'),
    write(S, '    # 1000 tokens at $15/million = $0.015\n'),
    write(S, '    cost = CostTracker.cost_compute(1000, 15.0)\n'),
    write(S, '    assert_in_delta cost, 0.015, 0.0001\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/test/cost_tracker_test.exs~n', []).

%% --- ContextManager tests ---
