    write(S, '  test "len counts messages" do\n'),
    write(S, '    state = %ContextManager{messages: [%{}, %{}, %{}]}\n'),
    write(S, '    assert ContextManager.len(state) == 3\n'),
    write(S, '  end\n\n'),
    write(S, '  test "estimate_tokens uses char/4 heuristic" do\n'),
    write(S, '    msg = %{"content" => String.duplicate("a", 400)}\n'),
    write(S, '    state = %ContextManager{messages: [msg]}\n'),
    write(S, '    assert ContextManager.estimate_tokens(state) == 100\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/test/context_manager_test.exs~n', []).

