%% --- Retry tests ---
generate_elixir_retry_test(Dir) :-
    atom_concat(Dir, 'retry_test.exs', Path),
    open(Path, write, S),
    write(S, 'defmodule AgentLoop.RetryTest do\n'),
    write(S, '  use ExUnit.Case, async: true\n\n'),
    write(S, '  alias AgentLoop.Retry\n\n'),
    write(S, '  test "is_retryable_status for 429" do\n'),
    write(S, '    assert Retry.is_retryable_status(429)\n'),
    write(S, '  end\n\n'),
    write(S, '  test "is_retryable_status for 500" do\n'),
    write(S, '    assert Retry.is_retryable_status(500)\n'),
    write(S, '  end\n\n'),
    write(S, '  test "is_retryable_status false for 200" do\n'),
    write(S, '    refute Retry.is_retryable_status(200)\n'),
    write(S, '  end\n\n'),
    write(S, '  test "is_retryable_status false for 404" do\n'),
    write(S, '    refute Retry.is_retryable_status(404)\n'),
    write(S, '  end\n\n'),
    write(S, '  test "compute_delay first attempt" do\n'),
    write(S, '    delay = Retry.compute_delay(1.0, 2.0, 1, 60.0)\n'),
    write(S, '    assert_in_delta delay, 1.0, 0.001\n'),
    write(S, '  end\n\n'),
    write(S, '  test "compute_delay exponential growth" do\n'),
    write(S, '    delay = Retry.compute_delay(1.0, 2.0, 4, 60.0)\n'),
    write(S, '    assert_in_delta delay, 8.0, 0.001\n'),
    write(S, '  end\n\n'),
    write(S, '  test "compute_delay caps at max_delay" do\n'),
    write(S, '    delay = Retry.compute_delay(1.0, 2.0, 10, 30.0)\n'),
    write(S, '    assert delay == 30.0\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/test/retry_test.exs~n', []).

%% --- Pricing tests ---
