    aggregate_all(count, model_pricing(_, _, _), PricingCount),
    format(S, '  test "pricing table has ~w entries" do~n', [PricingCount]),
    format(S, '    assert length(Pricing.all()) == ~w~n', [PricingCount]),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/test/pricing_test.exs~n', []).

%% --- Tools tests ---
generate_elixir_tools_test(Dir) :-
    atom_concat(Dir, 'tools_test.exs', Path),
    open(Path, write, S),
    write(S, 'defmodule AgentLoop.ToolsTest do\n'),
    write(S, '  use ExUnit.Case, async: true\n\n'),
    write(S, '  alias AgentLoop.Tools\n\n'),
    write(S, '  test "all returns non-empty list" do\n'),
    write(S, '    assert length(Tools.all()) > 0\n'),
    write(S, '  end\n\n'),
    write(S, '  test "lookup bash tool" do\n'),
    write(S, '    tool = Tools.lookup(:bash)\n'),
    write(S, '    assert tool != nil\n'),
    write(S, '    assert tool.name == :bash\n'),
    write(S, '    assert tool.confirm == true\n'),
    write(S, '  end\n\n'),
    write(S, '  test "lookup read tool is non-destructive" do\n'),
    write(S, '    tool = Tools.lookup(:read)\n'),
    write(S, '    assert tool != nil\n'),
    write(S, '    assert tool.confirm == false\n'),
    write(S, '  end\n\n'),
    write(S, '  test "destructive? checks destructive tools" do\n'),
    (destructive_tool(DT) ->
        format(S, '    assert Tools.destructive?("~w")~n', [DT])
    ; true),
    write(S, '    refute Tools.destructive?("read")\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/test/tools_test.exs~n', []).

