%% --- OutputParser tests ---
generate_elixir_output_parser_test(Dir) :-
    atom_concat(Dir, 'output_parser_test.exs', Path),
    open(Path, write, S),
    write(S, 'defmodule AgentLoop.OutputParserTest do\n'),
    write(S, '  use ExUnit.Case, async: true\n\n'),
    write(S, '  alias AgentLoop.OutputParser\n\n'),
    write(S, '  test "extract_fenced parses fenced JSON blocks" do\n'),
    write(S, '    text = "Some text\\n```json\\n{\\\"key\\\": \\\"value\\\"}\\n```\\nMore text"\n'),
    write(S, '    result = OutputParser.extract_fenced(text)\n'),
    write(S, '    assert [%{"key" => "value"}] = result\n'),
    write(S, '  end\n\n'),
    write(S, '  test "extract_bare parses bare JSON objects" do\n'),
    write(S, '    text = "Here is {\\\"a\\\": 1} inline"\n'),
    write(S, '    result = OutputParser.extract_bare(text)\n'),
    write(S, '    assert [%{"a" => 1}] = result\n'),
    write(S, '  end\n\n'),
    write(S, '  test "parse_response prefers fenced blocks" do\n'),
    write(S, '    text = "```json\\n{\\\"tool\\\": \\\"read\\\"}\\n```"\n'),
    write(S, '    {blocks, _raw, errors} = OutputParser.parse_response(text)\n'),
    write(S, '    assert length(blocks) == 1\n'),
    write(S, '    assert errors == []\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/test/output_parser_test.exs~n', []).

%% --- Sessions tests ---
generate_elixir_sessions_test(Dir) :-
    atom_concat(Dir, 'sessions_test.exs', Path),
    open(Path, write, S),
    write(S, 'defmodule AgentLoop.SessionsTest do\n'),
    write(S, '  use ExUnit.Case, async: true\n\n'),
    write(S, '  alias AgentLoop.Sessions\n\n'),
    write(S, '  setup do\n'),
    write(S, '    dir = Path.join(System.tmp_dir!(), "agent_loop_test_sessions_#{:rand.uniform(999999)}")\n'),
    write(S, '    File.mkdir_p!(dir)\n'),
    write(S, '    on_exit(fn -> File.rm_rf!(dir) end)\n'),
    write(S, '    %{state: %Sessions{sessions_dir: dir}}\n'),
    write(S, '  end\n\n'),
    write(S, '  test "session_path builds correct path", %{state: state} do\n'),
    write(S, '    path = Sessions.session_path(state, "abc123")\n'),
    write(S, '    assert String.ends_with?(path, "abc123.json")\n'),
    write(S, '  end\n\n'),
    write(S, '  test "session_exists returns false for missing session", %{state: state} do\n'),
    write(S, '    refute Sessions.session_exists(state, "nonexistent")\n'),
    write(S, '  end\n\n'),
    write(S, '  test "save and load round-trip", %{state: state} do\n'),
    write(S, '    :ok = Sessions.save_session(state, "test1", "Test Session", [%{"role" => "user", "content" => "hello"}])\n'),
    write(S, '    assert Sessions.session_exists(state, "test1")\n'),
    write(S, '    {:ok, data} = Sessions.load_session(state, "test1")\n'),
    write(S, '    assert data["name"] == "Test Session"\n'),
    write(S, '    assert length(data["messages"]) == 1\n'),
    write(S, '  end\n\n'),
    write(S, '  test "list_sessions returns saved sessions", %{state: state} do\n'),
    write(S, '    :ok = Sessions.save_session(state, "s1", "Session 1", [])\n'),
    write(S, '    :ok = Sessions.save_session(state, "s2", "Session 2", [])\n'),
    write(S, '    sessions = Sessions.list_sessions(state)\n'),
    write(S, '    assert length(sessions) == 2\n'),
    write(S, '  end\n\n'),
    write(S, '  test "delete_session removes file", %{state: state} do\n'),
    write(S, '    :ok = Sessions.save_session(state, "del1", "To Delete", [])\n'),
    write(S, '    assert Sessions.session_exists(state, "del1")\n'),
    write(S, '    :ok = Sessions.delete_session(state, "del1")\n'),
    write(S, '    refute Sessions.session_exists(state, "del1")\n'),
    write(S, '  end\n'),
    write(S, 'end\n'),
    close(S),
    format('  Generated elixir/test/sessions_test.exs~n', []).

