    write(S, '  (:require [clojure.string :as str]))\n\n'),
    write(S, '(defn create-context\n'),
    write(S, '  "Create a new context manager state."\n'),
    write(S, '  []\n'),
    write(S, '  {:messages []\n'),
    write(S, '   :format "plain"\n'),
    write(S, '   :max-tokens 0\n'),
    write(S, '   :max-messages 0})\n\n'),
    %% char-count helper used by estimate-tokens
    write(S, '(defn char-count\n'),
    write(S, '  "Compute total character count across all messages."\n'),
    write(S, '  [state]\n'),
    write(S, '  (reduce + 0 (map #(count (str (:content % ""))) (:messages state))))\n\n'),
