    generate_clojure_output_parser_test(TestDir),
    generate_clojure_sessions_test(TestDir),
    generate_clojure_mcp_test(TestDir),
    generate_clojure_property_test(TestDir).

%% --- Cost tests ---
generate_clojure_cost_test(Dir) :-
    atom_concat(Dir, 'costs_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.costs-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.costs :as costs]))\n\n'),
    write(S, '(deftest test-create-cost-tracker\n'),
    write(S, '  (let [state (costs/create-cost-tracker)]\n'),
    write(S, '    (is (= 0.0 (:total-cost state)))\n'),
    write(S, '    (is (= 0 (:total-input-tokens state)))\n'),
    write(S, '    (is (= 0 (:total-output-tokens state)))))\n\n'),
    write(S, '(deftest test-is-over-budget\n'),
    write(S, '  (testing "zero budget means unlimited"\n'),
    write(S, '    (is (false? (costs/is-over-budget (costs/create-cost-tracker) 0))))\n'),
    write(S, '  (testing "under budget"\n'),
    write(S, '    (is (false? (costs/is-over-budget {:total-cost 5.0} 10.0))))\n'),
    write(S, '  (testing "over budget"\n'),
    write(S, '    (is (true? (costs/is-over-budget {:total-cost 15.0} 10.0)))))\n\n'),
    write(S, '(deftest test-budget-remaining\n'),
    write(S, '  (testing "unlimited returns -1"\n'),
    write(S, '    (is (= -1.0 (costs/budget-remaining (costs/create-cost-tracker) 0))))\n'),
    write(S, '  (testing "remaining calculation"\n'),
    write(S, '    (is (= 7.0 (costs/budget-remaining {:total-cost 3.0} 10.0)))))\n\n'),
    write(S, '(deftest test-cost-compute\n'),
    write(S, '  (let [cost (costs/cost-compute 1000 15.0)]\n'),
    write(S, '    (is (< (Math/abs (- cost 0.015)) 0.0001))))\n\n'),
    write(S, '(deftest test-total-tokens\n'),
    write(S, '  (is (= 300 (costs/total-tokens {:total-input-tokens 200 :total-output-tokens 100}))))\n\n'),
    write(S, '(deftest test-is-free-model\n'),
    write(S, '  (is (true? (costs/is-free-model {:total-cost 0.0})))\n'),
    write(S, '  (is (false? (costs/is-free-model {:total-cost 0.5}))))\n\n'),
    write(S, '(deftest test-average-cost-per-message\n'),
    write(S, '  (is (= 0.0 (costs/average-cost-per-message {:total-cost 10.0 :message-count 0})))\n'),
    write(S, '  (is (= 2.0 (costs/average-cost-per-message {:total-cost 10.0 :message-count 5}))))\n\n'),
    write(S, '(deftest test-is-tracking\n'),
    write(S, '  (is (false? (costs/is-tracking {:message-count 0})))\n'),
    write(S, '  (is (true? (costs/is-tracking {:message-count 3}))))\n\n'),
    write(S, '(deftest test-has-records\n'),
    write(S, '  (is (not (costs/has-records {:records []})))\n'),
    write(S, '  (is (costs/has-records {:records [{:tokens 10}]})))\n\n'),
    write(S, '(deftest test-cost-summary-short\n'),
    write(S, '  (is (string? (costs/cost-summary-short {:total-cost 1.5 :total-input-tokens 100 :total-output-tokens 50}))))\n\n'),
    write(S, '(deftest test-cost-per-input-token\n'),
    write(S, '  (is (= 0.0 (costs/cost-per-input-token {:total-cost 1.0 :total-input-tokens 0})))\n'),
    write(S, '  (is (pos? (costs/cost-per-input-token {:total-cost 1.0 :total-input-tokens 1000}))))\n\n'),
    write(S, '(deftest test-reset\n'),
    write(S, '  (let [state (costs/reset {:total-cost 5.0 :total-input-tokens 100 :total-output-tokens 50 :message-count 3})]\n'),
    write(S, '    (is (= 0.0 (:total-cost state)))\n'),
    write(S, '    (is (= 0 (:total-input-tokens state)))))\n\n'),
    write(S, '(deftest test-total-messages\n'),
    write(S, '  (is (= 5 (costs/total-messages {:message-count 5})))\n'),
    write(S, '  (is (= 0 (costs/total-messages {:message-count 0}))))\n\n'),
    write(S, '(deftest test-cost-exceeds\n'),
    write(S, '  (is (true? (costs/cost-exceeds {:total-cost 15.0} 10.0)))\n'),
    write(S, '  (is (false? (costs/cost-exceeds {:total-cost 5.0} 10.0))))\n\n'),
    write(S, '(deftest test-input-ratio\n'),
    write(S, '  (is (= 0.0 (costs/input-ratio {:total-input-tokens 0 :total-output-tokens 0})))\n'),
    write(S, '  (is (= 0.5 (costs/input-ratio {:total-input-tokens 50 :total-output-tokens 50}))))\n\n'),
    write(S, '(deftest test-cost-format-dollars\n'),
    write(S, '  (is (= "$1.5" (costs/format-dollars 1.5)))\n'),
    write(S, '  (is (= "$0" (costs/format-dollars 0)))\n'),
    write(S, '  (is (= "$99.99" (costs/format-dollars 99.99))))\n\n'),
    write(S, '(deftest test-has-usage\n'),
    write(S, '  (is (false? (costs/has-usage {:total-input-tokens 0 :total-output-tokens 0})))\n'),
    write(S, '  (is (true? (costs/has-usage {:total-input-tokens 100 :total-output-tokens 0}))))\n\n'),
    write(S, '(deftest test-cost-output-ratio\n'),
    write(S, '  (is (= 0.0 (costs/output-ratio {:total-input-tokens 0 :total-output-tokens 0})))\n'),
    write(S, '  (is (= 0.5 (costs/output-ratio {:total-input-tokens 50 :total-output-tokens 50}))))\n\n'),
    write(S, '(deftest test-cost-is-input-heavy\n'),
    write(S, '  (is (true? (costs/is-input-heavy {:total-input-tokens 200 :total-output-tokens 50})))\n'),
    write(S, '  (is (false? (costs/is-input-heavy {:total-input-tokens 10 :total-output-tokens 100}))))\n\n'),
    write(S, '(deftest test-cost-is-output-heavy\n'),
    write(S, '  (is (true? (costs/is-output-heavy {:total-input-tokens 10 :total-output-tokens 100})))\n'),
    write(S, '  (is (false? (costs/is-output-heavy {:total-input-tokens 100 :total-output-tokens 10}))))\n\n'),
    write(S, '(deftest test-cost-is-zero\n'),
    write(S, '  (is (true? (costs/is-zero-cost {:total-cost 0.0})))\n'),
    write(S, '  (is (false? (costs/is-zero-cost {:total-cost 5.0}))))\n\n'),
    write(S, '(deftest test-is-output-heavy\n'),
    write(S, '  (is (true? (costs/is-output-heavy {:total-input-tokens 10 :total-output-tokens 100})))\n'),
    write(S, '  (is (false? (costs/is-output-heavy {:total-input-tokens 100 :total-output-tokens 10}))))\n\n'),
    write(S, '(deftest test-is-zero-cost\n'),
    write(S, '  (is (true? (costs/is-zero-cost {:total-cost 0.0})))\n'),
    write(S, '  (is (false? (costs/is-zero-cost {:total-cost 5.0}))))\n\n'),
    write(S, '(deftest test-is-under\n'),
    write(S, '  (is (true? (costs/is-under {:total-cost 5.0} 10.0)))\n'),
    write(S, '  (is (false? (costs/is-under {:total-cost 15.0} 10.0))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/costs_test.clj~n', []).

%% --- Context tests ---
generate_clojure_context_test(Dir) :-
    atom_concat(Dir, 'context_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.context-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.context :as ctx]))\n\n'),
    write(S, '(deftest test-create-context\n'),
    write(S, '  (let [state (ctx/create-context)]\n'),
    write(S, '    (is (= [] (:messages state)))\n'),
    write(S, '    (is (= "plain" (:format state)))))\n\n'),
    write(S, '(deftest test-context-is-empty\n'),
    write(S, '  (is (true? (ctx/is-empty (ctx/create-context))))\n'),
    write(S, '  (is (false? (ctx/is-empty {:messages [{:role "user"}]}))))\n\n'),
    write(S, '(deftest test-estimate-tokens\n'),
    write(S, '  (let [state {:messages [{:content "a"} {:content "b"} {:content "c"} {:content "d"} {:content "e"}]}]\n'),
    write(S, '    (is (>= (ctx/estimate-tokens state) 0))))\n\n'),
    write(S, '(deftest test-word-count\n'),
    write(S, '  (is (= 3 (ctx/word-count "hello world foo"))))\n\n'),
    write(S, '(deftest test-message-token-estimate\n'),
    write(S, '  (is (pos? (ctx/message-token-estimate "some content here"))))\n\n'),
    write(S, '(deftest test-context-len\n'),
    write(S, '  (is (= 0 (ctx/len {:messages []})))\n'),
    write(S, '  (is (= 2 (ctx/len {:messages [{:role "user"} {:role "assistant"}]}))))\n\n'),
    write(S, '(deftest test-context-has-messages\n'),
    write(S, '  (is (nil? (ctx/has-messages {:messages []})))\n'),
    write(S, '  (is (some? (ctx/has-messages {:messages [{:role "user"}]}))))\n\n'),
    write(S, '(deftest test-context-clear\n'),
    write(S, '  (let [state (ctx/clear {:messages [{:role "user"}]})]\n'),
    write(S, '    (is (= [] (:messages state)))))\n\n'),
    write(S, '(deftest test-context-message-count\n'),
    write(S, '  (is (= 3 (ctx/context-message-count {:messages [{} {} {}]}))))\n\n'),
    write(S, '(deftest test-get-format\n'),
    write(S, '  (is (= "json" (ctx/get-format {:format "json"}))))\n\n'),
    write(S, '(deftest test-token-budget\n'),
    write(S, '  (is (= -1 (ctx/token-budget {:max-tokens 0 :token-count 0})))\n'),
    write(S, '  (is (= 80 (ctx/token-budget {:max-tokens 100 :token-count 20}))))\n\n'),
    write(S, '(deftest test-context-messages-remaining\n'),
    write(S, '  (is (= -1 (ctx/messages-remaining {:max-messages 0 :messages []})))\n'),
    write(S, '  (is (= 3 (ctx/messages-remaining {:max-messages 5 :messages [{} {}]}))))\n\n'),
    write(S, '(deftest test-context-word-budget\n'),
    write(S, '  (is (= -1 (ctx/word-budget {:max-words 0 :token-count 0})))\n'),
    write(S, '  (is (= -1 (ctx/word-budget {:max-words -5 :token-count 10})))\n'),
    write(S, '  (is (= 80 (ctx/word-budget {:max-words 100 :token-count 20}))))\n\n'),
    write(S, '(deftest test-is-full\n'),
    write(S, '  (is (false? (ctx/is-full {:max-messages 0 :messages []})))\n'),
    write(S, '  (is (true? (ctx/is-full {:max-messages 2 :messages [{} {}]}))))\n\n'),
    write(S, '(deftest test-context-char-budget\n'),
    write(S, '  (is (= -1 (ctx/char-budget {:max-chars 0 :token-count 0})))\n'),
    write(S, '  (is (= 80 (ctx/char-budget {:max-chars 100 :token-count 20}))))\n\n'),
    write(S, '(deftest test-context-has-room\n'),
    write(S, '  (is (true? (ctx/has-room {:max-messages 0 :messages []})))\n'),
    write(S, '  (is (true? (ctx/has-room {:max-messages 5 :messages [{} {}]})))\n'),
    write(S, '  (is (false? (ctx/has-room {:max-messages 2 :messages [{} {}]}))))\n\n'),
    write(S, '(deftest test-context-is-near-full\n'),
    write(S, '  (is (false? (ctx/is-near-full {:max-messages 0 :messages []} 80)))\n'),
    write(S, '  (is (true? (ctx/is-near-full {:max-messages 10 :messages [{} {} {} {} {} {} {} {} {}]} 80))))\n\n'),
    write(S, '(deftest test-context-usage-pct\n'),
    write(S, '  (is (= 0.0 (ctx/usage-pct {:max-messages 0 :messages []})))\n'),
    write(S, '  (is (= 50.0 (ctx/usage-pct {:max-messages 10 :messages [{} {} {} {} {}]}))))\n\n'),
    write(S, '(deftest test-is-continue-mode\n'),
    write(S, '  (is (true? (ctx/is-continue-mode {:context-mode "continue"})))\n'),
    write(S, '  (is (false? (ctx/is-continue-mode {:context-mode "sliding"}))))\n\n'),
    write(S, '(deftest test-is-sliding-mode\n'),
    write(S, '  (is (true? (ctx/is-sliding-mode {:context-mode "sliding"})))\n'),
    write(S, '  (is (false? (ctx/is-sliding-mode {:context-mode "continue"}))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/context_test.clj~n', []).

%% --- ToolResultCache tests ---
generate_clojure_tool_cache_test(Dir) :-
    atom_concat(Dir, 'tool_cache_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.tool-cache-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.tool-cache :as cache]))\n\n'),
    write(S, '(deftest test-create-cache\n'),
    write(S, '  (let [state (cache/create-tool-cache)]\n'),
    write(S, '    (is (= {} (:cache state)))\n'),
    write(S, '    (is (= 100 (:max-size state)))))\n\n'),
    write(S, '(deftest test-cache-clear\n'),
    write(S, '  (let [state {:cache {"k1" "v1"} :max-size 100}\n'),
    write(S, '        cleared (cache/clear state)]\n'),
    write(S, '    (is (= {} (:cache cleared)))))\n\n'),
    write(S, '(deftest test-should-skip\n'),
    write(S, '  (let [state {:cache {} :max-size 100 :skip-tools #{"bash" "write"}}]\n'),
    write(S, '    (is (true? (cache/should-skip state "bash")))\n'),
    write(S, '    (is (false? (cache/should-skip state "read")))))\n\n'),
    write(S, '(deftest test-cache-len\n'),
    write(S, '  (is (= 0 (cache/len {:cache {}})))\n'),
    write(S, '  (is (= 2 (cache/len {:cache {"a" 1 "b" 2}}))))\n\n'),
    write(S, '(deftest test-is-empty-cache\n'),
    write(S, '  (is (true? (cache/is-empty-cache {:cache {}})))\n'),
    write(S, '  (is (false? (cache/is-empty-cache {:cache {"k" "v"}}))))\n\n'),
    write(S, '(deftest test-cache-has-key\n'),
    write(S, '  (is (true? (cache/has-key {:cache {"bash_ls" "result"}} "bash_ls")))\n'),
    write(S, '  (is (false? (cache/has-key {:cache {}} "bash_ls"))))\n\n'),
    write(S, '(deftest test-make-key\n'),
    write(S, '  (let [key (cache/make-key {:cache {}} "bash" {"cmd" "ls -la"})]\n'),
    write(S, '    (is (string? key))\n'),
    write(S, '    (is (pos? (count key)))))\n\n'),
    write(S, '(deftest test-evict-oldest\n'),
    write(S, '  (is (= 0 (cache/evict-oldest {:cache {} :max-size 100})))\n'),
    write(S, '  (is (= 1 (cache/evict-oldest {:cache {"a" 1 "b" 2} :max-size 2}))))\n\n'),
    write(S, '(deftest test-cache-hit-rate\n'),
    write(S, '  (is (= 0.0 (cache/cache-hit-rate {:hits 0 :total-lookups 0})))\n'),
    write(S, '  (is (= 0.5 (cache/cache-hit-rate {:hits 5 :total-lookups 10}))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/tool_cache_test.clj~n', []).

%% --- Retry tests ---
generate_clojure_retry_test(Dir) :-
    atom_concat(Dir, 'retry_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.retry-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.retry :as retry]))\n\n'),
    write(S, '(deftest test-is-retryable-status\n'),
    write(S, '  (is (some? (retry/is-retryable-status 429)))\n'),
    write(S, '  (is (some? (retry/is-retryable-status 503)))\n'),
    write(S, '  (is (nil? (retry/is-retryable-status 200)))\n'),
    write(S, '  (is (nil? (retry/is-retryable-status 404))))\n\n'),
    write(S, '(deftest test-compute-delay\n'),
    write(S, '  (let [delay (retry/compute-delay 1.0 2.0 1 60.0)]\n'),
    write(S, '    (is (= 1.0 delay)))\n'),
    write(S, '  (let [delay (retry/compute-delay 1.0 2.0 3 60.0)]\n'),
    write(S, '    (is (= 4.0 delay))))\n\n'),
    write(S, '(deftest test-is-retryable-error\n'),
    write(S, '  (is (retry/is-retryable-error 429))\n'),
    write(S, '  (is (retry/is-retryable-error 500))\n'),
    write(S, '  (is (retry/is-retryable-error 503))\n'),
    write(S, '  (is (not (retry/is-retryable-error 200)))\n'),
    write(S, '  (is (not (retry/is-retryable-error 404))))\n\n'),
    write(S, '(deftest test-max-retries-reached\n'),
    write(S, '  (is (true? (retry/max-retries-reached {:attempt 3 :max-retries 3})))\n'),
    write(S, '  (is (false? (retry/max-retries-reached {:attempt 1 :max-retries 3}))))\n\n'),
    write(S, '(deftest test-is-first-attempt\n'),
    write(S, '  (is (true? (retry/is-first-attempt 0)))\n'),
    write(S, '  (is (false? (retry/is-first-attempt 1))))\n\n'),
    write(S, '(deftest test-attempts-left\n'),
    write(S, '  (is (= 2 (retry/attempts-left {:max-retries 3 :attempt 1})))\n'),
    write(S, '  (is (= 0 (retry/attempts-left {:max-retries 3 :attempt 3}))))\n\n'),
    write(S, '(deftest test-delay-exceeds-max\n'),
    write(S, '  (is (true? (retry/delay-exceeds-max 120.0 60.0)))\n'),
    write(S, '  (is (false? (retry/delay-exceeds-max 30.0 60.0))))\n\n'),
    write(S, '(deftest test-is-last-attempt\n'),
    write(S, '  (is (true? (retry/is-last-attempt {:attempt 2 :max-retries 3})))\n'),
    write(S, '  (is (false? (retry/is-last-attempt {:attempt 0 :max-retries 3}))))\n\n'),
    write(S, '(deftest test-retry-total-attempts\n'),
    write(S, '  (is (= 1 (retry/total-attempts {:attempt 0})))\n'),
    write(S, '  (is (= 4 (retry/total-attempts {:attempt 3})))\n'),
    write(S, '  (is (= 6 (retry/total-attempts {:attempt 5}))))\n\n'),
    write(S, '(deftest test-retry-should-give-up\n'),
    write(S, '  (is (true? (retry/should-give-up 5 5)))\n'),
    write(S, '  (is (true? (retry/should-give-up 10 5)))\n'),
    write(S, '  (is (false? (retry/should-give-up 2 5))))\n\n'),
    write(S, '(deftest test-retry-total-wait\n'),
    write(S, '  (is (= 0.0 (retry/total-wait 1.0 0)))\n'),
    write(S, '  (is (= 3.0 (retry/total-wait 1.5 2)))\n'),
    write(S, '  (is (= 10.0 (retry/total-wait 2.0 5))))\n\n'),
    write(S, '(deftest test-retry-is-fresh\n'),
    write(S, '  (is (true? (retry/is-fresh {:attempt 0})))\n'),
    write(S, '  (is (false? (retry/is-fresh {:attempt 1}))))\n\n'),
    write(S, '(deftest test-retry-has-delay\n'),
    write(S, '  (is (true? (retry/has-delay {:base-delay 1.0})))\n'),
    write(S, '  (is (false? (retry/has-delay {:base-delay 0.0}))))\n\n'),
    write(S, '(deftest test-delay-remaining\n'),
    write(S, '  (is (= 0.0 (retry/delay-remaining 100.0 50.0)))\n'),
    write(S, '  (is (= 50.0 (retry/delay-remaining 50.0 100.0))))\n\n'),
    write(S, '(deftest test-is-worthwhile\n'),
    write(S, '  (is (true? (retry/is-worthwhile 0.5)))\n'),
    write(S, '  (is (false? (retry/is-worthwhile 0.05))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/retry_test.clj~n', []).

%% --- Tools tests ---
generate_clojure_tools_test(Dir) :-
    atom_concat(Dir, 'tools_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.tools-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.tools :as tools]))\n\n'),
    write(S, '(deftest test-is-destructive\n'),
    write(S, '  (is (tools/is-destructive "bash"))\n'),
    write(S, '  (is (tools/is-destructive "write"))\n'),
    write(S, '  (is (not (tools/is-destructive "read"))))\n\n'),
    write(S, '(deftest test-is-mcp-tool\n'),
    write(S, '  (is (true? (tools/is-mcp-tool "mcp:server/tool")))\n'),
    write(S, '  (is (false? (tools/is-mcp-tool "read"))))\n\n'),
    write(S, '(deftest test-is-builtin\n'),
    write(S, '  (is (true? (tools/is-builtin "read")))\n'),
    write(S, '  (is (true? (tools/is-builtin "bash")))\n'),
    write(S, '  (is (false? (tools/is-builtin "mcp__server__tool"))))\n\n'),
    write(S, '(deftest test-needs-path-validation\n'),
    write(S, '  (is (true? (tools/needs-path-validation "read")))\n'),
    write(S, '  (is (true? (tools/needs-path-validation "write")))\n'),
    write(S, '  (is (true? (tools/needs-path-validation "edit")))\n'),
    write(S, '  (is (false? (tools/needs-path-validation "bash"))))\n\n'),
    write(S, '(deftest test-tool-category\n'),
    write(S, '  (is (string? (tools/tool-category "bash"))))\n\n'),
    write(S, '(deftest test-has-schema\n'),
    write(S, '  (is (true? (tools/has-schema {:schema {:type "object"}} "bash")))\n'),
    write(S, '  (is (false? (tools/has-schema {:schema {}} "bash"))))\n\n'),
    write(S, '(deftest test-is-safe\n'),
    write(S, '  (is (true? (tools/is-safe "read")))\n'),
    write(S, '  (is (false? (tools/is-safe "bash"))))\n\n'),
    write(S, '(deftest test-is-mcp-prefixed\n'),
    write(S, '  (is (true? (tools/is-mcp-prefixed "mcp:read")))\n'),
    write(S, '  (is (false? (tools/is-mcp-prefixed "bash"))))\n\n'),
    write(S, '(deftest test-name-is-valid\n'),
    write(S, '  (is (true? (tools/name-is-valid "bash")))\n'),
    write(S, '  (is (false? (tools/name-is-valid ""))))\n\n'),
    write(S, '(deftest test-is-readonly\n'),
    write(S, '  (is (true? (tools/is-readonly "read")))\n'),
    write(S, '  (is (true? (tools/is-readonly "glob")))\n'),
    write(S, '  (is (false? (tools/is-readonly "bash"))))\n\n'),
    write(S, '(deftest test-tool-count\n'),
    write(S, '  (is (= 0 (tools/tool-count {:schema {}})))\n'),
    write(S, '  (is (= 2 (tools/tool-count {:schema {"bash" {} "read" {}}})))\n'),
    write(S, '  (is (= 3 (tools/tool-count {:schema {"a" {} "b" {} "c" {}}}))))\n\n'),
    write(S, '(deftest test-requires-confirm\n'),
    write(S, '  (is (true? (tools/requires-confirm "bash")))\n'),
    write(S, '  (is (true? (tools/requires-confirm "write")))\n'),
    write(S, '  (is (false? (tools/requires-confirm "read"))))\n\n'),
    write(S, '(deftest test-tool-safe-count\n'),
    write(S, '  (is (= 0 (tools/safe-count {:args []})))\n'),
    write(S, '  (is (= 3 (tools/safe-count {:args ["read" "glob" "grep"]}))))\n\n'),
    write(S, '(deftest test-tool-is-write-op\n'),
    write(S, '  (is (true? (tools/is-write-op "write")))\n'),
    write(S, '  (is (true? (tools/is-write-op "edit")))\n'),
    write(S, '  (is (false? (tools/is-write-op "read"))))\n\n'),
    write(S, '(deftest test-tool-is-bash\n'),
    write(S, '  (is (true? (tools/is-bash "bash")))\n'),
    write(S, '  (is (false? (tools/is-bash "read"))))\n\n'),
    write(S, '(deftest test-tool-is-edit\n'),
    write(S, '  (is (true? (tools/is-edit "edit")))\n'),
    write(S, '  (is (false? (tools/is-edit "bash"))))\n\n'),
    write(S, '(deftest test-is-read\n'),
    write(S, '  (is (true? (tools/is-read "read")))\n'),
    write(S, '  (is (false? (tools/is-read "bash"))))\n\n'),
    write(S, '(deftest test-is-write\n'),
    write(S, '  (is (true? (tools/is-write "write")))\n'),
    write(S, '  (is (false? (tools/is-write "read"))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/tools_test.clj~n', []).

%% --- Streaming tests ---
generate_clojure_streaming_test(Dir) :-
    atom_concat(Dir, 'streaming_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.streaming-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is]]\n'),
    write(S, '            [agent-loop.streaming :as streaming]))\n\n'),
    write(S, '(deftest test-create-counter\n'),
    write(S, '  (let [state (streaming/create-streaming-counter)]\n'),
    write(S, '    (is (= 0 (:token-count state)))\n'),
    write(S, '    (is (= 0 (:char-count state)))\n'),
    write(S, '    (is (false? (:show-live state)))))\n\n'),
    write(S, '(deftest test-is-live\n'),
    write(S, '  (is (false? (streaming/is-live {:show-live false})))\n'),
    write(S, '  (is (true? (streaming/is-live {:show-live true}))))\n\n'),
    write(S, '(deftest test-is-idle\n'),
    write(S, '  (is (true? (streaming/is-idle {:token-count 0})))\n'),
    write(S, '  (is (false? (streaming/is-idle {:token-count 5}))))\n\n'),
    write(S, '(deftest test-streaming-char-count\n'),
    write(S, '  (is (= 0 (streaming/streaming-char-count {:char-count 0})))\n'),
    write(S, '  (is (= 42 (streaming/streaming-char-count {:char-count 42}))))\n\n'),
    write(S, '(deftest test-streaming-token-count\n'),
    write(S, '  (is (= 0 (streaming/streaming-token-count {:token-count 0})))\n'),
    write(S, '  (is (= 10 (streaming/streaming-token-count {:token-count 10}))))\n\n'),
    write(S, '(deftest test-is-active\n'),
    write(S, '  (is (true? (streaming/is-active {:token-count 1 :char-count 5})))\n'),
    write(S, '  (is (false? (streaming/is-active {:token-count 0 :char-count 0}))))\n\n'),
    write(S, '(deftest test-chunk-is-complete\n'),
    write(S, '  (is (streaming/chunk-is-complete "data: hello"))\n'),
    write(S, '  (is (not (streaming/chunk-is-complete "partial"))))\n\n'),
    write(S, '(deftest test-avg-token-rate\n'),
    write(S, '  (is (= 0.0 (streaming/avg-token-rate {:token-count 100 :elapsed 0})))\n'),
    write(S, '  (is (= 50.0 (streaming/avg-token-rate {:token-count 100 :elapsed 2.0}))))\n\n'),
    write(S, '(deftest test-streaming-is-active\n'),
    write(S, '  (is (true? (streaming/is-active {:token-count 5 :char-count 0})))\n'),
    write(S, '  (is (false? (streaming/is-active {:token-count 0 :char-count 0}))))\n\n'),
    write(S, '(deftest test-chars-per-token\n'),
    write(S, '  (is (= 0.0 (streaming/chars-per-token {:char-count 0 :token-count 0})))\n'),
    write(S, '  (is (= 4.0 (streaming/chars-per-token {:char-count 40 :token-count 10}))))\n\n'),
    write(S, '(deftest test-progress-pct\n'),
    write(S, '  (is (= 0.0 (streaming/progress-pct {:token-count 50} 0)))\n'),
    write(S, '  (is (= 50.0 (streaming/progress-pct {:token-count 50} 100))))\n\n'),
    write(S, '(deftest test-streaming-tokens-remaining\n'),
    write(S, '  (is (= -1 (streaming/tokens-remaining {:token-count 10} 0)))\n'),
    write(S, '  (is (= 80 (streaming/tokens-remaining {:token-count 20} 100)))\n'),
    write(S, '  (is (= 0 (streaming/tokens-remaining {:token-count 50} 50))))\n\n'),
    write(S, '(deftest test-has-started\n'),
    write(S, '  (is (false? (streaming/has-started {:token-count 0})))\n'),
    write(S, '  (is (true? (streaming/has-started {:token-count 1}))))\n\n'),
    write(S, '(deftest test-streaming-exceeds-limit\n'),
    write(S, '  (is (true? (streaming/exceeds-limit {:token-count 150} 100)))\n'),
    write(S, '  (is (false? (streaming/exceeds-limit {:token-count 50} 100))))\n\n'),
    write(S, '(deftest test-streaming-is-waiting\n'),
    write(S, '  (is (true? (streaming/is-waiting {:token-count 0 :char-count 0})))\n'),
    write(S, '  (is (false? (streaming/is-waiting {:token-count 1 :char-count 0})))\n'),
    write(S, '  (is (false? (streaming/is-waiting {:token-count 0 :char-count 5}))))\n\n'),
    write(S, '(deftest test-streaming-has-elapsed\n'),
    write(S, '  (is (true? (streaming/has-elapsed {:elapsed 1.0})))\n'),
    write(S, '  (is (false? (streaming/has-elapsed {:elapsed 0.0}))))\n\n'),
    write(S, '(deftest test-streaming-is-balanced\n'),
    write(S, '  (is (true? (streaming/is-balanced {:char-count 10 :token-count 5})))\n'),
    write(S, '  (is (false? (streaming/is-balanced {:char-count 3 :token-count 10}))))\n\n'),
    write(S, '(deftest test-has-elapsed\n'),
    write(S, '  (is (true? (streaming/has-elapsed {:elapsed 1.0})))\n'),
    write(S, '  (is (false? (streaming/has-elapsed {:elapsed 0.0}))))\n\n'),
    write(S, '(deftest test-is-balanced\n'),
    write(S, '  (is (true? (streaming/is-balanced {:char-count 10 :token-count 5})))\n'),
    write(S, '  (is (false? (streaming/is-balanced {:char-count 3 :token-count 10}))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/streaming_test.clj~n', []).

%% --- Pricing tests ---
generate_clojure_pricing_test(Dir) :-
    atom_concat(Dir, 'pricing_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.pricing-test\n'),
