    write(S, '  (is (nil? (pricing/lookup "nonexistent-model-xyz"))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/pricing_test.clj~n', []).

%% --- Config tests ---
generate_clojure_config_test(Dir) :-
    atom_concat(Dir, 'config_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.config-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.config :as config]))\n\n'),
    write(S, '(deftest test-default-config-exists\n'),
    write(S, '  (is (map? config/default-config)))\n\n'),
    write(S, '(deftest test-search-paths-exist\n'),
    write(S, '  (is (pos? (count config/config-search-paths))))\n\n'),
    write(S, '(deftest test-api-key-env-vars\n'),
    write(S, '  (is (map? config/api-key-env-vars))\n'),
    write(S, '  (is (string? (get config/api-key-env-vars :openai)))\n'),
    write(S, '  (is (string? (get config/api-key-env-vars :claude))))\n\n'),
    write(S, '(deftest test-has-key\n'),
    write(S, '  (is (true? (config/has-key {:settings {:model "gpt-4"}} :model)))\n'),
    write(S, '  (is (false? (config/has-key {:settings {}} :model))))\n\n'),
    write(S, '(deftest test-is-debug\n'),
    write(S, '  (is (config/is-debug {:debug "true"}))\n'),
    write(S, '  (is (not (config/is-debug {:debug "false"}))))\n\n'),
    write(S, '(deftest test-config-has-field\n'),
    write(S, '  (is (true? (config/config-has-field {:model "gpt-4"} :model)))\n'),
    write(S, '  (is (false? (config/config-has-field {} :nonexistent))))\n\n'),
    write(S, '(deftest test-config-merge\n'),
    write(S, '  (is (= "new-val" (config/merge {:settings {"k" "old"}} "k" "new-val")))\n'),
    write(S, '  (is (= "old" (config/merge {:settings {"k" "old"}} "k" ""))))\n\n'),
    write(S, '(deftest test-config-field-count\n'),
    write(S, '  (is (= 2 (config/field-count {:settings {:a 1 :b 2}}))))\n\n'),
    write(S, '(deftest test-config-is-empty\n'),
    write(S, '  (is (true? (config/is-empty {:settings {}})))\n'),
    write(S, '  (is (false? (config/is-empty {:settings {:a 1}}))))\n\n'),
    write(S, '(deftest test-config-is-default-backend\n'),
    write(S, '  (is (true? (config/is-default-backend {:settings {}})))\n'),
    write(S, '  (is (true? (config/is-default-backend {:settings {"model" "gpt-4"}})))\n'),
    write(S, '  (is (false? (config/is-default-backend {:settings {"backend" "openai"}}))))\n\n'),
    write(S, '(deftest test-key-count\n'),
    write(S, '  (is (= 0 (config/key-count {:settings {}})))\n'),
    write(S, '  (is (= 2 (config/key-count {:settings {:a 1 :b 2}}))))\n\n'),
    write(S, '(deftest test-config-has-backend\n'),
    write(S, '  (is (true? (config/has-backend {:settings {"backend" "openai"}})))\n'),
    write(S, '  (is (false? (config/has-backend {:settings {"model" "gpt-4"}}))))\n\n'),
    write(S, '(deftest test-config-is-production\n'),
    write(S, '  (is (true? (config/is-production {:debug "false"})))\n'),
    write(S, '  (is (false? (config/is-production {:debug "true"}))))\n\n'),
    write(S, '(deftest test-config-has-model\n'),
    write(S, '  (is (true? (config/has-model {:settings {"model" "gpt-4"}})))\n'),
    write(S, '  (is (false? (config/has-model {:settings {}}))))\n\n'),
    write(S, '(deftest test-config-has-api-key\n'),
    write(S, '  (is (true? (config/has-api-key {:settings {"api_key" "sk-123"}})))\n'),
    write(S, '  (is (false? (config/has-api-key {:settings {}}))))\n\n'),
    write(S, '(deftest test-has-stream\n'),
    write(S, '  (is (true? (config/has-stream {:settings {"stream" "true"}})))\n'),
    write(S, '  (is (false? (config/has-stream {:settings {}}))))\n\n'),
    write(S, '(deftest test-has-max-tokens\n'),
