%% --- Security tests ---
generate_clojure_security_test(Dir) :-
    atom_concat(Dir, 'security_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.security-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.security :as security]))\n\n'),
    write(S, '(deftest test-is-path-safe\n'),
    write(S, '  (is (true? (security/is-path-safe "src/main.rs")))\n'),
    write(S, '  (is (false? (security/is-path-safe "../../etc/passwd"))))\n\n'),
    write(S, '(deftest test-is-visible-file\n'),
    write(S, '  (is (true? (security/is-visible-file "main.rs")))\n'),
    write(S, '  (is (false? (security/is-visible-file ".env"))))\n\n'),
    write(S, '(deftest test-profiles-exist\n'),
    write(S, '  (is (pos? (count security/profiles))))\n\n'),
    write(S, '(deftest test-blocked-paths-exist\n'),
    write(S, '  (is (pos? (count security/blocked-paths))))\n\n'),
    write(S, '(deftest test-path-blocked\n'),
    write(S, '  (is (some? (security/path-blocked? "/etc/shadow")))\n'),
    write(S, '  (is (not (security/path-blocked? "src/main.rs"))))\n\n'),
    write(S, '(deftest test-is-hidden-path\n'),
    write(S, '  (is (true? (security/is-hidden-path ".git")))\n'),
    write(S, '  (is (false? (security/is-hidden-path "src"))))\n\n'),
    write(S, '(deftest test-has-path-traversal\n'),
    write(S, '  (is (true? (security/has-path-traversal "..")))\n'),
    write(S, '  (is (true? (security/has-path-traversal "../etc")))\n'),
    write(S, '  (is (false? (security/has-path-traversal "src/main"))))\n\n'),
    write(S, '(deftest test-is-safe-command\n'),
    write(S, '  (is (true? (security/is-safe-command "ls -la")))\n'),
    write(S, '  (is (true? (security/is-safe-command "cat file.txt")))\n'),
    write(S, '  (is (false? (security/is-safe-command "rm -rf /"))))\n\n'),
    write(S, '(deftest test-is-blocked-command\n'),
    write(S, '  (is (true? (security/is-blocked-command "rm -rf /")))\n'),
    write(S, '  (is (true? (security/is-blocked-command "dd if=/dev/zero")))\n'),
    write(S, '  (is (true? (security/is-blocked-command "mkfs.ext4 /dev/sda")))\n'),
    write(S, '  (is (false? (security/is-blocked-command "ls -la"))))\n\n'),
    write(S, '(deftest test-is-writable-path\n'),
    write(S, '  (is (true? (security/is-writable-path "/home/user/file.txt")))\n'),
    write(S, '  (is (true? (security/is-writable-path "/tmp/scratch")))\n'),
    write(S, '  (is (false? (security/is-writable-path "/etc/passwd")))\n'),
    write(S, '  (is (false? (security/is-writable-path "/usr/bin/cat")))\n'),
    write(S, '  (is (false? (security/is-writable-path "/bin/sh"))))\n\n'),
    write(S, '(deftest test-needs-audit\n'),
    write(S, '  (is (true? (security/needs-audit "paranoid")))\n'),
    write(S, '  (is (true? (security/needs-audit "guarded")))\n'),
    write(S, '  (is (false? (security/needs-audit "open"))))\n\n'),
    write(S, '(deftest test-allows-auto\n'),
    write(S, '  (is (true? (security/allows-auto "open")))\n'),
    write(S, '  (is (false? (security/allows-auto "paranoid"))))\n\n'),
    write(S, '(deftest test-security-profile-count\n'),
    write(S, '  (is (= 3 (security/profile-count 3)))\n'),
    write(S, '  (is (= 0 (security/profile-count 0))))\n\n'),
    write(S, '(deftest test-security-is-home-path\n'),
    write(S, '  (is (true? (security/is-home-path "/home/user/file.txt")))\n'),
    write(S, '  (is (true? (security/is-home-path "/data/data/com.termux/files")))\n'),
    write(S, '  (is (false? (security/is-home-path "/etc/passwd"))))\n\n'),
    write(S, '(deftest test-security-has-pipe\n'),
    write(S, '  (is (true? (security/has-pipe "| cat")))\n'),
    write(S, '  (is (false? (security/has-pipe "ls"))))\n\n'),
    write(S, '(deftest test-security-is-absolute-path\n'),
    write(S, '  (is (true? (security/is-absolute-path "/usr/bin")))\n'),
    write(S, '  (is (false? (security/is-absolute-path "src"))))\n\n'),
    write(S, '(deftest test-is-safe-extension\n'),
    write(S, '  (is (true? (security/is-safe-extension "main.rs")))\n'),
    write(S, '  (is (false? (security/is-safe-extension "run.sh"))))\n\n'),
    write(S, '(deftest test-is-network-cmd\n'),
    write(S, '  (is (true? (security/is-network-cmd "curl url")))\n'),
    write(S, '  (is (false? (security/is-network-cmd "ls"))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/security_test.clj~n', []).

%% --- Output parser tests ---
generate_clojure_output_parser_test(Dir) :-
    atom_concat(Dir, 'output_parser_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.output-parser-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [agent-loop.output-parser :as parser]))\n\n'),
    write(S, '(deftest test-is-json-object\n'),
    write(S, '  (is (true? (parser/is-json-object "{:key 1}")))\n'),
    write(S, '  (is (false? (parser/is-json-object "hello"))))\n\n'),
    write(S, '(deftest test-is-json-content\n'),
    write(S, '  (is (true? (parser/is-json-content "{:key 1}")))\n'),
    write(S, '  (is (true? (parser/is-json-content "[1, 2, 3]")))\n'),
    write(S, '  (is (false? (parser/is-json-content "hello"))))\n\n'),
    write(S, '(deftest test-content-length\n'),
    write(S, '  (is (= 5 (parser/content-length "hello")))\n'),
    write(S, '  (is (= 0 (parser/content-length ""))))\n\n'),
    write(S, '(deftest test-strip-content\n'),
    write(S, '  (is (= "hello" (parser/strip-content "  hello  "))))\n\n'),
    write(S, '(deftest test-is-empty-response\n'),
    write(S, '  (is (true? (parser/is-empty-response "")))\n'),
    write(S, '  (is (true? (parser/is-empty-response "   ")))\n'),
    write(S, '  (is (false? (parser/is-empty-response "hello"))))\n\n'),
    write(S, '(deftest test-content-exceeds-length\n'),
    write(S, '  (is (true? (parser/content-exceeds-length "hello world" 5)))\n'),
    write(S, '  (is (false? (parser/content-exceeds-length "hi" 5))))\n\n'),
    write(S, '(deftest test-content-is-json\n'),
    write(S, '  (is (true? (parser/content-is-json "{key: 1}")))\n'),
    write(S, '  (is (true? (parser/content-is-json "[1,2,3]")))\n'),
    write(S, '  (is (false? (parser/content-is-json "hello"))))\n\n'),
    write(S, '(deftest test-content-preview\n'),
    write(S, '  (is (= "hi" (parser/content-preview "hi" 10)))\n'),
    write(S, '  (is (string? (parser/content-preview "hello world this is long" 5))))\n\n'),
    write(S, '(deftest test-is-multiline\n'),
    write(S, '  (is (true? (parser/is-multiline "hello world this is long" 5)))\n'),
    write(S, '  (is (false? (parser/is-multiline "hi" 10))))\n\n'),
    write(S, '(deftest test-output-has-code-block\n'),
    write(S, '  (is (true? (parser/has-code-block "```python\\nprint(1)\\n```")))\n'),
    write(S, '  (is (false? (parser/has-code-block "no code here"))))\n\n'),
    write(S, '(deftest test-output-is-short\n'),
    write(S, '  (is (true? (parser/is-short "hi" 10)))\n'),
    write(S, '  (is (false? (parser/is-short "hello world foo bar" 5))))\n\n'),
    write(S, '(deftest test-output-is-blank\n'),
    write(S, '  (is (true? (parser/is-blank "")))\n'),
    write(S, '  (is (true? (parser/is-blank "   ")))\n'),
    write(S, '  (is (false? (parser/is-blank "hello"))))\n\n'),
    write(S, '(deftest test-output-has-json-array\n'),
    write(S, '  (is (true? (parser/has-json-array "[1,2]")))\n'),
    write(S, '  (is (false? (parser/has-json-array "{}"))))\n\n'),
    write(S, '(deftest test-is-markdown\n'),
    write(S, '  (is (true? (parser/is-markdown "# heading")))\n'),
    write(S, '  (is (false? (parser/is-markdown "plain"))))\n\n'),
    write(S, '(deftest test-exceeds-limit\n'),
    write(S, '  (is (true? (parser/exceeds-limit "hello world" 5)))\n'),
    write(S, '  (is (false? (parser/exceeds-limit "hi" 10))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/output_parser_test.clj~n', []).

