    write(S, '  (is (false? (mcp/is-tool-call "notifications/ready"))))\n\n'),
    write(S, '(deftest test-mcp-server-name\n'),
    write(S, '  (is (= "my-server" (mcp/server-name {:name "my-server"}))))\n\n'),
    write(S, '(deftest test-format-error\n'),
    write(S, '  (is (= "error 404: not found" (mcp/format-error 404 "not found"))))\n\n'),
    write(S, '(deftest test-mcp-request-count\n'),
    write(S, '  (is (= 0 (mcp/request-count {:request-id 0})))\n'),
    write(S, '  (is (= 5 (mcp/request-count {:request-id 5})))\n'),
    write(S, '  (is (= 42 (mcp/request-count {:request-id 42}))))\n\n'),
    write(S, '(deftest test-has-clients\n'),
    write(S, '  (is (false? (mcp/has-clients {:clients {}})))\n'),
    write(S, '  (is (true? (mcp/has-clients {:clients {"srv1" {:name "s1"}}}))))\n\n'),
    write(S, '(deftest test-mcp-total-tools\n'),
    write(S, '  (is (= 0 (mcp/total-tools {:tools []})))\n'),
    write(S, '  (is (= 3 (mcp/total-tools {:tools ["a" "b" "c"]}))))\n\n'),
