    close(S),
    format('  Generated clojure/test/agent_loop/mcp_test.clj~n', []).

%% --- Property-based tests (test.check) ---
generate_clojure_property_test(Dir) :-
    atom_concat(Dir, 'property_test.clj', Path),
    open(Path, write, S),
    write(S, '(ns agent-loop.property-test\n'),
    write(S, '  (:require [clojure.test :refer [deftest is testing]]\n'),
    write(S, '            [clojure.test.check :as tc]\n'),
    write(S, '            [clojure.test.check.generators :as gen]\n'),
    write(S, '            [clojure.test.check.properties :as prop]\n'),
    write(S, '            [clojure.test.check.clojure-test :refer [defspec]]\n'),
    write(S, '            [agent-loop.costs :as costs]\n'),
    write(S, '            [agent-loop.context :as ctx]\n'),
    write(S, '            [agent-loop.retry :as retry]\n'),
    write(S, '            [agent-loop.streaming :as streaming]\n'),
    write(S, '            [agent-loop.sessions :as sessions]\n'),
    write(S, '            [agent-loop.security :as security]\n'),
    write(S, '            [agent-loop.tools :as tools]))\n\n'),
    %% --- Budget invariant: remaining + spent = budget ---
    write(S, '(defspec budget-remaining-clamped 50\n'),
    write(S, '  (prop/for-all [budget (gen/double* {:min 0.01 :max 1000.0 :NaN? false :infinite? false})\n'),
    write(S, '                 cost (gen/double* {:min 0.0 :max 500.0 :NaN? false :infinite? false})]\n'),
    write(S, '    (let [state {:total-cost cost}\n'),
    write(S, '          remaining (costs/budget-remaining state budget)]\n'),
    write(S, '      (and (>= remaining 0.0)\n'),
    write(S, '           (<= remaining budget)))))\n\n'),
    %% --- Cost compute is always non-negative ---
    write(S, '(defspec cost-compute-non-negative 50\n'),
    write(S, '  (prop/for-all [tokens (gen/choose 0 100000)\n'),
    write(S, '                 price (gen/double* {:min 0.0 :max 100.0 :NaN? false :infinite? false})]\n'),
    write(S, '    (>= (costs/cost-compute tokens price) 0.0)))\n\n'),
    %% --- Input ratio + output ratio = 1.0 (when tokens > 0) ---
    write(S, '(defspec input-output-ratio-sum 50\n'),
    write(S, '  (prop/for-all [input (gen/choose 1 10000)\n'),
    write(S, '                 output (gen/choose 1 10000)]\n'),
    write(S, '    (let [state {:total-input-tokens input :total-output-tokens output}\n'),
    write(S, '          ir (costs/input-ratio state)\n'),
    write(S, '          or_ (costs/output-ratio state)]\n'),
    write(S, '      (< (Math/abs (- (+ ir or_) 1.0)) 0.001))))\n\n'),
    %% --- Session age is always non-negative ---
    write(S, '(defspec session-age-non-negative 50\n'),
    write(S, '  (prop/for-all [created (gen/double* {:min 0.0 :max 1e9 :NaN? false :infinite? false})\n'),
    write(S, '                 now (gen/double* {:min 0.0 :max 1e9 :NaN? false :infinite? false})]\n'),
    write(S, '    (let [age (sessions/session-age created (max created now))]\n'),
    write(S, '      (>= age 0.0))))\n\n'),
    %% --- Retry delay is always positive for positive base ---
    write(S, '(defspec retry-delay-positive 50\n'),
    write(S, '  (prop/for-all [base (gen/double* {:min 0.1 :max 10.0 :NaN? false :infinite? false})\n'),
    write(S, '                 attempt (gen/choose 0 10)]\n'),
    write(S, '    (> (retry/exponential-delay base attempt) 0.0)))\n\n'),
    %% --- Token budget: unlimited returns -1 ---
    write(S, '(defspec token-budget-unlimited 50\n'),
    write(S, '  (prop/for-all [tokens (gen/choose 0 10000)]\n'),
    write(S, '    (= -1 (ctx/token-budget {:max-tokens 0 :token-count tokens}))))\n\n'),
    %% --- Safe and blocked commands are disjoint ---
    write(S, '(deftest safe-blocked-disjoint\n'),
    write(S, '  (testing "no command is both safe and blocked"\n'),
    write(S, '    (doseq [cmd ["ls" "cat file" "rm -rf /" "echo hi" "dd if=x" "grep p" "mkfs.ext4"]]\n'),
    write(S, '      (is (not (and (security/is-safe-command cmd) (security/is-blocked-command cmd)))))))\n\n'),
    %% --- Overflow count is always >= 0 ---
    write(S, '(defspec overflow-count-non-negative 50\n'),
    write(S, '  (prop/for-all [count (gen/choose 0 100)\n'),
    write(S, '                 limit (gen/choose 0 100)]\n'),
    write(S, '    (>= (sessions/overflow-count count limit) 0)))\n\n'),
    %% --- is_over_budget and is_under are complementary ---
    write(S, '(defspec budget-over-under-complementary 50\n'),
    write(S, '  (prop/for-all [cost (gen/double* {:min 0.0 :max 100.0 :NaN? false :infinite? false})\n'),
    write(S, '                 threshold (gen/double* {:min 0.01 :max 100.0 :NaN? false :infinite? false})]\n'),
    write(S, '    (let [state {:total-cost cost}]\n'),
    write(S, '      (or (costs/is-over-budget state threshold)\n'),
    write(S, '          (costs/is-under state threshold)\n'),
    write(S, '          (== cost threshold)))))\n'),
    close(S),
    format('  Generated clojure/test/agent_loop/property_test.clj~n', []).

%% generate_rust_command_dispatch(+Stream)
%% Emit command handler function from slash_command/4 facts.
generate_rust_command_dispatch(S) :-
    generate_rust_command_dispatch_with_sessions(S).

%% generate_rust_command_dispatch_with_sessions(+Stream)
%% Data-driven command handler — reads from rust_command_body/2 and slash_command/4.
generate_rust_command_dispatch_with_sessions(S) :-
    write(S, '/// Handle a slash command. Returns true if the command was handled.\n'),
    write(S, '/// Mutable runtime state that can be changed via slash commands.\n'),
    write(S, 'struct RuntimeState {\n'),
    write(S, '    max_iterations: i64,\n'),
    write(S, '    stream: bool,\n'),
    write(S, '    show_tokens: bool,\n'),
    write(S, '    multiline: bool,\n'),
    write(S, '    paste_mode: String,\n'),
    write(S, '}\n\n'),
    write(S, 'fn handle_command(\n'),
    write(S, '    input: &str,\n'),
    write(S, '    context: &mut ContextManager,\n'),
    write(S, '    cost_tracker: &CostTracker,\n'),
    write(S, '    session_manager: &SessionManager,\n'),
    write(S, '    backend_name: &str,\n'),
    write(S, '    state: &mut RuntimeState,\n'),
    write(S, '    config: &mut AgentConfig,\n'),
    write(S, ') -> bool {\n'),
    write(S, '    let parts: Vec<&str> = input.splitn(2, \' \').collect();\n'),
    write(S, '    let cmd = parts[0].trim_start_matches(\'/\');\n'),
    write(S, '    let _arg = if parts.len() > 1 { parts[1].trim() } else { "" };\n'),
    write(S, '    match cmd {\n'),
    %% Generate match arms from rust_command_body/2 facts
    slash_command_dispatch_order(Order),
    generate_rust_dispatch_arms(S, Order),
    %% Default catch-all
    write(S, '        _ => {\n'),
    write(S, '            println!("Unknown command: /{}", cmd);\n'),
    write(S, '            return false;\n'),
    write(S, '        }\n'),
    write(S, '    }\n'),
    write(S, '    true\n'),
    write(S, '}\n\n').

%% generate_rust_dispatch_arms(+Stream, +CommandNameList)
%% Emit match arms for each command, auto-wiring aliases from slash_command/4.
generate_rust_dispatch_arms(_, []).
generate_rust_dispatch_arms(S, [CmdName|Rest]) :-
    %% Determine the body key — most commands match by name,
    %% but 'delete' dispatches to 'drop' body (Rust uses /drop internally)
    (CmdName == delete -> BodyKey = drop ; BodyKey = CmdName),
    %% 'templates' dispatches to 'template' body
    (CmdName == templates -> BodyKey2 = template ; BodyKey2 = BodyKey),
    (rust_command_body(BodyKey2, Body) ->
        %% Build match pattern with aliases
        rust_cmd_match_pattern(CmdName, Pattern),
        format(S, '        ~w => {\n', [Pattern]),
        %% Emit body
        (Body == '%GENERATE_HELP%' ->
            generate_rust_help_text(S)
        ;
            maplist([Line]>>(format(S, '~w\n', [Line])), Body)
        ),
        format(S, '        }\n', [])
    ;
        %% No body for this command — skip with comment
        format(S, '        // ~w: no rust_command_body defined\n', [CmdName])
    ),
    generate_rust_dispatch_arms(S, Rest).

%% rust_cmd_match_pattern(+CmdName, -Pattern)
%% Build a Rust match pattern like "exit" | "quit" from slash_command aliases.
rust_cmd_match_pattern(CmdName, Pattern) :-
    atom_string(CmdName, CmdStr),
    (slash_command(CmdName, _, Props, _),
     member(aliases(Aliases), Props) ->
        maplist([A, QA]>>(atom_string(A, AS), format(atom(QA), '"~w"', [AS])), Aliases, QuotedAliases),
        format(atom(Primary), '"~w"', [CmdStr]),
        append([Primary], QuotedAliases, AllPatterns),
        atomic_list_concat(AllPatterns, ' | ', Pattern)
    ;
        format(atom(Pattern), '"~w"', [CmdStr])
    ).

%% generate_rust_clap_args(+Stream)
%% Emit clap Arg::new() calls from cli_argument/2 facts.
generate_rust_clap_args(S) :-
    findall(Name-Props, cli_argument(Name, Props), Args),
    maplist([Name-Props]>>(
        atom_string(Name, NameStr),
        format(S, '        .arg(clap::Arg::new("~w")', [NameStr]),
        %% Long flag (strip -- prefix)
        (member(long(Long), Props) ->
            (member(positional(true), Props) ->
                true  %% positional args don't get .long()
            ;
                atom_string(Long, LongStr),
                (sub_string(LongStr, 0, 2, _, "--") ->
                    sub_string(LongStr, 2, _, 0, LongName)
                ;
                    LongName = LongStr
                ),
                format(S, '~n            .long("~w")', [LongName])
            )
        ; true
        ),
        %% Short flag (strip - prefix)
        (member(short(Short), Props) ->
            atom_string(Short, ShortStr),
            (sub_string(ShortStr, 0, 1, _, "-") ->
                sub_string(ShortStr, 1, 1, 0, ShortChar)
            ;
                ShortChar = ShortStr
            ),
            format(S, '~n            .short(''~w'')', [ShortChar])
        ; true
        ),
        %% Help text
        (member(help(Help), Props) ->
            format(S, '~n            .help("~w")', [Help])
        ; true
        ),
        %% Default value (skip none)
        (member(default(Def), Props), Def \= none, Def \= [] ->
            term_to_atom(Def, DefAtom),
            format(S, '~n            .default_value("~w")', [DefAtom])
        ; true
        ),
        %% Choices
        (member(choices(Choices), Props) ->
            format(S, '~n            .value_parser([', []),
            rust_emit_choices_list(S, Choices),
            write(S, '])')
        ; true
        ),
        %% Action: store_true
        (member(action(store_true), Props) ->
            write(S, '\n            .action(clap::ArgAction::SetTrue)')
        ; true
        ),
        %% Nargs
        (member(nargs(Nargs), Props) ->
            (Nargs == '*' ->
                write(S, '\n            .num_args(0..)')
            ; Nargs == '?' ->
                write(S, '\n            .num_args(0..=1)')
            ; true
            )
        ; true
        ),
        %% Type: int
        (member(type(int), Props) ->
            write(S, '\n            .value_parser(clap::value_parser!(i64))')
        ; true
        ),
        %% Action: append
        (member(action(append), Props) ->
            write(S, '\n            .action(clap::ArgAction::Append)')
        ; true
        ),
        write(S, ')\n')
    ), Args).

%% Helper: emit comma-separated quoted choice list
rust_emit_choices_list(_, []).
rust_emit_choices_list(S, [C]) :- !,
    format(S, '"~w"', [C]).
rust_emit_choices_list(S, [C|Rest]) :-
    format(S, '"~w", ', [C]),
    rust_emit_choices_list(S, Rest).

%% generate_rust_cli_config_build(+Stream)
%% Emit code to build AgentConfig from clap matches.
generate_rust_cli_config_build(S) :-
    %% String overrides (str fields)
    maplist([Field-ArgName]>>(
        format(S, '    if let Some(v) = matches.get_one::<String>("~w") { config.~w = v.clone(); }~n', [ArgName, Field])
    ), [backend-backend]),
    %% Optional string overrides (str | None fields)
    maplist([Field-ArgName]>>(
        format(S, '    if let Some(v) = matches.get_one::<String>("~w") { config.~w = Some(v.clone()); }~n', [ArgName, Field])
    ), [model-model, api_key-api_key, system_prompt-system_prompt]),
    %% Bool flag overrides
    write(S, '    if matches.get_flag("auto_tools") { config.auto_tools = true; }\n'),
    write(S, '    if matches.get_flag("no_tokens") { config.show_tokens = false; }\n'),
    write(S, '    if matches.get_flag("stream_arg") { config.stream = true; }\n'),
    write(S, '    if matches.get_flag("no_security") { config.security_profile = "open".to_string(); }\n'),
    %% String overrides for security/approval
    maplist([Field-ArgName]>>(
        format(S, '    if let Some(v) = matches.get_one::<String>("~w") { config.~w = v.clone(); }~n', [ArgName, Field])
    ), [security_profile-security_profile, approval_mode-approval_mode]),
    %% Int overrides
    maplist([Field-ArgName]>>(
        format(S, '    if let Some(&v) = matches.get_one::<i64>("~w") { config.~w = v; }~n', [ArgName, Field])
    ), [max_iterations-max_iterations, max_context_tokens-max_tokens, max_chars-max_chars, max_words-max_words]),
    write(S, '\n').

