    write(S, 'def get_default_config() -> Config:\n'),
    write(S, '    """Get a default configuration with common presets."""\n'),
    write(S, '    config = Config()\n\n'),
    agent_loop_components:emit_config_section(S, default_presets, [target(python)]),
