    write(S, '_BLOCKED_COMMAND_PATTERNS = [\n'),
    agent_loop_components:emit_security_facts(S, [target(python), fact_type(blocked_command_pattern)]),
    write(S, ']\n\n\n'),
    %% is_command_blocked (imperative)
    write_py(S, tools_is_command_blocked),
