rust_fragment(context_manager, '

/// Manages conversation history with context modes and multi-limit trimming.
#[derive(Debug)]
pub struct ContextManager {
    pub messages: Vec<Message>,
    pub max_messages: usize,
    pub max_context_tokens: i64,
    pub max_tokens: i64,
    pub token_count: i64,
    pub max_chars: i64,
    pub max_words: i64,
    pub context_mode: String,
    undo_stack: Vec<Vec<Message>>,
}

impl Default for ContextManager {
    fn default() -> Self {
        Self {
            messages: Vec::new(),
            max_messages: 50,
            max_context_tokens: 100000,
            max_tokens: 100000,
            token_count: 0,
            max_chars: 0,
            max_words: 0,
            context_mode: "continue".to_string(),
            undo_stack: Vec::new(),
        }
    }
}

impl ContextManager {
    pub fn new(max_messages: usize, max_context_tokens: i64, max_chars: i64, max_words: i64, context_mode: &str) -> Self {
        Self {
            messages: Vec::new(),
            max_messages,
            max_context_tokens,
            max_tokens: max_context_tokens,
            token_count: 0,
            max_chars,
            max_words,
            context_mode: context_mode.to_string(),
            undo_stack: Vec::new(),
        }
    }

    /// Add a message to context. Returns number of old messages trimmed (0 if none).
    pub fn add_message(&mut self, role: &str, content: &str) -> usize {
        // Fresh mode: clear before each user message
        if self.context_mode == "fresh" && role == "user" {
            self.messages.clear();
        }
        self.messages.push(Message {
            role: role.to_string(),
            content: content.to_string(),
            tool_calls: None,
            tool_call_id: None,
        });
        self.trim_if_needed()
    }

    pub fn add_tool_call_message(&mut self, content: &str, tool_calls: Vec<ToolCall>) {
        self.messages.push(Message {
            role: "assistant".to_string(),
            content: content.to_string(),
            tool_calls: Some(tool_calls),
            tool_call_id: None,
        });
        self.trim_if_needed();
    }

    pub fn add_tool_result(&mut self, tool_call_id: &str, output: &str) {
        self.messages.push(Message {
            role: "tool".to_string(),
            content: output.to_string(),
            tool_calls: None,
            tool_call_id: Some(tool_call_id.to_string()),
        });
        self.trim_if_needed();
    }

    pub fn get_context(&self) -> &[Message] {
        &self.messages
    }

    pub fn get_messages(&self) -> &[Message] {
        &self.messages
    }

    /// Character count for a single message, including tool call estimates.
    fn message_char_count(m: &Message) -> usize {
        let mut n = m.content.len();
        if let Some(ref tcs) = m.tool_calls {
            for tc in tcs {
                n += 100; // base overhead: name + id + JSON structure
                for v in tc.arguments.values() {
                    n += v.to_string().len();
                }
            }
        }
        n
    }

    /// Total character count across all messages (includes tool call estimates).
    pub fn char_count(&self) -> usize {
        self.messages.iter().map(Self::message_char_count).sum()
    }

    /// Total word count across all messages.
    pub fn word_count(&self) -> usize {
        self.messages.iter()
            .map(|m| m.content.split_whitespace().count())
            .sum()
    }

    /// Trim messages to stay within all configured limits.
    /// Uses drain(..k) instead of remove(0) for O(n) performance.
    /// Trim context if limits are exceeded. Returns number of messages dropped.
    pub fn trim_if_needed(&mut self) -> usize {
        let before = self.messages.len();
        // Message count limit (sliding window)
        if self.max_messages > 0 && self.messages.len() > self.max_messages {
            let excess = self.messages.len() - self.max_messages;
            self.messages.drain(..excess);
        }
        // Token limit — compute cutpoint then drain once
        if self.max_context_tokens > 0 && self.estimate_tokens() > self.max_context_tokens as usize {
            let limit = self.max_context_tokens as usize;
            let mut k = 0;
            while k < self.messages.len().saturating_sub(1) {
                let remaining: usize = self.messages[k..].iter().map(Self::message_char_count).sum();
                if remaining / 4 <= limit { break; }
                k += 1;
            }
            if k > 0 { self.messages.drain(..k); }
        }
        // Character limit
        if self.max_chars > 0 && self.char_count() > self.max_chars as usize {
            let limit = self.max_chars as usize;
            let mut k = 0;
            let mut drop_chars = 0usize;
            let total = self.char_count();
            while k < self.messages.len().saturating_sub(1) && total - drop_chars > limit {
                drop_chars += Self::message_char_count(&self.messages[k]);
                k += 1;
            }
            if k > 0 { self.messages.drain(..k); }
        }
        // Word limit
        if self.max_words > 0 && self.word_count() > self.max_words as usize {
            let limit = self.max_words as usize;
            let mut k = 0;
            let mut drop_words = 0usize;
            let total = self.word_count();
            while k < self.messages.len().saturating_sub(1) && total - drop_words > limit {
                drop_words += self.messages[k].content.split_whitespace().count();
                k += 1;
            }
            if k > 0 { self.messages.drain(..k); }
        }
        before - self.messages.len()
    }

    /// Save current state for undo (max 10 deep).
    fn save_state(&mut self) {
        if self.undo_stack.len() >= 10 {
            self.undo_stack.remove(0);
        }
        self.undo_stack.push(self.messages.clone());
    }

    /// Edit a message at the given index.
    pub fn edit_message(&mut self, index: usize, new_content: &str) -> bool {
        if index >= self.messages.len() { return false; }
        self.save_state();
        self.messages[index].content = new_content.to_string();
        true
    }

    /// Delete a single message at the given index.
    pub fn delete_message(&mut self, index: usize) -> bool {
        if index >= self.messages.len() { return false; }
        self.save_state();
        self.messages.remove(index);
        true
    }

    /// Delete messages in range [start, end) (exclusive end).
    pub fn delete_range(&mut self, start: usize, end: usize) -> usize {
        let end = end.min(self.messages.len());
        if start >= end { return 0; }
        self.save_state();
        let count = end - start;
        self.messages.drain(start..end);
        count
    }

    /// Delete the last N messages.
    pub fn delete_last(&mut self, n: usize) -> usize {
        let count = n.min(self.messages.len());
        if count == 0 { return 0; }
        self.save_state();
        let start = self.messages.len() - count;
        self.messages.drain(start..);
        count
    }

    /// Delete all messages after the given index.
    pub fn truncate_after(&mut self, index: usize) -> usize {
        if index >= self.messages.len() { return 0; }
        self.save_state();
        let count = self.messages.len() - index - 1;
        self.messages.truncate(index + 1);
        count
    }

    /// Undo the last edit/delete operation.
    pub fn undo(&mut self) -> bool {
        if let Some(prev) = self.undo_stack.pop() {
            self.messages = prev;
            true
        } else {
            false
        }
    }

    /// Check if undo is available.
    pub fn can_undo(&self) -> bool {
        !self.undo_stack.is_empty()
    }

    /// Get full content of a message at index.
    pub fn get_full_content(&self, index: usize) -> Option<String> {
        self.messages.get(index).map(|m| m.content.clone())
    }

    /// Format history for display (last N messages, truncated previews).
    pub fn format_history(&self, limit: usize) -> String {
        let start = if self.messages.len() > limit { self.messages.len() - limit } else { 0 };
        let mut out = String::new();
        for (i, m) in self.messages[start..].iter().enumerate() {
            let idx = start + i;
            let preview = if m.content.len() > 80 {
                format!("{}...", &m.content[..80])
            } else {
                m.content.replace(''\\n'', " ")
            };
            out.push_str(&format!("[{}] {}: {} ({} chars)\\n", idx, m.role, preview.replace(''\\n'', " "), m.content.len()));
        }
        out
    }

