rust_fragment(tool_handler_validation, '
impl ToolHandler {
    /// Check if a path is allowed by security rules.
    /// Respects security_profile: "open" skips all checks.
    pub fn check_path_allowed(&self, path: &str) -> bool {
        use crate::security::*;

        // Open profile skips all path checks
        if let Some(spec) = self.get_profile_spec() {
            if !spec.path_validation {
                return true;
            }
        }

        // Check exact blocked paths
        for blocked in BLOCKED_PATHS.iter() {
            if path == *blocked {
                return false;
            }
        }

        // Check blocked prefixes
        for prefix in BLOCKED_PATH_PREFIXES.iter() {
            if path.starts_with(prefix) {
                return false;
            }
        }

        // Check home directory patterns
        if let Some(home) = std::env::var_os("HOME") {
            let home = home.to_string_lossy();
            for pattern in BLOCKED_HOME_PATTERNS.iter() {
                let blocked_path = format!("{}/{}", home, pattern);
                if path.starts_with(&blocked_path) {
                    return false;
                }
            }
        }

        true
    }

    /// Check if a command matches any blocked patterns.
    /// Respects security_profile: "open" skips checks, "guarded" adds extra blocks,
    /// "paranoid" uses allowlist-only mode.
    pub fn is_command_blocked(&self, command: &str) -> Option<String> {
        use crate::security::*;

        // Open profile skips all command checks
        if let Some(spec) = self.get_profile_spec() {
            if !spec.command_validation {
                return None;
            }
        }

        // Paranoid mode: allowlist-only (safe + confirm patterns)
        if self.security_profile == "paranoid" {
            let is_safe = PARANOID_SAFE.iter().any(|pat| {
                regex::Regex::new(pat).map(|re| re.is_match(command)).unwrap_or(false)
            });
            let is_confirm = PARANOID_CONFIRM.iter().any(|pat| {
                regex::Regex::new(pat).map(|re| re.is_match(command)).unwrap_or(false)
            });
            if !is_safe && !is_confirm {
                return Some("Command not in paranoid allowlist".to_string());
            }
            return None;
        }

        // Standard blocked command patterns (cautious + guarded)
        for (pattern, description) in BLOCKED_COMMAND_PATTERNS.iter() {
            if let Ok(re) = regex::Regex::new(pattern) {
                if re.is_match(command) {
                    return Some(description.to_string());
                }
            }
        }

        // Guarded mode: additional blocked patterns
        if self.security_profile == "guarded" {
            for pattern in GUARDED_EXTRA_BLOCKS.iter() {
                if let Ok(re) = regex::Regex::new(pattern) {
                    if re.is_match(command) {
                        return Some(format!("Blocked by guarded profile: {}", pattern));
                    }
                }
            }
        }

        None
    }

    /// Check if a tool requires approval based on approval_mode.
    /// Returns true if the tool is approved to execute, false if blocked.
    pub fn check_approval(&self, tool_name: &str) -> bool {
        match self.approval_mode.as_str() {
            "yolo" => true,
            "plan" => {
                // Plan mode: only read is allowed
                matches!(tool_name, "read")
            }
            "auto_edit" => {
                // Auto-approve read and edit, block bash and write
                matches!(tool_name, "read" | "edit" | "write")
            }
            "default" => {
                if self.auto_approve {
                    return true;
                }
                // Read is always auto-approved
                if tool_name == "read" {
                    return true;
                }
                // For other tools, prompt user
                true // Return true, actual prompt happens in confirm_tool_execution
            }
            _ => true,
        }
    }

    /// Interactive confirmation for tool execution with argument preview.
    /// Returns true if the user approves, false to skip.
    pub fn confirm_tool_execution(&self, tool_call: &ToolCall) -> bool {
        // Auto-approve in yolo mode or if auto_approve is set
        if self.approval_mode == "yolo" || self.auto_approve {
            return true;
        }
        // Read is always safe
        if tool_call.name == "read" {
            return true;
        }
        // Plan mode blocks all non-read tools
        if self.approval_mode == "plan" {
            eprintln!("  [plan mode] Blocked: {}", tool_call.name);
            return false;
        }
        // auto_edit mode: allow read/edit/write without prompt
        if self.approval_mode == "auto_edit" && matches!(tool_call.name.as_str(), "edit" | "write") {
            return true;
        }

        // Show tool details for confirmation
        let is_destructive = matches!(tool_call.name.as_str(), "bash" | "write" | "edit");
        let label = if is_destructive { "DESTRUCTIVE" } else { "Tool" };
        eprintln!("  [{}] {} tool:", label, tool_call.name);

        // Show relevant arguments preview
        match tool_call.name.as_str() {
            "bash" => {
                if let Some(cmd) = tool_call.arguments.get("command").and_then(|v| v.as_str()) {
                    let preview = if cmd.len() > 120 { &cmd[..120] } else { cmd };
                    eprintln!("    command: {}", preview);
                }
            }
            "write" | "edit" => {
                if let Some(path) = tool_call.arguments.get("file_path").and_then(|v| v.as_str()) {
                    eprintln!("    file: {}", path);
                }
            }
            _ => {
                // Show first argument key for plugin tools
                if let Some((key, val)) = tool_call.arguments.iter().next() {
                    let preview = val.to_string();
                    let preview = if preview.len() > 80 { &preview[..80] } else { &preview };
                    eprintln!("    {}: {}", key, preview);
                }
            }
        }

        eprint!("  Execute? [y/N] ");
        use std::io::Write;
        std::io::stderr().flush().ok();
        let mut input = String::new();
        if std::io::stdin().read_line(&mut input).is_ok() {
            input.trim().eq_ignore_ascii_case("y")
        } else {
            false
        }
    }

    /// Validate tool call arguments against known schemas.
    /// Returns Some(error_message) if validation fails, None if ok.
    pub fn validate_tool_args(&self, tool_call: &ToolCall) -> Option<String> {
        let required: &[&str] = match tool_call.name.as_str() {
            "bash" => &["command"],
            "read" => &["file_path"],
            "write" => &["file_path", "content"],
            "edit" => &["file_path", "old_string", "new_string"],
            _ => return None, // No schema for plugin/MCP tools
        };
        let missing: Vec<&str> = required.iter()
            .filter(|&&p| !tool_call.arguments.contains_key(p))
            .copied()
            .collect();
        if missing.is_empty() {
            None
        } else {
            Some(format!("Missing required parameter(s): {}", missing.join(", ")))
        }
    }
}

