rust_fragment(tool_handler_dispatch, '
impl ToolHandler {
    /// Execute a tool call and return the result.
    pub fn execute(&mut self, tool_call: &ToolCall) -> ToolResult {
        // Check approval mode before executing
        if !self.check_approval(&tool_call.name) {
            return ToolResult {
                success: false,
                output: format!("Tool ''{}'' blocked by approval mode ''{}''", tool_call.name, self.approval_mode),
                tool_name: tool_call.name.clone(),
            };
        }

        // Validate required parameters
        if let Some(err) = self.validate_tool_args(tool_call) {
            return ToolResult {
                success: false,
                output: format!("[Validation] {}", err),
                tool_name: tool_call.name.clone(),
            };
        }

        // Check cache for non-destructive tools
        if let Some(cached) = self.cache.get(&tool_call.name, &tool_call.arguments) {
            return cached.clone();
        }

        // MCP tool dispatch (tool names starting with "mcp:")
        if tool_call.name.starts_with("mcp:") {
            let result = if let Some(ref mut mgr) = self.mcp_manager {
                match mgr.dispatch(&tool_call.name, serde_json::json!(tool_call.arguments)) {
                    Some(val) => ToolResult {
                        success: true,
                        output: serde_json::to_string_pretty(&val).unwrap_or_default(),
                        tool_name: tool_call.name.clone(),
                    },
                    None => ToolResult {
                        success: false,
                        output: format!("MCP tool not found: {}", tool_call.name),
                        tool_name: tool_call.name.clone(),
                    },
                }
            } else {
                ToolResult {
                    success: false,
                    output: "No MCP servers configured".to_string(),
                    tool_name: tool_call.name.clone(),
                }
            };
            self.cache.put(&tool_call.name, &tool_call.arguments, result.clone());
            return result;
        }

        let result = match tool_call.name.as_str() {
            "bash" => self.handle_bash(&tool_call.arguments),
            "read" => self.handle_read(&tool_call.arguments),
            "write" => self.handle_write(&tool_call.arguments),
            "edit" => self.handle_edit(&tool_call.arguments),
            _ => {
                // Check plugin tools
                if let Some(ref pm) = self.plugins {
                    if let Some(cmd) = pm.execute(&tool_call.name, &tool_call.arguments) {
                        // Execute plugin command via bash
                        let mut plugin_args = std::collections::HashMap::new();
                        plugin_args.insert("command".to_string(), serde_json::json!(cmd));
                        let mut r = self.handle_bash(&plugin_args);
                        r.tool_name = tool_call.name.clone();
                        return r;
                    }
                }
                ToolResult {
                    success: false,
                    output: format!("Unknown tool: {}", tool_call.name),
                    tool_name: tool_call.name.clone(),
                }
            },
        };

        // Store in cache
        self.cache.put(&tool_call.name, &tool_call.arguments, result.clone());
        result
    }

    /// Async tool execution — uses tokio::process::Command for plugin tools.
    /// Falls back to sync execute() for built-in tools.
    pub async fn execute_async(&mut self, tool_call: &ToolCall) -> ToolResult {
        // Check if this is a plugin tool with async support
        if let Some(ref pm) = self.plugins {
            if pm.has_tool(&tool_call.name) {
                if let Some((success, output)) = pm.execute_async(&tool_call.name, &tool_call.arguments).await {
                    return ToolResult {
                        success,
                        output,
                        tool_name: tool_call.name.clone(),
                    };
                }
            }
        }
        // Fall back to sync execution for built-in tools
        self.execute(tool_call)
    }

    fn handle_bash(&mut self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let command = args.get("command")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if let Some(reason) = self.is_command_blocked(command) {
            return ToolResult {
                success: false,
                output: format!("Command blocked: {}", reason),
                tool_name: "bash".to_string(),
            };
        }

        // If proot is enabled, wrap the command in proot
        let (exec_cmd, exec_env) = if let Some(ref mut proot) = self.proot {
            match proot.wrap_command(command) {
                Ok(wrapped) => {
                    let env_overrides = proot.build_env_overrides();
                    (wrapped, Some(env_overrides))
                }
                Err(e) => {
                    return ToolResult {
                        success: false,
                        output: format!("Proot error: {}", e),
                        tool_name: "bash".to_string(),
                    };
                }
            }
        } else {
            (command.to_string(), None)
        };

        let mut cmd = Command::new("bash");
        cmd.arg("-c").arg(&exec_cmd)
           .stdout(Stdio::piped()).stderr(Stdio::piped());

        // Apply proot env overrides
        if let Some(env_overrides) = exec_env {
            for (key, val) in env_overrides {
                cmd.env(key, val);
            }
        }

        match cmd.output() {
            Ok(output) => {
                let stdout = String::from_utf8_lossy(&output.stdout);
                let stderr = String::from_utf8_lossy(&output.stderr);
                let combined = if stderr.is_empty() {
                    stdout.to_string()
                } else {
                    format!("{}\n{}", stdout, stderr)
                };
                ToolResult {
                    success: output.status.success(),
                    output: combined,
                    tool_name: "bash".to_string(),
                }
            }
            Err(e) => ToolResult {
                success: false,
                output: format!("Error: {}", e),
                tool_name: "bash".to_string(),
            },
        }
    }

    fn handle_read(&self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let path = args.get("file_path")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if !self.check_path_allowed(path) {
            return ToolResult {
                success: false,
                output: format!("Path blocked: {}", path),
                tool_name: "read".to_string(),
            };
        }

        match std::fs::read_to_string(path) {
            Ok(content) => ToolResult {
                success: true,
                output: content,
                tool_name: "read".to_string(),
            },
            Err(e) => ToolResult {
                success: false,
                output: format!("Error reading {}: {}", path, e),
                tool_name: "read".to_string(),
            },
        }
    }

    fn handle_write(&self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let path = args.get("file_path")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let content = args.get("content")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if !self.check_path_allowed(path) {
            return ToolResult {
                success: false,
                output: format!("Path blocked: {}", path),
                tool_name: "write".to_string(),
            };
        }

        match std::fs::write(path, content) {
            Ok(()) => ToolResult {
                success: true,
                output: format!("Wrote {} bytes to {}", content.len(), path),
                tool_name: "write".to_string(),
            },
            Err(e) => ToolResult {
                success: false,
                output: format!("Error writing {}: {}", path, e),
                tool_name: "write".to_string(),
            },
        }
    }

    fn handle_edit(&self, args: &std::collections::HashMap<String, serde_json::Value>) -> ToolResult {
        let path = args.get("file_path")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let old_string = args.get("old_string")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let new_string = args.get("new_string")
            .and_then(|v| v.as_str())
            .unwrap_or("");

        if !self.check_path_allowed(path) {
            return ToolResult {
                success: false,
                output: format!("Path blocked: {}", path),
                tool_name: "edit".to_string(),
            };
        }

        match std::fs::read_to_string(path) {
            Ok(content) => {
                if !content.contains(old_string) {
                    return ToolResult {
                        success: false,
                        output: "old_string not found in file".to_string(),
                        tool_name: "edit".to_string(),
                    };
                }
                let new_content = content.replacen(old_string, new_string, 1);
                match std::fs::write(path, &new_content) {
                    Ok(()) => ToolResult {
                        success: true,
                        output: format!("Edited {}", path),
                        tool_name: "edit".to_string(),
                    },
                    Err(e) => ToolResult {
                        success: false,
                        output: format!("Error writing {}: {}", path, e),
                        tool_name: "edit".to_string(),
                    },
                }
            }
            Err(e) => ToolResult {
                success: false,
                output: format!("Error reading {}: {}", path, e),
                tool_name: "edit".to_string(),
            },
        }
    }
}

