    let json = serde_json::json!({
        "choices": [{"message": {"content": "", "tool_calls": [
            {"id": "call_1", "function": {"name": "bash", "arguments": args_json}}
        ]}}],
        "usage": {"prompt_tokens": 10, "completion_tokens": 5}
    });
