%% --- Fragment: async_api_backend (Python parity with Rust AsyncApiBackend) ---

py_fragment(async_api_backend, '
class AsyncApiBackend(AgentBackend):
    """Async HTTP backend using aiohttp for non-blocking API calls."""

    def __init__(self, name: str, endpoint: str, api_key: str | None = None,
                 model: str = "", stream: bool = False, api_format: str = "openai"):
        self._name = name
        self.endpoint = endpoint
        self.api_key = api_key
        self.model = model
        self.stream = stream
        self.api_format = api_format

    @property
    def name(self) -> str:
        return self._name

    def _build_headers(self) -> dict:
        headers = {"Content-Type": "application/json"}
        if self.api_key:
            if self.api_format == "anthropic":
                headers["x-api-key"] = self.api_key
                headers["anthropic-version"] = "2023-06-01"
            else:
                headers["Authorization"] = f"Bearer {self.api_key}"
        return headers

    def _build_body(self, message: str, context: list[dict]) -> dict:
        messages = [{"role": m.get("role", "user"), "content": m.get("content", "")} for m in context]
        messages.append({"role": "user", "content": message})
        if self.api_format == "anthropic":
            return {"model": self.model, "messages": messages, "max_tokens": 4096, "stream": self.stream}
        return {"model": self.model, "messages": messages, "stream": self.stream}

    async def send_message_async(self, message: str, context: list[dict], **kwargs) -> AgentResponse:
        """Send message asynchronously using aiohttp."""
        try:
            import aiohttp
        except ImportError:
            # Fallback to sync if aiohttp not available
            return self.send_message(message, context, **kwargs)

        headers = self._build_headers()
        body = self._build_body(message, context)

        async with aiohttp.ClientSession() as session:
            async with session.post(self.endpoint, json=body, headers=headers) as resp:
                data = await resp.json()

        return self._parse_response(data)

    def send_message(self, message: str, context: list[dict], **kwargs) -> AgentResponse:
        """Synchronous fallback using urllib."""
        import urllib.request
        import json as _json
        headers = self._build_headers()
        body = self._build_body(message, context)
        req = urllib.request.Request(
            self.endpoint,
            data=_json.dumps(body).encode(),
            headers=headers,
            method="POST"
        )
        with urllib.request.urlopen(req, timeout=120) as resp:
            data = _json.loads(resp.read())
        return self._parse_response(data)

    def _parse_response(self, data: dict) -> AgentResponse:
        tool_calls = []
        if self.api_format == "anthropic":
            content = ""
            for block in data.get("content", []):
                if block.get("type") == "text":
                    content = block.get("text", "")
                elif block.get("type") == "tool_use":
                    tool_calls.append(ToolCall(
                        name=block.get("name", ""),
                        arguments=block.get("input", {}),
                        id=block.get("id", "")
                    ))
            usage = data.get("usage", {})
            tokens = {"input": usage.get("input_tokens", 0), "output": usage.get("output_tokens", 0)}
        else:
            choice = data.get("choices", [{}])[0].get("message", {})
            content = choice.get("content", "") or ""
            for tc in choice.get("tool_calls", []):
                import json as _tc_json
                args = tc.get("function", {}).get("arguments", "{}")
                try:
                    parsed_args = _tc_json.loads(args) if isinstance(args, str) else args
                except (ValueError, TypeError):
                    parsed_args = {}
                tool_calls.append(ToolCall(
                    name=tc.get("function", {}).get("name", ""),
                    arguments=parsed_args,
                    id=tc.get("id", "")
                ))
            usage = data.get("usage", {})
            tokens = {"input": usage.get("prompt_tokens", 0), "output": usage.get("completion_tokens", 0)}
        return AgentResponse(content=content, tool_calls=tool_calls, tokens=tokens, raw=data)

    def supports_streaming(self) -> bool:
        return self.stream
').

%% --- Fragment: output_parser (Python — new capability) ---

py_fragment(output_parser, '# Structured output parser - extract JSON from model responses.

import json

class ParsedOutput:
    """Result of parsing a model response for structured output."""
    __slots__ = ("json_blocks", "raw_text", "errors")

    def __init__(self, json_blocks: list[dict], raw_text: str, errors: list[str]):
        self.json_blocks = json_blocks
        self.raw_text = raw_text
        self.errors = errors

class OutputParser:
    """Extract and validate JSON from model responses."""

    @classmethod
    def _extract_fenced(cls, text: str) -> list[dict]:
        """Extract JSON from fenced code blocks (```json ... ```)."""
        results = []
        marker = "```"
        pos = 0
        while True:
            start = text.find(marker, pos)
            if start < 0:
                break
            # Skip optional language tag
            line_end = text.find("\\n", start)
            if line_end < 0:
                break
            end = text.find(marker, line_end)
            if end < 0:
                break
            block = text[line_end + 1:end].strip()
            try:
                parsed = json.loads(block)
                if isinstance(parsed, dict):
                    results.append(parsed)
                elif isinstance(parsed, list):
                    results.extend(d for d in parsed if isinstance(d, dict))
            except (json.JSONDecodeError, ValueError):
                pass
            pos = end + len(marker)
        return results

    @classmethod
    def _extract_bare(cls, text: str) -> list[dict]:
        """Extract bare JSON objects from text."""
        results = []
        depth = 0
        start = -1
        for i, ch in enumerate(text):
            if ch == "{":
                if depth == 0:
                    start = i
                depth += 1
            elif ch == "}":
                depth -= 1
                if depth == 0 and start >= 0:
                    try:
                        parsed = json.loads(text[start:i + 1])
                        if isinstance(parsed, dict):
                            results.append(parsed)
                    except (json.JSONDecodeError, ValueError):
                        pass
                    start = -1
        return results

    @classmethod
    def parse_response(cls, text: str, expected_keys: list[str] | None = None) -> ParsedOutput:
        """Parse response, optionally validating expected top-level keys."""
        blocks = cls.extract_json(text)
        errors = []
        if expected_keys and blocks:
            for i, block in enumerate(blocks):
                missing = [k for k in expected_keys if k not in block]
                if missing:
                    errors.append(f"Block {i}: missing keys {missing}")
        return ParsedOutput(json_blocks=blocks, raw_text=text, errors=errors)
').

%% --- Fragment: mcp_client (Python — new capability) ---

py_fragment(mcp_client, '# MCP (Model Context Protocol) client - stdio JSON-RPC 2.0 transport.

import json
import subprocess
import os
import sys

class MCPClient:
    """Connect to an MCP server over stdio and call tools."""

    def __init__(self, name: str, command: list[str], env: dict[str, str] | None = None):
        self.name = name
        self.command = command
        self.env = env
        self._process = None
        self._request_id = 0

    def connect(self, timeout: float = 10.0) -> bool:
        """Start the MCP server subprocess."""
        try:
            merged_env = {**os.environ, **(self.env or {})}
            self._process = subprocess.Popen(
                self.command,
                stdin=subprocess.PIPE,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                env=merged_env,
            )
            # Send initialize request
            resp = self._send_request("initialize", {
                "protocolVersion": "2024-11-05",
                "capabilities": {},
                "clientInfo": {"name": "uwsal", "version": "0.2.0"}
            })
            return resp is not None and "error" not in resp
        except (OSError, FileNotFoundError) as e:
            print(f"MCP [{self.name}] connect failed: {e}", file=sys.stderr)
            return False

    def _send_request(self, method: str, params: dict | None = None) -> dict | None:
        """Send a JSON-RPC 2.0 request and read the response."""
        if not self._process or self._process.stdin is None:
            return None
        self._request_id += 1
        request = {
            "jsonrpc": "2.0",
            "id": self._request_id,
            "method": method,
        }
        if params is not None:
            request["params"] = params
        try:
            line = json.dumps(request) + "\\n"
            self._process.stdin.write(line.encode())
            self._process.stdin.flush()
            resp_line = self._process.stdout.readline()
            if not resp_line:
                return None
            return json.loads(resp_line.decode())
        except (BrokenPipeError, json.JSONDecodeError, OSError):
            return None

    def discover_tools(self) -> list[dict]:
        """Call tools/list and return tool definitions."""
        resp = self._send_request("tools/list", {})
        if resp and "result" in resp:
            return resp["result"].get("tools", [])
        return []

    def call_tool(self, name: str, arguments: dict) -> dict:
        """Call tools/call and return the result."""
        resp = self._send_request("tools/call", {"name": name, "arguments": arguments})
        if resp and "result" in resp:
            return resp["result"]
        error = resp.get("error", {}) if resp else {"message": "No response"}
        return {"error": error.get("message", str(error))}

    def disconnect(self) -> None:
        """Terminate the MCP server subprocess."""
        if self._process:
            try:
                self._process.stdin.close()
                self._process.terminate()
                self._process.wait(timeout=5)
            except (OSError, subprocess.TimeoutExpired):
                self._process.kill()
            self._process = None

    def __del__(self):
        self.disconnect()


class MCPManager:
    """Manage multiple MCP server connections."""

    def __init__(self, server_configs: list[dict] | None = None):
        self.clients: dict[str, MCPClient] = {}
        self._tools: dict[str, tuple[str, dict]] = {}  # tool_name -> (server_name, spec)
        if server_configs:
            for cfg in server_configs:
                self.add_server(cfg)

    def add_server(self, config: dict) -> bool:
        """Add and connect an MCP server from config dict."""
        name = config.get("name", "")
        command = config.get("command", [])
        if isinstance(command, str):
            command = command.split()
        env = config.get("env")
        client = MCPClient(name, command, env)
        if client.connect():
            self.clients[name] = client
            # Discover tools
            for tool in client.discover_tools():
                tool_name = f"mcp:{name}:{tool[\"name\"]}"
                self._tools[tool_name] = (name, tool)
            return True
        return False

    def list_tools(self) -> list[dict]:
        """List all discovered MCP tools."""
        return [
            {"name": name, "server": server, "description": spec.get("description", "")}
            for name, (server, spec) in self._tools.items()
        ]

    def dispatch(self, tool_name: str, arguments: dict) -> dict | None:
        """Dispatch a tool call to the appropriate MCP server."""
        entry = self._tools.get(tool_name)
        if not entry:
            return None
        server_name, spec = entry
        client = self.clients.get(server_name)
        if not client:
            return None
        # Extract the real tool name (strip mcp:server: prefix)
        real_name = spec.get("name", tool_name.split(":")[-1])
        return client.call_tool(real_name, arguments)

    def disconnect_all(self) -> None:
        """Disconnect all MCP servers."""
        for client in self.clients.values():
            client.disconnect()
        self.clients.clear()
        self._tools.clear()
').

%% --- Fragment: _format_prompt (shared by 5 CLI backends) ---

py_fragment(format_prompt, '    def _format_prompt(self, message: str, context: list[dict]) -> str:
        """Format message with conversation context."""
        if not context:
            return message

        history_lines = []
        for msg in context[-6:]:
            role = "User" if msg.get(\'role\') == \'user\' else "Assistant"
            content = msg.get(\'content\', \'\')
            if len(content) > 500:
                content = content[:500] + "..."
            history_lines.append(f"{role}: {content}")

        history = "\\n".join(history_lines)

        return f"""Previous conversation:
{history}

Current request: {message}"""
').

