py_fragment(tools_handler_class_methods, '
    def check_approval(self, tool_name: str) -> bool:
        """Check if a tool is approved to execute under the current approval mode.
        Returns True if approved, False if blocked."""
        mode = self.approval_mode
        if mode == "yolo":
            return True
        if mode == "plan":
            return tool_name == "read"
        if mode == "auto_edit":
            return tool_name in ("read", "edit", "write")
        # default mode: read always approved, others go through confirm
        if tool_name == "read":
            return True
        return True  # actual prompt happens in confirm_tool_execution

    def confirm_tool_execution(self, tool_call: ToolCall) -> bool:
        """Interactive confirmation for tool execution with argument preview.
        Returns True if the user approves, False to skip."""
        import sys
        # Auto-approve in yolo mode
        if self.approval_mode == "yolo" or not self.confirm_destructive:
            return True
        # Read is always safe
        if tool_call.name == "read":
            return True
        # Plan mode blocks all non-read tools
        if self.approval_mode == "plan":
            print(f"  [plan mode] Blocked: {tool_call.name}", file=sys.stderr)
            return False
        # auto_edit mode: allow read/edit/write without prompt
        if self.approval_mode == "auto_edit" and tool_call.name in ("edit", "write"):
            return True

        # Show tool details for confirmation
        is_destructive = tool_call.name in ("bash", "write", "edit")
        label = "DESTRUCTIVE" if is_destructive else "Tool"
        print(f"  [{label}] {tool_call.name} tool:", file=sys.stderr)

        # Show relevant arguments preview
        if tool_call.name == "bash":
            cmd = tool_call.arguments.get("command", "")
            preview = cmd[:120] if len(cmd) > 120 else cmd
            print(f"    command: {preview}", file=sys.stderr)
        elif tool_call.name in ("write", "edit"):
            path = tool_call.arguments.get("file_path", tool_call.arguments.get("path", ""))
            print(f"    file: {path}", file=sys.stderr)
        else:
            # Show first argument for plugin/MCP tools
            for key, val in tool_call.arguments.items():
                preview = str(val)
                preview = preview[:80] if len(preview) > 80 else preview
                print(f"    {key}: {preview}", file=sys.stderr)
                break

        try:
            sys.stderr.write("  Execute? [y/N] ")
            sys.stderr.flush()
            response = input().strip().lower()
            return response in ("y", "yes")
        except (EOFError, KeyboardInterrupt):
            return False

    def _validate_tool_args(self, tool_call: ToolCall) -> str | None:
        """Validate tool call arguments against schema. Returns error message or None."""
        required = self.tool_required_params.get(tool_call.name)
        if required is None:
            return None  # No schema for this tool (plugin/MCP)
        missing = [p for p in required if p not in tool_call.arguments]
        if missing:
            return f"Missing required parameter(s): {'', ''.join(missing)}"
        return None

    def _init_plugins(self):
        """Load plugins from default directory."""
        self.plugin_manager = PluginManager()
        plugin_count = self.plugin_manager.load_default()
        if plugin_count > 0:
            for tool in self.plugin_manager.list_tools():
                name = tool["name"]
                self.allowed_tools.append(name)
                self.tools[name] = self._make_plugin_handler(name)
            print(f"[Loaded {plugin_count} plugin(s)]")

    def _make_plugin_handler(self, tool_name: str):
        """Create a handler function for a plugin tool."""
        def handler(args):
            cmd = self.plugin_manager.execute(tool_name, args)
            if cmd is None:
                return ToolResult(
                    success=False,
                    output=f"Missing required parameters for {tool_name}",
                    tool_name=tool_name
                )
            return self._execute_bash({"command": cmd})
        return handler
').

py_fragment(tools_handler_class_body, '
    def execute(self, tool_call: ToolCall) -> ToolResult:
        """Execute a tool call and return the result."""
        # Check approval mode before executing
        if not self.check_approval(tool_call.name):
            return ToolResult(
                success=False,
                output=f"Tool \'{tool_call.name}\' blocked by approval mode \'{self.approval_mode}\'",
                tool_name=tool_call.name
            )

        # Interactive confirmation (for default/auto_edit modes)
        if not self.confirm_tool_execution(tool_call):
            return ToolResult(
                success=False,
                output="User declined to execute tool",
                tool_name=tool_call.name
            )

        # Validate tool arguments against schema
        validation_error = self._validate_tool_args(tool_call)
        if validation_error:
            return ToolResult(
                success=False,
                output=f"[Validation] {validation_error}",
                tool_name=tool_call.name
            )

        # Check cache first
        cached = self.cache.get(tool_call.name, tool_call.arguments)
        if cached is not None:
            return cached

        # MCP tool dispatch
        if tool_call.name.startswith("mcp:"):
            result = self._execute_mcp(tool_call)
            self.cache.put(tool_call.name, tool_call.arguments, result)
            return result

        if tool_call.name not in self.allowed_tools:
            return ToolResult(
                success=False,
                output=f"Tool \'{tool_call.name}\' is not allowed",
                tool_name=tool_call.name
            )

        if tool_call.name not in self.tools:
            return ToolResult(
                success=False,
                output=f"Unknown tool: {tool_call.name}",
                tool_name=tool_call.name
            )

        if tool_call.name == \'bash\':
            blocked = self._pre_check_bash(tool_call.arguments)
            if blocked:
                self.audit.log_tool_call(
                    tool_call.name, False,
                    args_summary=str(tool_call.arguments)[:256]
                )
                return blocked

        if self.confirm_destructive and tool_call.name in self.destructive_tools:
            if not self._is_safe_command(tool_call):
                if not self._confirm_execution(tool_call):
                    return ToolResult(
                        success=False,
                        output="User declined to execute tool",
                        tool_name=tool_call.name
                    )

        try:
            result = self.tools[tool_call.name](tool_call.arguments)
            self.audit.log_tool_call(
                tool_call.name, result.success,
                args_summary=str(tool_call.arguments)[:256]
            )
            self.cache.put(tool_call.name, tool_call.arguments, result)
            return result
        except Exception as e:
            self.audit.log_tool_call(tool_call.name, False, args_summary=str(e))
            return ToolResult(
                success=False,
                output=f"Error executing {tool_call.name}: {e}",
                tool_name=tool_call.name
            )

    def _execute_mcp(self, tool_call: ToolCall) -> ToolResult:
        """Execute a tool call via MCP server."""
        if self.mcp_manager is None:
            return ToolResult(success=False, output="No MCP servers configured", tool_name=tool_call.name)
        result = self.mcp_manager.dispatch(tool_call.name, tool_call.arguments)
        if result is not None:
            import json as _mcp_json
            return ToolResult(success=True, output=_mcp_json.dumps(result, indent=2), tool_name=tool_call.name)
        return ToolResult(success=False, output=f"MCP tool not found: {tool_call.name}", tool_name=tool_call.name)

    def _confirm_execution(self, tool_call: ToolCall) -> bool:
        """Ask user to confirm execution of a destructive tool."""
        print(f"\\n[Tool: {tool_call.name}]")

        if tool_call.name == \'bash\':
            cmd = tool_call.arguments.get(\'command\', \'\')
            print(f"  Command: {cmd}")
        elif tool_call.name == \'write\':
            path = tool_call.arguments.get(\'path\', \'\')
            print(f"  File: {path}")
        elif tool_call.name == \'edit\':
            path = tool_call.arguments.get(\'path\', \'\')
            old = tool_call.arguments.get(\'old_string\', \'\')[:50]
            print(f"  File: {path}")
            print(f"  Replace: {old}...")

        try:
            response = input("Execute? [y/N]: ").strip().lower()
            return response in (\'y\', \'yes\')
        except (EOFError, KeyboardInterrupt):
            return False

    def _is_safe_command(self, tool_call: ToolCall) -> bool:
        """Check if a tool call is safe enough to skip confirmation."""
        if tool_call.name != \'bash\':
            return False
        if not self.security.safe_commands:
            return False

        command = tool_call.arguments.get(\'command\', \'\').strip()
        return any(
            re.search(pat, command, re.IGNORECASE)
            for pat in self.security.safe_commands
        )

    def _pre_check_bash(self, args: dict) -> ToolResult | None:
        """Run security checks on a bash command BEFORE confirmation."""
        command = args.get(\'command\', \'\').strip()
        if not command:
            return ToolResult(
                success=False,
                output="No command provided",
                tool_name=\'bash\'
            )

        if self.security.allowed_commands_only:
            matched = any(
                re.search(pat, command, re.IGNORECASE)
                for pat in self.security.allowed_commands
            )
            if not matched:
                reason = "Command not in allowlist"
                self.audit.log_command(command, allowed=False, reason=reason)
                return ToolResult(
                    success=False,
                    output=f"[Security] {reason}",
                    tool_name=\'bash\'
                )

        if self.security.command_blocklist:
            reason = is_command_blocked(
                command,
                extra_blocked=self.security.blocked_commands,
                extra_allowed=self.security.allowed_commands if not self.security.allowed_commands_only else None,
            )
            if reason:
                self.audit.log_command(command, allowed=False, reason=reason)
                return ToolResult(
                    success=False,
                    output=f"[Security] {reason}",
                    tool_name=\'bash\'
                )

        if self.proxy:
            proxy_mode = self.security.command_proxying
            allowed, reason = self.proxy.check(command, proxy_mode)
            if not allowed:
                self.audit.log_command(command, allowed=False, reason=reason)
                self.audit.log_proxy_action(command, \'\', \'block\', reason or \'\')
                return ToolResult(
                    success=False,
                    output=f"[Security/Proxy] {reason}",
                    tool_name=\'bash\'
                )

        return None

    def _execute_bash(self, args: dict) -> ToolResult:
        """Execute a bash command."""
        command = args.get(\'command\', \'\')
        if not command:
            return ToolResult(
                success=False,
                output="No command provided",
                tool_name=\'bash\'
            )

        exec_env = None
        exec_cmd = command

        if self.path_proxy:
            log_file = self.audit._log_file if self.audit._log_file else None
            exec_env = self.path_proxy.build_env(
                proxy_mode=self.security.command_proxying,
                audit_log=str(log_file) if log_file else None,
            )

        if self.proot:
            exec_cmd = self.proot.wrap_command(command)
            proot_env = self.proot.build_env_overrides()
            if exec_env is None:
                exec_env = dict(os.environ)
            exec_env.update(proot_env)

        try:
            result = subprocess.run(
                exec_cmd,
                shell=True,
                capture_output=True,
                text=True,
                timeout=120,
                cwd=self.working_dir,
                env=exec_env,
            )

            output = result.stdout
            if result.stderr:
                output += "\\n" + result.stderr

            self.audit.log_command(
                command, allowed=True,
                output=output.strip() if output else None
            )

            return ToolResult(
                success=result.returncode == 0,
                output=output.strip() or "(no output)",
                tool_name=\'bash\'
            )

        except subprocess.TimeoutExpired:
            self.audit.log_command(command, allowed=True, reason=\'timeout\')
            return ToolResult(
                success=False,
                output="Command timed out after 120 seconds",
                tool_name=\'bash\'
            )
        except Exception as e:
            self.audit.log_command(command, allowed=True, reason=str(e))
            return ToolResult(
                success=False,
                output=f"Error: {e}",
                tool_name=\'bash\'
            )

    def _validate_file_path(self, raw_path: str, tool_name: str) -> tuple[Path, ToolResult | None]:
        """Validate and resolve a file path."""
        if not raw_path:
            return Path(), ToolResult(False, "No path provided", tool_name)

        if self.security.path_validation:
            resolved, error = validate_path(
                raw_path, self.working_dir,
                extra_blocked=self.security.blocked_paths,
                extra_allowed=self.security.allowed_paths,
            )
            if error:
                self.audit.log_file_access(raw_path, tool_name, allowed=False, reason=error)
                return Path(resolved), ToolResult(False, f"[Security] {error}", tool_name)
            return Path(resolved), None

        if raw_path.startswith(\'/\'):
            return Path(raw_path), None
        return Path(self.working_dir) / raw_path, None

    def _read_file(self, args: dict) -> ToolResult:
        """Read a file."""
        path = args.get(\'file_path\', \'\')
        file_path, error = self._validate_file_path(path, \'read\')
        if error:
            return error

        try:
            if self.security.max_file_read_size is not None:
                try:
                    file_size = file_path.stat().st_size
                    if file_size > self.security.max_file_read_size:
                        reason = (f"File too large: {file_size} bytes "
                                  f"(limit: {self.security.max_file_read_size})")
                        self.audit.log_file_access(path, \'read\', allowed=False, reason=reason)
                        return ToolResult(False, f"[Security] {reason}", \'read\')
                except OSError:
                    pass

            content = file_path.read_text()
            self.audit.log_file_access(
                path, \'read\', allowed=True, bytes_count=len(content)
            )
            return ToolResult(
                success=True,
                output=content,
                tool_name=\'read\'
            )
        except FileNotFoundError:
            return ToolResult(
                success=False,
                output=f"File not found: {path}",
                tool_name=\'read\'
            )
        except Exception as e:
            return ToolResult(
                success=False,
                output=f"Error reading file: {e}",
                tool_name=\'read\'
            )

    def _write_file(self, args: dict) -> ToolResult:
        """Write content to a file."""
        path = args.get(\'file_path\', \'\')
        content = args.get(\'content\', \'\')

        file_path, error = self._validate_file_path(path, \'write\')
        if error:
            return error

        if self.security.max_file_write_size is not None:
            if len(content) > self.security.max_file_write_size:
                reason = (f"Content too large: {len(content)} bytes "
                          f"(limit: {self.security.max_file_write_size})")
                self.audit.log_file_access(path, \'write\', allowed=False, reason=reason)
                return ToolResult(False, f"[Security] {reason}", \'write\')

        try:
            file_path.parent.mkdir(parents=True, exist_ok=True)
            file_path.write_text(content)
            self.audit.log_file_access(
                path, \'write\', allowed=True, bytes_count=len(content)
            )
            return ToolResult(
                success=True,
                output=f"Wrote {len(content)} bytes to {path}",
                tool_name=\'write\'
            )
        except Exception as e:
            return ToolResult(
                success=False,
                output=f"Error writing file: {e}",
                tool_name=\'write\'
            )

    def _edit_file(self, args: dict) -> ToolResult:
        """Edit a file with search/replace."""
        path = args.get(\'file_path\', \'\')
        old_string = args.get(\'old_string\', \'\')
        new_string = args.get(\'new_string\', \'\')

        file_path, error = self._validate_file_path(path, \'edit\')
        if error:
            return error

        if not old_string:
            return ToolResult(
                success=False,
                output="No old_string provided",
                tool_name=\'edit\'
            )

        try:
            content = file_path.read_text()

            if old_string not in content:
                return ToolResult(
                    success=False,
                    output=f"old_string not found in {path}",
                    tool_name=\'edit\'
                )

            count = content.count(old_string)
            if count > 1:
                return ToolResult(
                    success=False,
                    output=f"old_string found {count} times - must be unique",
                    tool_name=\'edit\'
                )

            new_content = content.replace(old_string, new_string, 1)
            file_path.write_text(new_content)
            self.audit.log_file_access(
                path, \'edit\', allowed=True,
                bytes_count=len(new_content)
            )

            return ToolResult(
                success=True,
                output=f"Edited {path}",
                tool_name=\'edit\'
            )

        except FileNotFoundError:
            return ToolResult(
                success=False,
                output=f"File not found: {path}",
                tool_name=\'edit\'
            )
        except Exception as e:
            return ToolResult(
                success=False,
                output=f"Error editing file: {e}",
                tool_name=\'edit\'
            )

    def format_result_for_agent(self, result: ToolResult) -> str:
        """Format a tool result for sending back to the agent."""
        status = "Success" if result.success else "Failed"
        return f"[Tool {result.tool_name} - {status}]\\n{result.output}"
').

