class StreamingTokenCounter:
    """Counts tokens during streaming and optionally shows live status."""

    def __init__(self, show_live: bool = True, cost_tracker=None, model: str = "unknown"):
        self.token_count = 0
        self.char_count = 0
        self.show_live = show_live
        self.cost_tracker = cost_tracker
        self.model = model
        self._last_status_len = 0

').

py_fragment(streaming_token_counter_tail, '
    def finish(self) -> dict:
        """Called after streaming ends. Returns stats dict."""
        return {
            "approx_tokens": self.token_count,
            "chars": self.char_count,
        }

    def format_summary(self) -> str:
        """Format a one-line summary of streaming stats."""
        parts = [f"~{self.token_count} tokens", f"{self.char_count} chars"]
        if self.cost_tracker:
            # Estimate cost based on output tokens only (input counted later from response)
            pricing = self.cost_tracker.get_pricing(self.model)
            if pricing:
                est_cost = self.token_count * pricing.get(''output'', 0.0) / 1_000_000
                if est_cost > 0:
                    parts.append(f"~${est_cost:.4f}")
        return ", ".join(parts)
').

py_fragment(agent_loop_process_message, '    def _process_message(self, user_input: str) -> None:
        """Process a user message and get response."""
        # Add to context
        _trimmed = self.context.add_message(\'user\', user_input)
        if _trimmed and _trimmed > 0:
            print(f"  [context] Trimmed {_trimmed} old message(s) to stay within limits")

        # Show that we\'re calling the backend
        use_spinner = self.display_mode == \'ncurses\' and DisplayMode.supports_ncurses()
        spinner = None

        if use_spinner:
            spinner = Spinner("Calling backend...")
            spinner.start()
        else:
            print("\\n[Calling backend...]")

        # Status callback to update spinner with tool call info
        def on_status(status: str):
            if spinner:
                spinner.update(status)
            else:
                print(f"  {status}")

        # Get response from backend (with streaming + retry)
        try:
            if self.streaming and self.backend.supports_streaming() and hasattr(self.backend, \'send_message_streaming\'):
                if spinner:
                    spinner.stop()
                    spinner = None
                print("\\nAssistant: ", end="", flush=True)
                _counter = StreamingTokenCounter(
                    show_live=self.show_tokens,
                    cost_tracker=self.cost_tracker,
                    model=getattr(self.backend, \'model\', \'unknown\'),
                )
                response = self._send_streaming_with_retry(
                    user_input,
                    self.context.get_context(),
                    on_token=_counter.on_token
                )
                _stream_stats = _counter.finish()
                print()  # Newline after streaming
                if self.show_tokens:
                    print(f"  [Streamed: {_counter.format_summary()}]")
            else:
                response = self.backend.send_message(
                    user_input,
                    self.context.get_context(),
                    on_status=on_status
                )
        except KeyboardInterrupt:
            if spinner:
                spinner.stop()
            print("\\n[Interrupted]")
            return
        finally:
            if spinner:
                spinner.stop()

        # Handle tool calls if present
        iteration_count = 0
        prev_tool_sig = None  # Track previous tool calls to detect loops
        while response.tool_calls:
            iteration_count += 1

            # Detect duplicate tool calls (model stuck in a loop)
            current_sig = [
                (tc.name, json.dumps(tc.arguments, sort_keys=True))
                for tc in response.tool_calls
            ]
            if current_sig == prev_tool_sig:
                print("\\n[Stopped: model repeated the same tool call]")
                # Ask the model to respond with text instead of retrying
                self.context.add_message(
                    \'user\',
                    "The tool has already been executed and the result "
                    "was returned above. Please respond with your answer."
                )
                response = self.backend.send_message(
                    "",
                    self.context.get_context(),
                    on_status=on_status
                )
                break
            prev_tool_sig = current_sig

            # Check iteration limit
            if self.max_iterations > 0 and iteration_count > self.max_iterations:
                print(f"\\n[Paused after {self.max_iterations} iteration(s)]")
                print("[Press Enter to continue, or type a message]")
                try:
                    cont = input("You: ")
                    if cont.strip():
                        # User provided new input - process it instead
                        self.context.add_message(\'assistant\', response.content, 0)
                        self._process_message(cont)
                        return
                    # Reset counter and continue
                    iteration_count = 1
                except EOFError:
                    return

            # Record assistant message with its tool calls in context
            raw_tool_calls = []
            for tc in response.tool_calls:
                raw_tool_calls.append({
                    "id": tc.id,
                    "type": "function",
                    "function": {
                        "name": tc.name,
                        "arguments": json.dumps(tc.arguments),
                    }
                })
            self.context.add_message(
                \'assistant\', response.content or \'\',
                tool_calls=raw_tool_calls
            )

            for tool_call in response.tool_calls:
                # Execute the tool (with confirmation unless auto_execute)
                if self.auto_execute_tools:
                    # Skip confirmation
                    self.tools.confirm_destructive = False

                result = self.tools.execute(tool_call)

                # Show result to user
                print(f"  {result.output[:200]}{\'...\' if len(result.output) > 200 else \'\'}")

                # Record tool result with proper role
                self.context.add_message(
                    \'tool\',
                    self.tools.format_result_for_agent(result),
                    tool_call_id=tool_call.id
                )

            print(f"\\n[Iteration {iteration_count}: continuing with tool results...]")
            # Context now has assistant (with tool_calls) + tool results;
            # send empty message so backend just reads context
            response = self.backend.send_message(
                "",
                self.context.get_context(),
                on_status=on_status
            )

        # Display response (if not already streamed)
        if not (self.streaming and self.backend.supports_streaming() and hasattr(self.backend, \'send_message_streaming\')):
            print(f"\\nAssistant: {response.content}\\n")
        else:
            print()  # Just add spacing after streamed output

        # Parse structured output (JSON blocks) from response
        try:
            from output_parser import OutputParser
            parsed = OutputParser.parse_response(response.content)
            if parsed.json_blocks:
                self._last_parsed_output = parsed
        except Exception:
            pass  # OutputParser is optional

        # Add response to context
        output_tokens = response.tokens.get(\'output\', 0)
        input_tokens = response.tokens.get(\'input\', 0)
        self.context.add_message(\'assistant\', response.content, output_tokens)

        # Track costs
        if self.cost_tracker and response.tokens:
            model = getattr(self.backend, \'model\', \'unknown\')
            self.cost_tracker.ensure_pricing(model)
            self.cost_tracker.record_usage(model, input_tokens, output_tokens)

        # Show token summary if enabled
        if self.show_tokens and response.tokens:
            token_info = ", ".join(
                f"{k}: {v}" for k, v in response.tokens.items()
            )
            cost_info = ""
            if self.cost_tracker:
                cost_info = f" | Est. cost: {self.cost_tracker.get_summary()[\'cost_formatted\']}"
            print(f"  [Tokens: {token_info}{cost_info}]\\n")

        # Check token budget
        budget = getattr(self.config, \'token_budget\', 0.0) or 0.0
        if self.cost_tracker and budget > 0 and self.cost_tracker.is_over_budget(budget):
            remaining = self.cost_tracker.budget_remaining(budget)
            print(f"  [Budget exceeded] Spent ${self.cost_tracker.total_cost:.4f} of ${budget:.4f} budget.")
            try:
                cont = input("  Continue? [y/N]: ").strip().lower()
                if cont not in (\'y\', \'yes\'):
                    self.running = False
            except (EOFError, KeyboardInterrupt):
                self.running = False
').

py_fragment(agent_loop_streaming_retry, '    def _send_streaming_with_retry(self, message: str, context: list,
                                    on_token=None, max_retries: int = 3) -> "AgentResponse":
        """Send streaming message with retry on connection/timeout errors."""
        import time as _retry_time
        last_error = None
        for attempt in range(max_retries):
            try:
                return self.backend.send_message_streaming(
                    message, context, on_token=on_token
                )
            except (ConnectionError, TimeoutError, OSError) as e:
                last_error = e
                if attempt < max_retries - 1:
                    delay = (2 ** attempt) * 0.5  # 0.5s, 1s, 2s
                    print(f"\\n  [Retry {attempt + 1}/{max_retries} after {delay:.1f}s: {e}]", flush=True)
                    _retry_time.sleep(delay)
                    print("Assistant: ", end="", flush=True)
            except Exception:
                # Non-retryable errors — let the outer handler deal with them
                raise
        # All retries exhausted
        from backends.base import AgentResponse
        return AgentResponse(
            content=f"[Streaming failed after {max_retries} retries: {last_error}]",
            tokens={}
        )
').

